                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Số thứ tự thửa *</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.sothua} onChange={e=>setFormData({...formData, sothua: e.target.value})} required /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Chủ sở hữu</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.tenchu||''} onChange={e=>setFormData({...formData, tenchu: e.target.value})} /></div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Mục đích (Loại đất)</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-black uppercase" value={formData.loaidat||''} onChange={e=>setFormData({...formData, loaidat: e.target.value.toUpperCase()})} /></div>
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Diện tích (m²)</label><input type="number" className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-mono font-bold text-emerald-500" value={formData.dientich||''} onChange={e=>setFormData({...formData, dientich: parseFloat(e.target.value)})} /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Địa chỉ chi tiết</label><textarea className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none h-20 resize-none" value={formData.diachi||''} onChange={e=>setFormData({...formData, diachi: e.target.value})} /></div>
                                <div className="pt-4 flex gap-3">
                                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-gray-400 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest">HỦY</button>
                                    <button type="submit" disabled={loading} className="flex-[2] bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex justify-center items-center gap-2">{loading ? <RefreshCw className="animate-spin" size={16}/> : <Save size={16}/>} LƯU DỮ LIỆU</button>
                                </div>
                            </form>
                        </div>
                        <div className="hidden md:flex w-[350px] bg-gray-950 border-l border-gray-800 p-8 flex-col">
                            <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-6">Trực quan hóa thửa đất</h4>
                            <div className="flex-1 bg-gray-900 rounded-2xl border border-gray-800 relative flex items-center justify-center overflow-hidden">
                                {formData.geometry ? <canvas ref={editCanvasRef} width={300} height={300} className="w-full h-full" /> : <div className="text-center p-6 flex flex-col items-center gap-3"><MapPin className="text-gray-800" size={48} /><p className="text-[10px] text-gray-700 font-bold uppercase italic">Chưa có dữ liệu hình học</p></div>}
                            </div>
                            <div className="mt-6 p-4 bg-gray-900 rounded-2xl border border-gray-800">
                                <div onClick={() => fileInputRef.current?.click()} className="cursor-pointer group flex flex-col items-center gap-2">
                                    <FileUp className="text-gray-500 group-hover:text-blue-500 transition-colors" size={24} />
                                    <p className="text-[9px] text-gray-500 font-bold uppercase text-center">{formData.file ? formData.file.name : "Tải lên Shapefile / GeoJSON để cập nhật hình học"}</p>
                                    <input type="file" ref={fileInputRef} className="hidden" accept=".zip,.geojson,.json" onChange={e => setFormData({ ...formData, file: e.target.files?.[0] || null })} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ParcelManager;

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

export default function(pool, logSystemAction) {
    const router = express.Router();

    // DANH SÁCH CÁC TÊN CỘT THƯỜNG GẶP 
    // QUAN TRỌNG: Thứ tự ưu tiên từ trái sang phải. 
    // Đặt các tên cột đặc thù (kyhieumucd, shbando) lên trước các tên chuẩn (loaidat, sodoto)
    // để nếu bảng có cả 2 (do script tự tạo thêm) thì sẽ ưu tiên lấy cột gốc có dữ liệu.
    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tự động tìm tên cột đúng trong bảng DB (Case-Insensitive Match)
     * Trả về object map: { sodoto: "shbando", loaidat: "kyhieumucd", ... }
     */
    const resolveTableColumns = async (tableName) => {
        try {
            // 1. Lấy danh sách cột thực tế của bảng từ Schema
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            // Giữ nguyên casing gốc từ DB để query chính xác (ví dụ: "KyHieuMucD" phải query có quote)
            const dbColumns = res.rows.map(r => r.column_name); 
            const mapping = {};

            // 2. Duyệt qua từng trường chuẩn để tìm cột tương ứng trong DB
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                // Tìm cột DB nào khớp với danh sách ứng viên (không phân biệt hoa thường)
                const foundCol = dbColumns.find(dbCol => 
                    candidates.includes(dbCol.toLowerCase())
                );

                // Nếu tìm thấy, dùng tên cột gốc từ DB. Nếu không, fallback về tên chuẩn (để query fail rõ ràng hoặc handle sau)
                mapping[standardKey] = foundCol || standardKey;
            }

            // Log mapping để debug nếu cần
            // console.log(`[Schema Resolve] Table ${tableName}:`, mapping);

            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich' };
        }
    };

    // Helper: Ensure table has all required columns (Self-Healing)
    const syncTableSchema = async (tableName) => {
        // Chỉ thêm các cột chuẩn nếu KHÔNG tìm thấy bất kỳ biến thể nào
        try {
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`
                SELECT column_name FROM information_schema.columns WHERE table_name = $1
            `, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            const missingCols = [];
            // Check sodoto
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });
            // ... (tenchu, diachi optional)

            if (missingCols.length > 0) {
                console.log(`[Schema Sync] Adding missing columns to ${tableName}:`, missingCols.map(c=>c.name));
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
            }
            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    // --- 1. REGISTRY MANAGEMENT ---

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 4326),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await logSystemAction(req, 'CREATE_TABLE', `Tạo bảng mới: ${safeName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            await logSystemAction(req, 'LINK_TABLE', `Liên kết bảng: ${tableName}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        try {
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [req.body.tableName]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/spatial-tables/:name', async (req, res) => {
        const tableName = req.params.name;
        try {
            await pool.query('BEGIN');
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            await pool.query(`DROP TABLE IF EXISTS "${tableName}" CASCADE`);
            await logSystemAction(req, 'DROP_TABLE', `Xóa bảng: ${tableName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok' });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    // --- 2. DATA CRUD WITH DYNAMIC MAPPING ---

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        if (!/^[a-zA-Z0-9_]+$/.test(table)) return res.status(400).json({ error: "Invalid table name" });

        try {
            const cols = await resolveTableColumns(table);

            // Dùng COALESCE cho loaidat và sodoto/sothua để fallback nếu mapping chính bị null nhưng cột phụ (như loaidat do sync tạo) lại tồn tại
            // Tuy nhiên, logic resolveTableColumns hiện tại đã ưu tiên cột có ý nghĩa (kyhieumucd) trước.
            // Ta select đúng cột đã resolve.

            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;

            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            if (tenchu) { query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; params.push(`%${tenchu}%`); }
            if (diachi) { query += ` AND "${cols.diachi}" ILIKE $${idx++}`; params.push(`%${diachi}%`); }

            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            const features = result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null,
                // Thêm các trường gốc để fallback nếu cần phía frontend
                kyhieumucd: row.loaidat,
                shbando: row.sodoto,
                shthua: row.sothua
            }));
            res.json(features);
        } catch (e) {
            // Auto-heal attempt
            if (e.code === '42703') { // Undefined column
                 console.warn("Column missing, trying to sync schema...", e.message);
                 await syncTableSchema(table);
                 return res.status(500).json({ error: "Database schema was updated. Please refresh." });
            }
            res.status(500).json({ error: "Lỗi truy vấn: " + e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_SetSRID(ST_GeomFromGeoJSON($7), 4326)`;
                params.push(JSON.stringify(geometry));
            }
            const query = `
                INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry)
                VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid
            `;
            const result = await pool.query(query, params);
            await logSystemAction(req, 'ADD_PARCEL', `Thêm thửa đất vào ${table}`);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_SetSRID(ST_GeomFromGeoJSON($${idx}), 4326)`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            await logSystemAction(req, 'UPDATE_PARCEL', `Cập nhật thửa GID ${gid}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            await logSystemAction(req, 'DELETE_PARCEL', `Xóa thửa GID ${req.params.gid}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 

        if (!file) return res.status(400).json({ error: 'No file uploaded' });

        try {
            const cols = await resolveTableColumns(table);
            const buffer = fs.readFileSync(file.path);
            let geojson;

            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());

            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;

            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");

            if (gid) {
                await pool.query(
                    `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_SetSRID(ST_GeomFromGeoJSON($7), 4326) WHERE gid=$8`,
                    [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]
                );
            } else {
                await pool.query(
                    `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_SetSRID(ST_GeomFromGeoJSON($7), 4326))`,
                    [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]
                );
            }
            fs.unlinkSync(file.path);
            await logSystemAction(req, 'UPLOAD_GEOMETRY', `Upload hình học cho ${table}`);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: "Lỗi xử lý file: " + e.message });
        }
    });

    return router;
}

import express from 'express';
import multer from 'multer';
import shp from 'shpjs';
import fs from 'fs';

const upload = multer({ dest: 'uploads/' });

export default function(pool, logSystemAction) {
    const router = express.Router();

    // DANH SÁCH ƯU TIÊN TÊN CỘT (Từ trái sang phải)
    // Hệ thống sẽ kiểm tra lần lượt: nếu có 'kyhieumucd' thì dùng, nếu không mới tìm 'loaidat'
    const COLUMN_VARIANTS = {
        sodoto: ['shbando', 'sh_ban_do', 'tobando', 'to_ban_do', 'map_sheet', 'shmap', 'sodoto', 'so_to'],
        sothua: ['shthua', 'sh_thua', 'thua_dat', 'parcel_no', 'shparcel', 'so_thu_tu_thua', 'sothua', 'so_thua'],
        loaidat: ['kyhieumucd', 'ky_hieu_muc_dich', 'mucdich', 'mdsd', 'kh_mucdich', 'purpose', 'loaidat', 'loai_dat'],
        tenchu: ['tenchu', 'ten_chu', 'chu_so_huu', 'ten_chu_sd', 'owner', 'owner_name', 'chusudung'],
        diachi: ['diachi', 'dia_chi', 'vitri', 'vi_tri', 'address', 'location', 'khu_vuc'],
        dientich: ['dientich', 'dien_tich', 'dt_phaply', 'area', 'shape_area', 'st_area']
    };

    /**
     * Hàm tìm tên cột chính xác trong DB dựa trên danh sách ưu tiên
     */
    const resolveTableColumns = async (tableName) => {
        try {
            // 1. Lấy tất cả cột hiện có trong bảng
            const res = await pool.query(`
                SELECT column_name 
                FROM information_schema.columns 
                WHERE table_name = $1
            `, [tableName]);

            // Tạo Map: key là tên viết thường -> value là tên gốc (để query chính xác)
            const dbColsMap = {};
            res.rows.forEach(r => {
                dbColsMap[r.column_name.toLowerCase()] = r.column_name;
            });

            const mapping = {};

            // 2. Duyệt qua từng loại trường chuẩn (sodoto, loaidat...)
            for (const [standardKey, candidates] of Object.entries(COLUMN_VARIANTS)) {
                let foundCol = standardKey; // Mặc định fallback về tên chuẩn nếu không tìm thấy

                // 3. QUAN TRỌNG: Duyệt danh sách candidates TRƯỚC để lấy độ ưu tiên cao nhất
                for (const candidate of candidates) {
                    if (dbColsMap[candidate]) {
                        foundCol = dbColsMap[candidate];
                        break; // Tìm thấy ứng viên có độ ưu tiên cao nhất (ví dụ kyhieumucd) -> Dừng ngay
                    }
                }
                mapping[standardKey] = foundCol;
            }

            // console.log(`[Schema Resolve] Table ${tableName} map:`, mapping);
            return mapping;
        } catch (e) {
            console.error(`Error resolving columns for ${tableName}:`, e);
            return { sodoto: 'sodoto', sothua: 'sothua', loaidat: 'loaidat', tenchu: 'tenchu', diachi: 'diachi', dientich: 'dientich' };
        }
    };

    // Helper: Tự động thêm cột thiếu nếu không tìm thấy bất kỳ biến thể nào
    const syncTableSchema = async (tableName) => {
        try {
            const currentMap = await resolveTableColumns(tableName);
            const res = await pool.query(`SELECT column_name FROM information_schema.columns WHERE table_name = $1`, [tableName]);
            const existingCols = res.rows.map(r => r.column_name.toLowerCase());

            const missingCols = [];
            // Chỉ thêm cột chuẩn nếu cột đang được map cũng không tồn tại trong bảng (trường hợp bảng mới tinh)
            if (!existingCols.includes(currentMap.sodoto.toLowerCase())) missingCols.push({ name: 'sodoto', type: 'TEXT' });
            if (!existingCols.includes(currentMap.sothua.toLowerCase())) missingCols.push({ name: 'sothua', type: 'TEXT' });
            if (!existingCols.includes(currentMap.loaidat.toLowerCase())) missingCols.push({ name: 'loaidat', type: 'TEXT' });
            if (!existingCols.includes(currentMap.dientich.toLowerCase())) missingCols.push({ name: 'dientich', type: 'NUMERIC' });

            if (missingCols.length > 0) {
                console.log(`[Schema Sync] Adding missing columns to ${tableName}:`, missingCols.map(c=>c.name));
                for (const col of missingCols) {
                    await pool.query(`ALTER TABLE "${tableName}" ADD COLUMN IF NOT EXISTS "${col.name}" ${col.type}`);
                }
            }
            await pool.query(`CREATE INDEX IF NOT EXISTS "${tableName}_geom_idx" ON "${tableName}" USING GIST (geometry)`);
        } catch (e) {
            console.error(`[Schema Sync] Error syncing table ${tableName}:`, e.message);
        }
    };

    // --- 1. REGISTRY MANAGEMENT ---

    router.get('/spatial-tables', async (req, res) => {
        try {
            const result = await pool.query(`SELECT * FROM spatial_tables_registry ORDER BY created_at DESC`);
            res.json(result.rows);
        } catch (e) {
            res.status(500).json({ error: e.message });
        }
    });

    router.post('/spatial-tables', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        const safeName = tableName.toLowerCase().replace(/[^a-z0-9_]/g, '_');
        try {
            await pool.query('BEGIN');
            await pool.query(`
                CREATE TABLE IF NOT EXISTS "${safeName}" (
                    gid SERIAL PRIMARY KEY,
                    sodoto TEXT, sothua TEXT, tenchu TEXT, diachi TEXT, loaidat TEXT, dientich NUMERIC,
                    geometry GEOMETRY(Geometry, 4326),
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                )
            `);
            await pool.query(`CREATE INDEX IF NOT EXISTS "${safeName}_geom_idx" ON "${safeName}" USING GIST (geometry)`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [safeName, displayName, description]);

            await syncTableSchema(safeName);
            await logSystemAction(req, 'CREATE_TABLE', `Tạo bảng mới: ${safeName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok', tableName: safeName });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/link', async (req, res) => {
        const { tableName, displayName, description } = req.body;
        try {
            const check = await pool.query(`SELECT to_regclass($1) as exists`, [tableName]);
            if (!check.rows[0].exists) throw new Error(`Bảng ${tableName} không tồn tại.`);
            await pool.query(`
                INSERT INTO spatial_tables_registry (table_name, display_name, description) VALUES ($1, $2, $3)
                ON CONFLICT (table_name) DO UPDATE SET display_name = EXCLUDED.display_name
            `, [tableName, displayName, description]);

            await syncTableSchema(tableName);
            await logSystemAction(req, 'LINK_TABLE', `Liên kết bảng: ${tableName}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/spatial-tables/unlink', async (req, res) => {
        try {
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [req.body.tableName]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/spatial-tables/:name', async (req, res) => {
        const tableName = req.params.name;
        try {
            await pool.query('BEGIN');
            await pool.query(`DELETE FROM spatial_tables_registry WHERE table_name = $1`, [tableName]);
            await pool.query(`DROP TABLE IF EXISTS "${tableName}" CASCADE`);
            await logSystemAction(req, 'DROP_TABLE', `Xóa bảng: ${tableName}`);
            await pool.query('COMMIT');
            res.json({ status: 'ok' });
        } catch (e) { await pool.query('ROLLBACK'); res.status(500).json({ error: e.message }); }
    });

    // --- 2. DATA CRUD WITH DYNAMIC MAPPING ---

    router.get('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi } = req.query;
        if (!/^[a-zA-Z0-9_]+$/.test(table)) return res.status(400).json({ error: "Invalid table name" });

        try {
            const cols = await resolveTableColumns(table);

            // Query sử dụng alias chuẩn hóa output
            // COALESCE(..., NULL) để tường minh
            let query = `
                SELECT gid, 
                "${cols.sodoto}" as sodoto, 
                "${cols.sothua}" as sothua, 
                "${cols.tenchu}" as tenchu, 
                "${cols.diachi}" as diachi, 
                "${cols.loaidat}" as loaidat, 
                "${cols.dientich}" as dientich, 
                ST_AsGeoJSON(geometry) as geometry 
                FROM "${table}" WHERE 1=1
            `;
            const params = [];
            let idx = 1;

            if (sodoto) { query += ` AND "${cols.sodoto}"::text ILIKE $${idx++}`; params.push(`%${sodoto}%`); }
            if (sothua) { query += ` AND "${cols.sothua}"::text ILIKE $${idx++}`; params.push(`%${sothua}%`); }
            if (tenchu) { query += ` AND "${cols.tenchu}" ILIKE $${idx++}`; params.push(`%${tenchu}%`); }
            if (diachi) { query += ` AND "${cols.diachi}" ILIKE $${idx++}`; params.push(`%${diachi}%`); }

            query += ` ORDER BY gid DESC LIMIT 100`;

            const result = await pool.query(query, params);
            const features = result.rows.map(row => ({
                ...row,
                geometry: row.geometry ? JSON.parse(row.geometry) : null,
                // Trả về thêm các trường gốc (legacy support)
                // Vì select as alias 'loaidat', nên row.loaidat chính là giá trị của cột kyhieumucd
                kyhieumucd: row.loaidat, 
                shbando: row.sodoto,
                shthua: row.sothua
            }));
            res.json(features);
        } catch (e) {
            // Auto-heal attempt
            if (e.code === '42703') { // Undefined column
                 console.warn("Column missing, trying to sync schema...", e.message);
                 await syncTableSchema(table);
                 return res.status(500).json({ error: "Database schema was updated. Please refresh." });
            }
            res.status(500).json({ error: "Lỗi truy vấn: " + e.message });
        }
    });

    router.get('/data/:table/extent', async (req, res) => {
        try {
            const result = await pool.query(`SELECT ST_XMin(ext) as xmin, ST_YMin(ext) as ymin, ST_XMax(ext) as xmax, ST_YMax(ext) as ymax FROM (SELECT ST_Extent(geometry) as ext FROM "${req.params.table}") as t`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table', async (req, res) => {
        const { table } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let geomSql = 'NULL';
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            if (geometry) {
                geomSql = `ST_SetSRID(ST_GeomFromGeoJSON($7), 4326)`;
                params.push(JSON.stringify(geometry));
            }
            const query = `
                INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry)
                VALUES ($1, $2, $3, $4, $5, $6, ${geomSql}) RETURNING gid
            `;
            const result = await pool.query(query, params);
            await logSystemAction(req, 'ADD_PARCEL', `Thêm thửa đất vào ${table}`);
            res.json({ status: 'ok', gid: result.rows[0].gid });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/data/:table/:gid', async (req, res) => {
        const { table, gid } = req.params;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, geometry } = req.body;
        try {
            const cols = await resolveTableColumns(table);
            let query = `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6`;
            const params = [sodoto, sothua, tenchu, diachi, loaidat, dientich];
            let idx = 7;
            if (geometry) {
                query += `, geometry=ST_SetSRID(ST_GeomFromGeoJSON($${idx}), 4326)`;
                params.push(JSON.stringify(geometry));
                idx++;
            }
            query += ` WHERE gid=$${idx}`;
            params.push(gid);
            await pool.query(query, params);
            await logSystemAction(req, 'UPDATE_PARCEL', `Cập nhật thửa GID ${gid}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/data/:table/:gid', async (req, res) => {
        try {
            await pool.query(`DELETE FROM "${req.params.table}" WHERE gid=$1`, [req.params.gid]);
            await logSystemAction(req, 'DELETE_PARCEL', `Xóa thửa GID ${req.params.gid}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/data/:table/upload', upload.single('file'), async (req, res) => {
        const { table } = req.params;
        const file = req.file;
        const { sodoto, sothua, tenchu, diachi, loaidat, dientich, gid } = req.body; 

        if (!file) return res.status(400).json({ error: 'No file uploaded' });

        try {
            const cols = await resolveTableColumns(table);
            const buffer = fs.readFileSync(file.path);
            let geojson;

            if (file.originalname.endsWith('.zip')) geojson = await shp(buffer);
            else geojson = JSON.parse(buffer.toString());

            let geometry = null;
            if (Array.isArray(geojson)) geometry = geojson[0]?.features[0]?.geometry;
            else if (geojson.type === 'FeatureCollection') geometry = geojson.features[0]?.geometry;
            else if (geojson.type === 'Feature') geometry = geojson.geometry;
            else geometry = geojson;

            if (!geometry) throw new Error("Không tìm thấy dữ liệu hình học.");

            if (gid) {
                await pool.query(
                    `UPDATE "${table}" SET "${cols.sodoto}"=$1, "${cols.sothua}"=$2, "${cols.tenchu}"=$3, "${cols.diachi}"=$4, "${cols.loaidat}"=$5, "${cols.dientich}"=$6, geometry=ST_SetSRID(ST_GeomFromGeoJSON($7), 4326) WHERE gid=$8`,
                    [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry), gid]
                );
            } else {
                await pool.query(
                    `INSERT INTO "${table}" ("${cols.sodoto}", "${cols.sothua}", "${cols.tenchu}", "${cols.diachi}", "${cols.loaidat}", "${cols.dientich}", geometry) VALUES ($1, $2, $3, $4, $5, $6, ST_SetSRID(ST_GeomFromGeoJSON($7), 4326))`,
                    [sodoto, sothua, tenchu, diachi, loaidat, dientich, JSON.stringify(geometry)]
                );
            }
            fs.unlinkSync(file.path);
            await logSystemAction(req, 'UPLOAD_GEOMETRY', `Upload hình học cho ${table}`);
            res.json({ status: 'ok' });
        } catch (e) {
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: "Lỗi xử lý file: " + e.message });
        }
    });

    return router;
}

import React, { useEffect, useState, useRef, useCallback } from 'react';
import { parcelApi, ParcelDTO, SpatialTable } from '../services/parcelApi';
import { 
    Edit, Trash2, Plus, Save, X, RefreshCw, Layers, Search, 
    Database, Filter, AlertTriangle, ClipboardList, Info, 
    FileUp, Download, FileJson, Paperclip, Home, MapPin, Check, Eye, Maximize2, ZoomIn, ZoomOut, RotateCcw, ArrowRight, FileDown
} from 'lucide-react';

const ParcelManager: React.FC = () => {
    const [layer, setLayer] = useState('');
    const [availableTables, setAvailableTables] = useState<SpatialTable[]>([]);
    const [parcels, setParcels] = useState<ParcelDTO[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [searchFilters, setSearchFilters] = useState({ sodoto: '', sothua: '', tenchu: '', diachi: '' });

    // Form & Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isPreviewOpen, setIsPreviewOpen] = useState(false);
    const [editingId, setEditingId] = useState<number | null>(null);
    const [previewParcel, setPreviewParcel] = useState<any>(null);
    const [formData, setFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });

    // Interactive Preview State
    const [viewState, setViewState] = useState({ scale: 1, offset: { x: 0, y: 0 } });
    const isDragging = useRef(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const fileInputRef = useRef<HTMLInputElement>(null);
    const previewCanvasRef = useRef<HTMLCanvasElement>(null);
    const editCanvasRef = useRef<HTMLCanvasElement>(null);

    const [hasSearched, setHasSearched] = useState(false);

    // --- HELPER: ÁNH XẠ THÔNG MINH CÁC CỘT DỮ LIỆU ---
    const getFieldValue = (obj: any, aliases: string[]) => {
        for (const alias of aliases) {
            if (obj[alias] !== undefined && obj[alias] !== null && obj[alias] !== '') return obj[alias];
            const lower = alias.toLowerCase();
            const keys = Object.keys(obj);
            const foundKey = keys.find(k => k.toLowerCase() === lower);
            if (foundKey && obj[foundKey] !== undefined && obj[foundKey] !== null && obj[foundKey] !== '') return obj[foundKey];
        }
        return null;
    };

    const getLandType = (p: any) => getFieldValue(p, ['loaidat', 'kyhieumucd', 'mucdich', 'mdsd', 'purpose', 'kh_mucdich']) || 'N/A';
    const getOwner = (p: any) => getFieldValue(p, ['tenchu', 'chu_so_huu', 'owner', 'ten_chu', 'chusudung']) || '--';
    const getAreaVal = (p: any) => parseFloat(getFieldValue(p, ['dientich', 'dien_tich', 'area', 'shape_area', 'dt_phaply']) || 0);
    const getAddressVal = (p: any) => getFieldValue(p, ['diachi', 'dia_chi', 'address', 'vi_tri', 'khu_vuc']) || '--';
    const getSheetNo = (p: any) => getFieldValue(p, ['sodoto', 'so_to', 'shbando', 'map_sheet']) || '--';
    const getParcelNo = (p: any) => getFieldValue(p, ['sothua', 'so_thua', 'shthua', 'parcel_no']) || '--';

    useEffect(() => { loadTables(); }, []);

    useEffect(() => { 
        if (layer) {
            setParcels([]);
            setHasSearched(false);
            setError(null);
        }
    }, [layer]);

    const loadTables = async () => {
        setLoading(true);
        try {
            const tables = await parcelApi.manageTables.getAll();
            setAvailableTables(tables);
            if (tables.length > 0) {
                if (!layer) setLayer(tables[0].table_name);
                setError(null);
            } else {
                setLayer(''); 
            }
        } catch (e: any) {
            console.error(e);
            setError("Không thể tải danh sách lớp dữ liệu. Vui lòng kiểm tra kết nối Server API.");
        } finally {
            setLoading(false);
        }
    };

    const handleSearchClick = async () => {
        if (!layer) return alert("Vui lòng chọn một lớp dữ liệu trước.");
        setLoading(true);
        setError(null);
        setHasSearched(true);
        try {
            const data = await parcelApi.getAll(layer, searchFilters);
            setParcels(data);
        } catch (err: any) {
            setError(err.message);
            setParcels([]); 
        } finally { setLoading(false); }
    };

    // --- CHỨC NĂNG XUẤT DỮ LIỆU (DOWNLOAD PARCEL) ---
    const handleDownloadParcel = (p: any) => {
        try {
            const geojson = {
                type: "Feature",
                geometry: p.geometry,
                properties: {
                    gid: p.gid,
                    so_to: getSheetNo(p),
                    so_thua: getParcelNo(p),
                    chu_su_dung: getOwner(p),
                    loai_dat: getLandType(p),
                    dien_tich: getAreaVal(p),
                    dia_chi: getAddressVal(p),
                    nguon_du_lieu: layer,
                    ngay_xuat: new Date().toISOString()
                }
            };

            const dataStr = JSON.stringify(geojson, null, 2);
            const dataBlob = new Blob([dataStr], { type: 'application/json' });
            const url = URL.createObjectURL(dataBlob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `Thua_${geojson.properties.so_to}_${geojson.properties.so_thua}_${layer}.geojson`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        } catch (err) {
            alert("Lỗi khi tạo file tải xuống: " + err);
        }
    };

    const openAddModal = () => {
        setEditingId(null);
        setFormData({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });
        setIsModalOpen(true);
    };

    const handleEdit = (p: any) => {
        setEditingId(p.gid!);
        setFormData({
            sodoto: getSheetNo(p).toString(),
            sothua: getParcelNo(p).toString(),
            tenchu: getOwner(p),
            diachi: getAddressVal(p),
            loaidat: getLandType(p),
            dientich: getAreaVal(p),
            geometry: p.geometry,
            file: null
        });
        setIsModalOpen(true);
    };

    const handleQuickView = (p: any) => {
        setPreviewParcel(p);
        setViewState({ scale: 1, offset: { x: 0, y: 0 } }); 
        setIsPreviewOpen(true);
    };

    const drawParcel = useCallback((parcel: any, canvas: HTMLCanvasElement | null, state: typeof viewState) => {
        if (!canvas || !parcel?.geometry) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        let rawCoords: any[] = [];
        if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0];
        else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0];

        if (rawCoords.length === 0) return;

        const points = rawCoords.map((c: any, i: number) => ({ id: i + 1, x: c[0], y: c[1] }));
        if (points.length > 1 && points[0].x === points[points.length-1].x && points[0].y === points[points.length-1].y) {
            points.pop();
        }

        const xs = points.map(p => p.x);
        const ys = points.map(p => p.y);
        const minX = Math.min(...xs), maxX = Math.max(...xs);
        const minY = Math.min(...ys), maxY = Math.max(...ys);
        const rangeX = maxX - minX || 0.000001;
        const rangeY = maxY - minY || 0.000001;

        const padding = 40;
        const baseScale = Math.min((canvas.width - padding * 2) / rangeX, (canvas.height - padding * 2) / rangeY);
        const currentScale = baseScale * state.scale;
        const midX = (minX + maxX) / 2;
        const midY = (minY + maxY) / 2;

        ctx.clearRect(0, 0, canvas.width, canvas.height);
        const tx = (x: number) => (canvas.width / 2) + (x - midX) * currentScale + state.offset.x;
        const ty = (y: number) => (canvas.height / 2) - (y - midY) * currentScale + state.offset.y;

        ctx.strokeStyle = 'rgba(30, 41, 59, 0.5)';
        ctx.lineWidth = 0.5;
        const step = 50 * state.scale;
        for(let i = state.offset.x % step; i < canvas.width; i += step) {
            ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke();
        }
        for(let i = state.offset.y % step; i < canvas.height; i += step) {
            ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke();
        }

        ctx.beginPath();
        ctx.lineWidth = 3 / Math.sqrt(state.scale); 
        ctx.strokeStyle = '#3b82f6';
        ctx.lineJoin = 'round';
        ctx.fillStyle = 'rgba(59, 130, 246, 0.15)';
        points.forEach((pt, idx) => {
            const px = tx(pt.x), py = ty(pt.y);
            if (idx === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
        });
        ctx.closePath();
        ctx.fill();
        ctx.stroke();

        if (state.scale > 0.3) {
            points.forEach((pt) => {
                const px = tx(pt.x), py = ty(pt.y);
                ctx.beginPath();
                ctx.arc(px, py, 4, 0, Math.PI * 2);
                ctx.fillStyle = '#fff';
                ctx.fill();
                ctx.strokeStyle = '#3b82f6';
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.font = `bold ${Math.max(8, 10 * state.scale)}px sans-serif`;
                ctx.fillStyle = '#94a3b8';
                ctx.fillText(pt.id.toString(), px + 8, py + 4);
            });
        }
    }, []);

    useEffect(() => {
        if (isPreviewOpen && previewParcel) {
            drawParcel(previewParcel, previewCanvasRef.current, viewState);
        }
    }, [isPreviewOpen, previewParcel, viewState, drawParcel]);

    useEffect(() => {
        if (isModalOpen && formData.geometry) {
            drawParcel({ geometry: formData.geometry }, editCanvasRef.current, { scale: 1, offset: { x: 0, y: 0 } });
        }
    }, [isModalOpen, formData.geometry, drawParcel]);

    const handleWheel = (e: React.WheelEvent) => {
        const zoomSpeed = 0.1;
        const delta = e.deltaY > 0 ? 1 - zoomSpeed : 1 + zoomSpeed;
        const newScale = Math.min(Math.max(viewState.scale * delta, 0.1), 20);
        setViewState(prev => ({ ...prev, scale: newScale }));
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isDragging.current) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;
        setViewState(prev => ({
            ...prev,
            offset: { x: prev.offset.x + dx, y: prev.offset.y + dy }
        }));
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => { isDragging.current = false; };
    const resetView = () => setViewState({ scale: 1, offset: { x: 0, y: 0 } });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.sothua || !formData.sodoto) return alert("Vui lòng nhập đầy đủ Số tờ và Số thửa.");
        setLoading(true);
        try {
            if (editingId) {
                if (formData.file) await parcelApi.createWithUpload(layer, { ...formData, gid: editingId });
                else await parcelApi.update(layer, editingId, formData);
            } else {
                if (formData.file) await parcelApi.createWithUpload(layer, formData);
                else await parcelApi.create(layer, formData);
            }
            setIsModalOpen(false);
            handleSearchClick(); 
        } catch (err: any) { alert("Lỗi: " + err.message); } finally { setLoading(false); }
    };

    const handleDelete = async (gid: number) => {
        if (!confirm(`Xóa thửa đất GID: ${gid}?`)) return;
        setLoading(true);
        try {
            await parcelApi.delete(layer, gid);
            handleSearchClick();
        } catch (err: any) { alert(err.message); } finally { setLoading(false); }
    };

    // --- HIỂN THỊ KHI CHƯA CÓ BẢNG ---
    if (!loading && availableTables.length === 0) {
        return (
            <div className="p-10 flex flex-col items-center justify-center h-full bg-gray-900 text-center">
                <div className="bg-gray-800 p-8 rounded-full mb-6 border border-gray-700 shadow-2xl">
                    <Database size={64} className="text-gray-600" />
                </div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tight mb-2">Chưa có bảng dữ liệu nào</h2>
                <p className="text-gray-400 max-w-md mb-8">Hệ thống chưa tìm thấy bảng dữ liệu (Registry) nào để quản lý thửa đất. Vui lòng tạo mới hoặc liên kết bảng có sẵn trong Database.</p>
                <div className="flex gap-4">
                    <button onClick={loadTables} className="px-6 py-3 bg-gray-800 text-white rounded-xl hover:bg-gray-700 font-bold transition-all border border-gray-700 flex items-center gap-2">
                        <RefreshCw size={18} /> Thử lại
                    </button>
                    <a href="#" className="px-6 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-500 font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2 cursor-not-allowed opacity-80" title="Vui lòng truy cập menu Admin > Lớp bản đồ & DB">
                        <Layers size={18} /> Đi tới Quản lý DB <ArrowRight size={16}/>
                    </a>
                </div>
                <p className="mt-6 text-[10px] text-gray-500 italic">Mẹo: Truy cập trang "Quản trị hệ thống" &gt; "Lớp bản đồ & DB" để khởi tạo bảng.</p>
            </div>
        );
    }

    return (
        <div className="p-6 bg-gray-950 text-white min-h-full space-y-6 font-sans flex flex-col">
            {/* TOP HEADER */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-gray-800 pb-6 gap-4">
                <div className="flex items-center gap-4">
                    <div className="bg-blue-600/20 p-3 rounded-2xl border border-blue-500/30">
                        <Database className="text-blue-500" size={28} />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black tracking-tight flex items-center gap-2 uppercase">Quản trị Thửa đất</h2>
                        <div className="flex items-center gap-2 text-gray-500 text-xs mt-0.5 font-bold uppercase tracking-widest">
                            <Layers size={14} className="text-blue-400" />
                            <span>Database: {layer || 'Chưa chọn'}</span>
                        </div>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button onClick={loadTables} className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 px-4 py-2.5 rounded-xl text-xs font-black transition-all border border-gray-700">
                        <RefreshCw size={16} className={loading ? "animate-spin" : ""} /> TẢI LẠI
                    </button>
                    <button onClick={openAddModal} disabled={!layer} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 px-5 py-2.5 rounded-xl text-xs font-black transition-all shadow-lg shadow-blue-500/20 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                        <Plus size={18} /> THÊM THỬA ĐẤT
                    </button>
                </div>
            </div>

            {/* MAIN ACTION CARD */}
            <div className="bg-gray-900 rounded-3xl border border-gray-800 shadow-2xl overflow-hidden flex flex-col flex-1">
                {/* HORIZONTAL FILTER BAR */}
                <div className="p-5 bg-gray-900/50 border-b border-gray-800 grid grid-cols-1 md:grid-cols-6 gap-4 items-end">
                    <div className="space-y-1.5 md:col-span-1">
                        <label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Lớp dữ liệu</label>
                        <select value={layer} onChange={(e) => setLayer(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-blue-500 font-bold">
                            {availableTables.length > 0 ? (
                                availableTables.map(tbl => <option key={tbl.table_name} value={tbl.table_name}>{tbl.display_name || tbl.table_name}</option>)
                            ) : (
                                <option value="">(Trống)</option>
                            )}
                        </select>
                    </div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Số tờ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none font-bold text-blue-400" placeholder="Số tờ..." value={searchFilters.sodoto} onChange={e=>setSearchFilters({...searchFilters, sodoto: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Số thửa</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none font-bold text-blue-400" placeholder="Số thửa..." value={searchFilters.sothua} onChange={e=>setSearchFilters({...searchFilters, sothua: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Tên chủ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none" placeholder="Tên chủ..." value={searchFilters.tenchu} onChange={e=>setSearchFilters({...searchFilters, tenchu: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Địa chỉ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none" placeholder="Địa chỉ..." value={searchFilters.diachi} onChange={e=>setSearchFilters({...searchFilters, diachi: e.target.value})} /></div>
                    <div className="md:col-span-1"><button onClick={handleSearchClick} disabled={loading || !layer} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all uppercase tracking-widest disabled:opacity-50">{loading ? <RefreshCw size={14} className="animate-spin" /> : <Filter size={14}/>} TRUY VẤN</button></div>
                </div>

                {/* TABLE SECTION */}
                <div className="overflow-auto flex-1 custom-scrollbar">
                    {error ? (
                        <div className="flex flex-col items-center justify-center h-full py-20 text-red-400 gap-4">
                            <AlertTriangle size={64} className="opacity-20" />
                            <div className="text-center">
                                <p className="text-sm font-black uppercase tracking-widest mb-1">{error}</p>
                                <p className="text-xs text-gray-500">Vui lòng kiểm tra lại kết nối Backend hoặc cấu hình Database.</p>
                            </div>
                            <button onClick={loadTables} className="px-4 py-2 bg-red-900/20 hover:bg-red-900/40 text-red-400 rounded-lg text-xs font-bold transition-all border border-red-800/50">Thử lại</button>
                        </div>
                    ) : !hasSearched ? (
                        <div className="flex flex-col items-center justify-center h-full py-40 text-gray-700">
                            <Search size={80} className="opacity-10 mb-4" />
                            <p className="text-sm font-bold uppercase tracking-[0.3em] opacity-30">Chế độ chờ tìm kiếm</p>
                        </div>
                    ) : (
                        <table className="w-full text-sm text-left border-collapse">
                            <thead className="bg-gray-950 text-gray-500 uppercase text-[10px] sticky top-0 z-10 font-black tracking-widest border-b border-gray-800">
                                <tr>
                                    <th className="p-4">Tờ/Thửa</th>
                                    <th className="p-4">Chủ sử dụng</th>
                                    <th className="p-4">Loại đất</th>
                                    <th className="p-4 text-right">Diện tích (m²)</th>
                                    <th className="p-4">Địa chỉ</th>
                                    <th className="p-4 text-center">Hành động</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-800/50">
                                {parcels.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="p-8 text-center text-gray-500 italic">Không tìm thấy dữ liệu phù hợp</td>
                                    </tr>
                                ) : parcels.map(p => (
                                    <tr key={p.gid} className="hover:bg-blue-600/5 transition-colors group">
                                        <td className="p-4">
                                            <div className="flex flex-col">
                                                <span className="font-black text-blue-400 text-sm">{getSheetNo(p)}/{getParcelNo(p)}</span>
                                                <span className="text-[9px] text-gray-600 font-mono">GID: {p.gid}</span>
                                            </div>
                                        </td>
                                        <td className="p-4 font-bold text-gray-200">{getOwner(p)}</td>
                                        <td className="p-4">
                                            <span className="bg-gray-800 text-gray-400 text-[10px] px-2 py-1 rounded-lg font-black border border-gray-700">
                                                {getLandType(p)}
                                            </span>
                                        </td>
                                        <td className="p-4 text-right font-mono text-emerald-500 font-black">
                                            {getAreaVal(p) ? Math.round(getAreaVal(p)).toLocaleString() : '--'}
                                        </td>
                                        <td className="p-4 text-xs text-gray-500 max-w-xs truncate">{getAddressVal(p)}</td>
                                        <td className="p-4">
                                            <div className="flex justify-center gap-2">
                                                <button onClick={() => handleQuickView(p)} className="p-2 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-600 hover:text-white rounded-xl transition-all" title="Xem nhanh sơ đồ"><Eye size={16}/></button>
                                                <button onClick={() => handleDownloadParcel(p)} className="p-2 bg-indigo-500/10 text-indigo-400 hover:bg-indigo-600 hover:text-white rounded-xl transition-all" title="Tải xuống dữ liệu GeoJSON"><FileDown size={16}/></button>
                                                <button onClick={() => handleEdit(p)} className="p-2 bg-blue-500/10 text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all"><Edit size={16}/></button>
                                                <button onClick={() => handleDelete(p.gid!)} className="p-2 bg-red-500/10 text-red-400 hover:bg-red-600 hover:text-white rounded-xl transition-all"><Trash2 size={16}/></button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>

            {/* --- MODAL XEM TRƯỚC SƠ ĐỒ (QUICK VIEW) --- */}
            {isPreviewOpen && previewParcel && (
                <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 animate-in fade-in zoom-in duration-300">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-3xl shadow-[0_0_100px_rgba(59,130,246,0.2)] overflow-hidden relative">
                        <button onClick={() => setIsPreviewOpen(false)} className="absolute top-6 right-6 z-20 bg-gray-800/80 hover:bg-red-600 text-white p-3 rounded-full transition-all active:scale-90 shadow-lg"><X size={24}/></button>
                        <div className="flex flex-col md:flex-row h-full">
                            <div className="flex-1 bg-gray-950 p-6 relative group">
                                <div className="absolute top-8 left-8 z-10 pointer-events-none">
                                    <div className="flex items-center gap-3 text-emerald-400 font-black text-[10px] uppercase tracking-[0.3em] mb-1">
                                        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> Sơ đồ tương tác
                                    </div>
                                    <h3 className="text-2xl font-black text-white tracking-tighter">THỬA {getParcelNo(previewParcel)} - TỜ {getSheetNo(previewParcel)}</h3>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase mt-1 italic">Dùng chuột để Zoom & Di chuyển</p>
                                </div>
                                <div className="absolute bottom-8 left-8 flex flex-col gap-2 z-10 opacity-60 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => setViewState(p => ({ ...p, scale: Math.min(p.scale * 1.2, 20) }))} className="p-3 bg-gray-800 hover:bg-blue-600 rounded-xl text-white shadow-xl transition-all"><ZoomIn size={20}/></button>
                                    <button onClick={() => setViewState(p => ({ ...p, scale: Math.max(p.scale / 1.2, 0.1) }))} className="p-3 bg-gray-800 hover:bg-blue-600 rounded-xl text-white shadow-xl transition-all"><ZoomOut size={20}/></button>
                                    <button onClick={resetView} className="p-3 bg-gray-800 hover:bg-orange-600 rounded-xl text-white shadow-xl transition-all" title="Reset View"><RotateCcw size={20}/></button>
                                </div>
                                <div className="flex items-center justify-center h-[500px] cursor-move overflow-hidden">
                                    <canvas ref={previewCanvasRef} width={600} height={500} className="w-full h-full" onWheel={handleWheel} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} />
                                </div>
                            </div>
                            <div className="w-full md:w-64 bg-gray-900 border-l border-gray-800 p-8 flex flex-col justify-center gap-6">
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Mục đích SD</p><p className="text-xl font-black text-blue-400">{getLandType(previewParcel)}</p></div>
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Diện tích</p><p className="text-2xl font-black text-emerald-500">{Math.round(getAreaVal(previewParcel)).toLocaleString()} m²</p></div>
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Chủ sở hữu</p><p className="text-sm font-bold text-gray-200">{getOwner(previewParcel)}</p></div>
                                <div className="flex flex-col gap-2">
                                    <button onClick={() => handleDownloadParcel(previewParcel)} className="w-full bg-indigo-600 text-white py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all flex items-center justify-center gap-2">
                                        <FileDown size={14}/> Tải dữ liệu
                                    </button>
                                    <button onClick={() => setIsPreviewOpen(false)} className="w-full bg-white text-black py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-blue-400 hover:text-white transition-all">Đóng xem</button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MODAL FORM (THÊM/SỬA) --- */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
                    <div className="bg-gray-900 border border-gray-800 rounded-3xl w-full max-w-4xl shadow-2xl overflow-hidden flex flex-col md:flex-row">
                        <div className="flex-1 p-8 overflow-y-auto max-h-[85vh]">
                            <div className="flex justify-between items-center mb-8 border-b border-gray-800 pb-4">
                                <div className="flex items-center gap-3">
                                    <div className={`p-2 rounded-xl ${editingId ? 'bg-orange-500/20 text-orange-500' : 'bg-blue-500/20 text-blue-500'}`}>
                                        {editingId ? <Edit size={24} /> : <Plus size={24} />}
                                    </div>
                                    <h3 className="text-lg font-black uppercase tracking-tighter">{editingId ? "Cập nhật dữ liệu thửa" : "Đăng ký thửa đất mới"}</h3>
                                </div>
                                <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                            </div>
                            <form onSubmit={handleSubmit} className="space-y-5">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Số tờ bản đồ *</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.sodoto} onChange={e=>setFormData({...formData, sodoto: e.target.value})} required /></div>
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Số thứ tự thửa *</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.sothua} onChange={e=>setFormData({...formData, sothua: e.target.value})} required /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Chủ sở hữu</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.tenchu||''} onChange={e=>setFormData({...formData, tenchu: e.target.value})} /></div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Mục đích (Loại đất)</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-black uppercase" value={formData.loaidat||''} onChange={e=>setFormData({...formData, loaidat: e.target.value.toUpperCase()})} /></div>
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Diện tích (m²)</label><input type="number" className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-mono font-bold text-emerald-500" value={formData.dientich||''} onChange={e=>setFormData({...formData, dientich: parseFloat(e.target.value)})} /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Địa chỉ chi tiết</label><textarea className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none h-20 resize-none" value={formData.diachi||''} onChange={e=>setFormData({...formData, diachi: e.target.value})} /></div>
                                <div className="pt-4 flex gap-3">
                                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-gray-400 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest">HỦY</button>
                                    <button type="submit" disabled={loading} className="flex-[2] bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex justify-center items-center gap-2">{loading ? <RefreshCw className="animate-spin" size={16}/> : <Save size={16}/>} LƯU DỮ LIỆU</button>
                                </div>
                            </form>
                        </div>
                        <div className="hidden md:flex w-[350px] bg-gray-950 border-l border-gray-800 p-8 flex-col">
                            <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-6">Trực quan hóa thửa đất</h4>
                            <div className="flex-1 bg-gray-900 rounded-2xl border border-gray-800 relative flex items-center justify-center overflow-hidden">
                                {formData.geometry ? <canvas ref={editCanvasRef} width={300} height={300} className="w-full h-full" /> : <div className="text-center p-6 flex flex-col items-center gap-3"><MapPin className="text-gray-800" size={48} /><p className="text-[10px] text-gray-700 font-bold uppercase italic">Chưa có dữ liệu hình học</p></div>}
                            </div>
                            <div className="mt-6 p-4 bg-gray-900 rounded-2xl border border-gray-800">
                                <div onClick={() => fileInputRef.current?.click()} className="cursor-pointer group flex flex-col items-center gap-2">
                                    <FileUp className="text-gray-500 group-hover:text-blue-500 transition-colors" size={24} />
                                    <p className="text-[9px] text-gray-500 font-bold uppercase text-center">{formData.file ? formData.file.name : "Tải lên Shapefile / GeoJSON để cập nhật hình học"}</p>
                                    <input type="file" ref={fileInputRef} className="hidden" accept=".zip,.geojson,.json" onChange={e => setFormData({ ...formData, file: e.target.files?.[0] || null })} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ParcelManager;

import React, { useEffect, useState, useRef, useCallback } from 'react';
import { parcelApi, ParcelDTO, SpatialTable } from '../services/parcelApi';
import { 
    Edit, Trash2, Plus, Save, X, RefreshCw, Layers, Search, 
    Database, Filter, AlertTriangle, ClipboardList, Info, 
    FileUp, Download, FileJson, Paperclip, Home, MapPin, Check, Eye, Maximize2, ZoomIn, ZoomOut, RotateCcw, ArrowRight, FileDown, CheckCircle2
} from 'lucide-react';

const ParcelManager: React.FC = () => {
    const [layer, setLayer] = useState('');
    const [availableTables, setAvailableTables] = useState<SpatialTable[]>([]);
    const [parcels, setParcels] = useState<ParcelDTO[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [searchFilters, setSearchFilters] = useState({ sodoto: '', sothua: '', tenchu: '', diachi: '' });

    // Form & Modal State
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isPreviewOpen, setIsPreviewOpen] = useState(false);
    const [editingId, setEditingId] = useState<number | null>(null);
    const [previewParcel, setPreviewParcel] = useState<any>(null);
    const [formData, setFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    // Interactive Preview State
    const [viewState, setViewState] = useState({ scale: 1, offset: { x: 0, y: 0 } });
    const isDragging = useRef(false);
    const lastMousePos = useRef({ x: 0, y: 0 });

    const fileInputRef = useRef<HTMLInputElement>(null);
    const previewCanvasRef = useRef<HTMLCanvasElement>(null);
    const editCanvasRef = useRef<HTMLCanvasElement>(null);

    const [hasSearched, setHasSearched] = useState(false);

    // --- HELPER: ÁNH XẠ THÔNG MINH CÁC CỘT DỮ LIỆU ---
    const getFieldValue = (obj: any, aliases: string[]) => {
        for (const alias of aliases) {
            if (obj[alias] !== undefined && obj[alias] !== null && obj[alias] !== '') return obj[alias];
            const lower = alias.toLowerCase();
            const keys = Object.keys(obj);
            const foundKey = keys.find(k => k.toLowerCase() === lower);
            if (foundKey && obj[foundKey] !== undefined && obj[foundKey] !== null && obj[foundKey] !== '') return obj[foundKey];
        }
        return null;
    };

    const getLandType = (p: any) => getFieldValue(p, ['loaidat', 'kyhieumucd', 'mucdich', 'mdsd', 'purpose', 'kh_mucdich']) || 'N/A';
    const getOwner = (p: any) => getFieldValue(p, ['tenchu', 'chu_so_huu', 'owner', 'ten_chu', 'chusudung']) || '--';
    const getAreaVal = (p: any) => parseFloat(getFieldValue(p, ['dientich', 'dien_tich', 'area', 'shape_area', 'dt_phaply']) || 0);
    const getAddressVal = (p: any) => getFieldValue(p, ['diachi', 'dia_chi', 'address', 'vi_tri', 'khu_vuc']) || '--';
    const getSheetNo = (p: any) => getFieldValue(p, ['sodoto', 'so_to', 'shbando', 'map_sheet']) || '--';
    const getParcelNo = (p: any) => getFieldValue(p, ['sothua', 'so_thua', 'shthua', 'parcel_no']) || '--';

    useEffect(() => { loadTables(); }, []);

    useEffect(() => { 
        if (layer) {
            setParcels([]);
            setHasSearched(false);
            setError(null);
        }
    }, [layer]);

    const loadTables = async () => {
        setLoading(true);
        try {
            const tables = await parcelApi.manageTables.getAll();
            setAvailableTables(tables);
            if (tables.length > 0) {
                if (!layer) setLayer(tables[0].table_name);
                setError(null);
            } else {
                setLayer(''); 
            }
        } catch (e: any) {
            console.error(e);
            setError("Không thể tải danh sách lớp dữ liệu. Vui lòng kiểm tra kết nối Server API.");
        } finally {
            setLoading(false);
        }
    };

    const handleSearchClick = async () => {
        if (!layer) return showDialog('error', 'Lỗi truy vấn', 'Vui lòng chọn một lớp dữ liệu trước khi thực hiện tìm kiếm.');
        setLoading(true);
        setError(null);
        setHasSearched(true);
        try {
            const data = await parcelApi.getAll(layer, searchFilters);
            setParcels(data);
        } catch (err: any) {
            setError(err.message);
            setParcels([]); 
        } finally { setLoading(false); }
    };

    // --- CHỨC NĂNG XUẤT DỮ LIỆU (DOWNLOAD PARCEL) ---
    const handleDownloadParcel = (p: any) => {
        try {
            const geojson = {
                type: "Feature",
                geometry: p.geometry,
                properties: {
                    gid: p.gid,
                    so_to: getSheetNo(p),
                    so_thua: getParcelNo(p),
                    chu_su_dung: getOwner(p),
                    loai_dat: getLandType(p),
                    dien_tich: getAreaVal(p),
                    dia_chi: getAddressVal(p),
                    nguon_du_lieu: layer,
                    ngay_xuat: new Date().toISOString()
                }
            };

            const dataStr = JSON.stringify(geojson, null, 2);
            const dataBlob = new Blob([dataStr], { type: 'application/json' });
            const url = URL.createObjectURL(dataBlob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `Thua_${geojson.properties.so_to}_${geojson.properties.so_thua}_${layer}.geojson`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        } catch (err) {
            showDialog('error', 'Lỗi xuất file', "Không thể tạo tệp tải xuống: " + err);
        }
    };

    const openAddModal = () => {
        setEditingId(null);
        setFormData({ sothua: '', sodoto: '', tenchu: '', diachi: '', loaidat: '', file: null });
        setIsModalOpen(true);
    };

    const handleEdit = (p: any) => {
        setEditingId(p.gid!);
        setFormData({
            sodoto: getSheetNo(p).toString(),
            sothua: getParcelNo(p).toString(),
            tenchu: getOwner(p),
            diachi: getAddressVal(p),
            loaidat: getLandType(p),
            dientich: getAreaVal(p),
            geometry: p.geometry,
            file: null
        });
        setIsModalOpen(true);
    };

    const handleQuickView = (p: any) => {
        setPreviewParcel(p);
        setViewState({ scale: 1, offset: { x: 0, y: 0 } }); 
        setIsPreviewOpen(true);
    };

    const drawParcel = useCallback((parcel: any, canvas: HTMLCanvasElement | null, state: typeof viewState) => {
        if (!canvas || !parcel?.geometry) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        let rawCoords: any[] = [];
        if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0];
        else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0];

        if (rawCoords.length === 0) return;

        const points = rawCoords.map((c: any, i: number) => ({ id: i + 1, x: c[0], y: c[1] }));
        if (points.length > 1 && points[0].x === points[points.length-1].x && points[0].y === points[points.length-1].y) {
            points.pop();
        }

        const xs = points.map(p => p.x);
        const ys = points.map(p => p.y);
        const minX = Math.min(...xs), maxX = Math.max(...xs);
        const minY = Math.min(...ys), maxY = Math.max(...ys);
        const rangeX = maxX - minX || 0.000001;
        const rangeY = maxY - minY || 0.000001;

        const padding = 40;
        const baseScale = Math.min((canvas.width - padding * 2) / rangeX, (canvas.height - padding * 2) / rangeY);
        const currentScale = baseScale * state.scale;
        const midX = (minX + maxX) / 2;
        const midY = (minY + maxY) / 2;

        ctx.clearRect(0, 0, canvas.width, canvas.height);
        const tx = (x: number) => (canvas.width / 2) + (x - midX) * currentScale + state.offset.x;
        const ty = (y: number) => (canvas.height / 2) - (y - midY) * currentScale + state.offset.y;

        ctx.strokeStyle = 'rgba(30, 41, 59, 0.5)';
        ctx.lineWidth = 0.5;
        const step = 50 * state.scale;
        for(let i = state.offset.x % step; i < canvas.width; i += step) {
            ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke();
        }
        for(let i = state.offset.y % step; i < canvas.height; i += step) {
            ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke();
        }

        ctx.beginPath();
        ctx.lineWidth = 3 / Math.sqrt(state.scale); 
        ctx.strokeStyle = '#3b82f6';
        ctx.lineJoin = 'round';
        ctx.fillStyle = 'rgba(59, 130, 246, 0.15)';
        points.forEach((pt, idx) => {
            const px = tx(pt.x), py = ty(pt.y);
            if (idx === 0) ctx.moveTo(px, py); else ctx.lineTo(px, py);
        });
        ctx.closePath();
        ctx.fill();
        ctx.stroke();

        if (state.scale > 0.3) {
            points.forEach((pt) => {
                const px = tx(pt.x), py = ty(pt.y);
                ctx.beginPath();
                ctx.arc(px, py, 4, 0, Math.PI * 2);
                ctx.fillStyle = '#fff';
                ctx.fill();
                ctx.strokeStyle = '#3b82f6';
                ctx.lineWidth = 2;
                ctx.stroke();
                ctx.font = `bold ${Math.max(8, 10 * state.scale)}px sans-serif`;
                ctx.fillStyle = '#94a3b8';
                ctx.fillText(pt.id.toString(), px + 8, py + 4);
            });
        }
    }, []);

    useEffect(() => {
        if (isPreviewOpen && previewParcel) {
            drawParcel(previewParcel, previewCanvasRef.current, viewState);
        }
    }, [isPreviewOpen, previewParcel, viewState, drawParcel]);

    useEffect(() => {
        if (isModalOpen && formData.geometry) {
            drawParcel({ geometry: formData.geometry }, editCanvasRef.current, { scale: 1, offset: { x: 0, y: 0 } });
        }
    }, [isModalOpen, formData.geometry, drawParcel]);

    const handleWheel = (e: React.WheelEvent) => {
        const zoomSpeed = 0.1;
        const delta = e.deltaY > 0 ? 1 - zoomSpeed : 1 + zoomSpeed;
        const newScale = Math.min(Math.max(viewState.scale * delta, 0.1), 20);
        setViewState(prev => ({ ...prev, scale: newScale }));
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        isDragging.current = true;
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isDragging.current) return;
        const dx = e.clientX - lastMousePos.current.x;
        const dy = e.clientY - lastMousePos.current.y;
        setViewState(prev => ({
            ...prev,
            offset: { x: prev.offset.x + dx, y: prev.offset.y + dy }
        }));
        lastMousePos.current = { x: e.clientX, y: e.clientY };
    };

    const handleMouseUp = () => { isDragging.current = false; };
    const resetView = () => setViewState({ scale: 1, offset: { x: 0, y: 0 } });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!formData.sothua || !formData.sodoto) return showDialog('error', 'Thiếu thông tin', "Vui lòng nhập đầy đủ Số tờ và Số thửa.");
        setLoading(true);
        try {
            if (editingId) {
                if (formData.file) await parcelApi.createWithUpload(layer, { ...formData, gid: editingId });
                else await parcelApi.update(layer, editingId, formData);
            } else {
                if (formData.file) await parcelApi.createWithUpload(layer, formData);
                else await parcelApi.create(layer, formData);
            }
            setIsModalOpen(false);
            showDialog('success', 'Thành công', editingId ? 'Cập nhật dữ liệu thửa đất thành công.' : 'Đã đăng ký thửa đất mới vào hệ thống.');
            handleSearchClick(); 
        } catch (err: any) { showDialog('error', 'Lỗi xử lý', err.message); } finally { setLoading(false); }
    };

    const handleDelete = async (gid: number) => {
        showDialog('confirm', 'Xác nhận xóa', `Bạn có chắc chắn muốn xóa thửa đất GID: ${gid} khỏi hệ thống? Thao tác này không thể khôi phục.`, async () => {
            setLoading(true);
            try {
                await parcelApi.delete(layer, gid);
                handleSearchClick();
                showDialog('success', 'Đã xóa', 'Xóa thửa đất thành công.');
            } catch (err: any) { showDialog('error', 'Lỗi xóa', err.message); } finally { setLoading(false); }
        });
    };

    // --- HIỂN THỊ KHI CHƯA CÓ BẢNG ---
    if (!loading && availableTables.length === 0) {
        return (
            <div className="p-10 flex flex-col items-center justify-center h-full bg-gray-900 text-center">
                <div className="bg-gray-800 p-8 rounded-full mb-6 border border-gray-700 shadow-2xl">
                    <Database size={64} className="text-gray-600" />
                </div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tight mb-2">Chưa có bảng dữ liệu nào</h2>
                <p className="text-gray-400 max-w-md mb-8">Hệ thống chưa tìm thấy bảng dữ liệu (Registry) nào để quản lý thửa đất. Vui lòng tạo mới hoặc liên kết bảng có sẵn trong Database.</p>
                <div className="flex gap-4">
                    <button onClick={loadTables} className="px-6 py-3 bg-gray-800 text-white rounded-xl hover:bg-gray-700 font-bold transition-all border border-gray-700 flex items-center gap-2">
                        <RefreshCw size={18} /> Thử lại
                    </button>
                    <a href="#" className="px-6 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-500 font-bold transition-all shadow-lg shadow-blue-900/20 flex items-center gap-2 cursor-not-allowed opacity-80" title="Vui lòng truy cập menu Admin > Lớp bản đồ & DB">
                        <Layers size={18} /> Đi tới Quản lý DB <ArrowRight size={16}/>
                    </a>
                </div>
                <p className="mt-6 text-[10px] text-gray-500 italic">Mẹo: Truy cập trang "Quản trị hệ thống" &gt; "Lớp bản đồ & DB" để khởi tạo bảng.</p>
            </div>
        );
    }

    return (
        <div className="p-6 bg-gray-950 text-white min-h-full space-y-6 font-sans flex flex-col">
            {/* TOP HEADER */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-gray-800 pb-6 gap-4">
                <div className="flex items-center gap-4">
                    <div className="bg-blue-600/20 p-3 rounded-2xl border border-blue-500/30">
                        <Database className="text-blue-500" size={28} />
                    </div>
                    <div>
                        <h2 className="text-2xl font-black tracking-tight flex items-center gap-2 uppercase">Quản trị Thửa đất</h2>
                        <div className="flex items-center gap-2 text-gray-500 text-xs mt-0.5 font-bold uppercase tracking-widest">
                            <Layers size={14} className="text-blue-400" />
                            <span>Database: {layer || 'Chưa chọn'}</span>
                        </div>
                    </div>
                </div>
                <div className="flex gap-2">
                    <button onClick={loadTables} className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 px-4 py-2.5 rounded-xl text-xs font-black transition-all border border-gray-700">
                        <RefreshCw size={16} className={loading ? "animate-spin" : ""} /> TẢI LẠI
                    </button>
                    <button onClick={openAddModal} disabled={!layer} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-500 px-5 py-2.5 rounded-xl text-xs font-black transition-all shadow-lg shadow-blue-500/20 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed">
                        <Plus size={18} /> THÊM THỬA ĐẤT
                    </button>
                </div>
            </div>

            {/* MAIN ACTION CARD */}
            <div className="bg-gray-900 rounded-3xl border border-gray-800 shadow-2xl overflow-hidden flex flex-col flex-1">
                {/* HORIZONTAL FILTER BAR */}
                <div className="p-5 bg-gray-900/50 border-b border-gray-800 grid grid-cols-1 md:grid-cols-6 gap-4 items-end">
                    <div className="space-y-1.5 md:col-span-1">
                        <label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Lớp dữ liệu</label>
                        <select value={layer} onChange={(e) => setLayer(e.target.value)} className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-blue-500 font-bold">
                            {availableTables.length > 0 ? (
                                availableTables.map(tbl => <option key={tbl.table_name} value={tbl.table_name}>{tbl.display_name || tbl.table_name}</option>)
                            ) : (
                                <option value="">(Trống)</option>
                            )}
                        </select>
                    </div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Số tờ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none font-bold text-blue-400" placeholder="Số tờ..." value={searchFilters.sodoto} onChange={e=>setSearchFilters({...searchFilters, sodoto: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Số thửa</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none font-bold text-blue-400" placeholder="Số thửa..." value={searchFilters.sothua} onChange={e=>setSearchFilters({...searchFilters, sothua: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Tên chủ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none" placeholder="Tên chủ..." value={searchFilters.tenchu} onChange={e=>setSearchFilters({...searchFilters, tenchu: e.target.value})} /></div>
                    <div className="space-y-1.5 md:col-span-1"><label className="text-[10px] font-black text-gray-500 uppercase ml-1 tracking-widest">Địa chỉ</label><input className="w-full bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-xs focus:border-blue-500 outline-none" placeholder="Địa chỉ..." value={searchFilters.diachi} onChange={e=>setSearchFilters({...searchFilters, diachi: e.target.value})} /></div>
                    <div className="md:col-span-1"><button onClick={handleSearchClick} disabled={loading || !layer} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all uppercase tracking-widest disabled:opacity-50">{loading ? <RefreshCw size={14} className="animate-spin" /> : <Filter size={14}/>} TRUY VẤN</button></div>
                </div>

                {/* TABLE SECTION */}
                <div className="overflow-auto flex-1 custom-scrollbar">
                    {error ? (
                        <div className="flex flex-col items-center justify-center h-full py-20 text-red-400 gap-4">
                            <AlertTriangle size={64} className="opacity-20" />
                            <div className="text-center">
                                <p className="text-sm font-black uppercase tracking-widest mb-1">{error}</p>
                                <p className="text-xs text-gray-500">Vui lòng kiểm tra lại kết nối Backend hoặc cấu hình Database.</p>
                            </div>
                            <button onClick={loadTables} className="px-4 py-2 bg-red-900/20 hover:bg-red-900/40 text-red-400 rounded-lg text-xs font-bold transition-all border border-red-800/50">Thử lại</button>
                        </div>
                    ) : !hasSearched ? (
                        <div className="flex flex-col items-center justify-center h-full py-40 text-gray-700">
                            <Search size={80} className="opacity-10 mb-4" />
                            <p className="text-sm font-bold uppercase tracking-[0.3em] opacity-30">Chế độ chờ tìm kiếm</p>
                        </div>
                    ) : (
                        <table className="w-full text-sm text-left border-collapse">
                            <thead className="bg-gray-950 text-gray-500 uppercase text-[10px] sticky top-0 z-10 font-black tracking-widest border-b border-gray-800">
                                <tr>
                                    <th className="p-4">Tờ/Thửa</th>
                                    <th className="p-4">Chủ sử dụng</th>
                                    <th className="p-4">Loại đất</th>
                                    <th className="p-4 text-right">Diện tích (m²)</th>
                                    <th className="p-4">Địa chỉ</th>
                                    <th className="p-4 text-center">Hành động</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-800/50">
                                {parcels.length === 0 ? (
                                    <tr>
                                        <td colSpan={6} className="p-8 text-center text-gray-500 italic">Không tìm thấy dữ liệu phù hợp</td>
                                    </tr>
                                ) : parcels.map(p => (
                                    <tr key={p.gid} className="hover:bg-blue-600/5 transition-colors group">
                                        <td className="p-4">
                                            <div className="flex flex-col">
                                                <span className="font-black text-blue-400 text-sm">{getSheetNo(p)}/{getParcelNo(p)}</span>
                                                <span className="text-[9px] text-gray-600 font-mono">GID: {p.gid}</span>
                                            </div>
                                        </td>
                                        <td className="p-4 font-bold text-gray-200">{getOwner(p)}</td>
                                        <td className="p-4">
                                            <span className="bg-gray-800 text-gray-400 text-[10px] px-2 py-1 rounded-lg font-black border border-gray-700">
                                                {getLandType(p)}
                                            </span>
                                        </td>
                                        <td className="p-4 text-right font-mono text-emerald-500 font-black">
                                            {getAreaVal(p) ? Math.round(getAreaVal(p)).toLocaleString() : '--'}
                                        </td>
                                        <td className="p-4 text-xs text-gray-500 max-w-xs truncate">{getAddressVal(p)}</td>
                                        <td className="p-4">
                                            <div className="flex justify-center gap-2">
                                                <button onClick={() => handleQuickView(p)} className="p-2 bg-emerald-500/10 text-emerald-400 hover:bg-emerald-600 hover:text-white rounded-xl transition-all" title="Xem nhanh sơ đồ"><Eye size={16}/></button>
                                                <button onClick={() => handleDownloadParcel(p)} className="p-2 bg-indigo-500/10 text-indigo-400 hover:bg-indigo-600 hover:text-white rounded-xl transition-all" title="Tải xuống dữ liệu GeoJSON"><FileDown size={16}/></button>
                                                <button onClick={() => handleEdit(p)} className="p-2 bg-blue-500/10 text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all"><Edit size={16}/></button>
                                                <button onClick={() => handleDelete(p.gid!)} className="p-2 bg-red-500/10 text-red-400 hover:bg-red-600 hover:text-white rounded-xl transition-all"><Trash2 size={16}/></button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    )}
                </div>
            </div>

            {/* --- SYSTEM MODAL DIALOG (THAY THẾ ALERT/CONFIRM) --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2.5rem] w-full max-w-md border border-gray-800 shadow-2xl overflow-hidden relative">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-16 h-16 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={32}/></div>}
                            {dialog.type === 'error' && <div className="w-16 h-16 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={32}/></div>}
                            {dialog.type === 'confirm' && <div className="w-16 h-16 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={32}/></div>}
                            {dialog.type === 'alert' && <div className="w-16 h-16 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={32}/></div>}

                            <h3 className="text-xl font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-sm leading-relaxed mb-8">{dialog.message}</p>

                            <div className="flex gap-3 w-full">
                                {dialog.type === 'confirm' ? (
                                    <>
                                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3.5 bg-gray-800 hover:bg-gray-700 text-gray-400 rounded-2xl font-black text-xs uppercase tracking-widest transition-all">HỦY BỎ</button>
                                        <button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3.5 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-red-900/20 transition-all">ĐỒNG Ý</button>
                                    </>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3.5 bg-blue-600 hover:bg-blue-500 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all">ĐÓNG</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MODAL XEM TRƯỚC SƠ ĐỒ (QUICK VIEW) --- */}
            {isPreviewOpen && previewParcel && (
                <div className="fixed inset-0 z-[1100] bg-black/95 backdrop-blur-xl flex items-center justify-center p-4 animate-in fade-in zoom-in duration-300">
                    <div className="bg-gray-900 border border-gray-800 rounded-[2.5rem] w-full max-w-3xl shadow-[0_0_100px_rgba(59,130,246,0.2)] overflow-hidden relative">
                        <button onClick={() => setIsPreviewOpen(false)} className="absolute top-6 right-6 z-20 bg-gray-800/80 hover:bg-red-600 text-white p-3 rounded-full transition-all active:scale-90 shadow-lg"><X size={24}/></button>
                        <div className="flex flex-col md:flex-row h-full">
                            <div className="flex-1 bg-gray-950 p-6 relative group">
                                <div className="absolute top-8 left-8 z-10 pointer-events-none">
                                    <div className="flex items-center gap-3 text-emerald-400 font-black text-[10px] uppercase tracking-[0.3em] mb-1">
                                        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div> Sơ đồ tương tác
                                    </div>
                                    <h3 className="text-2xl font-black text-white tracking-tighter">THỬA {getParcelNo(previewParcel)} - TỜ {getSheetNo(previewParcel)}</h3>
                                    <p className="text-[9px] text-gray-500 font-bold uppercase mt-1 italic">Dùng chuột để Zoom & Di chuyển</p>
                                </div>
                                <div className="absolute bottom-8 left-8 flex flex-col gap-2 z-10 opacity-60 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => setViewState(p => ({ ...p, scale: Math.min(p.scale * 1.2, 20) }))} className="p-3 bg-gray-800 hover:bg-blue-600 rounded-xl text-white shadow-xl transition-all"><ZoomIn size={20}/></button>
                                    <button onClick={() => setViewState(p => ({ ...p, scale: Math.max(p.scale / 1.2, 0.1) }))} className="p-3 bg-gray-800 hover:bg-blue-600 rounded-xl text-white shadow-xl transition-all"><ZoomOut size={20}/></button>
                                    <button onClick={resetView} className="p-3 bg-gray-800 hover:bg-orange-600 rounded-xl text-white shadow-xl transition-all" title="Reset View"><RotateCcw size={20}/></button>
                                </div>
                                <div className="flex items-center justify-center h-[500px] cursor-move overflow-hidden">
                                    <canvas ref={previewCanvasRef} width={600} height={500} className="w-full h-full" onWheel={handleWheel} onMouseDown={handleMouseDown} onMouseMove={handleMouseMove} onMouseUp={handleMouseUp} onMouseLeave={handleMouseUp} />
                                </div>
                            </div>
                            <div className="w-full md:w-64 bg-gray-900 border-l border-gray-800 p-8 flex flex-col justify-center gap-6">
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Mục đích SD</p><p className="text-xl font-black text-blue-400">{getLandType(previewParcel)}</p></div>
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Diện tích</p><p className="text-2xl font-black text-emerald-500">{Math.round(getAreaVal(previewParcel)).toLocaleString()} m²</p></div>
                                <div><p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-1">Chủ sở hữu</p><p className="text-sm font-bold text-gray-200">{getOwner(previewParcel)}</p></div>
                                <div className="flex flex-col gap-2">
                                    <button onClick={() => handleDownloadParcel(previewParcel)} className="w-full bg-indigo-600 text-white py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-indigo-500 transition-all flex items-center justify-center gap-2">
                                        <FileDown size={14}/> Tải dữ liệu
                                    </button>
                                    <button onClick={() => setIsPreviewOpen(false)} className="w-full bg-white text-black py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-blue-400 hover:text-white transition-all">Đóng xem</button>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* --- MODAL FORM (THÊM/SỬA) --- */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-300">
                    <div className="bg-gray-900 border border-gray-800 rounded-3xl w-full max-w-4xl shadow-2xl overflow-hidden flex flex-col md:flex-row">
                        <div className="flex-1 p-8 overflow-y-auto max-h-[85vh]">
                            <div className="flex justify-between items-center mb-8 border-b border-gray-800 pb-4">
                                <div className="flex items-center gap-3">
                                    <div className={`p-2 rounded-xl ${editingId ? 'bg-orange-500/20 text-orange-500' : 'bg-blue-500/20 text-blue-500'}`}>
                                        {editingId ? <Edit size={24} /> : <Plus size={24} />}
                                    </div>
                                    <h3 className="text-lg font-black uppercase tracking-tighter">{editingId ? "Cập nhật dữ liệu thửa" : "Đăng ký thửa đất mới"}</h3>
                                </div>
                                <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={24}/></button>
                            </div>
                            <form onSubmit={handleSubmit} className="space-y-5">
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Số tờ bản đồ *</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.sodoto} onChange={e=>setFormData({...formData, sodoto: e.target.value})} required /></div>
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Số thứ tự thửa *</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.sothua} onChange={e=>setFormData({...formData, sothua: e.target.value})} required /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Chủ sở hữu</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-bold" value={formData.tenchu||''} onChange={e=>setFormData({...formData, tenchu: e.target.value})} /></div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Mục đích (Loại đất)</label><input className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-black uppercase" value={formData.loaidat||''} onChange={e=>setFormData({...formData, loaidat: e.target.value.toUpperCase()})} /></div>
                                    <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Diện tích (m²)</label><input type="number" className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none font-mono font-bold text-emerald-500" value={formData.dientich||''} onChange={e=>setFormData({...formData, dientich: parseFloat(e.target.value)})} /></div>
                                </div>
                                <div className="space-y-1.5"><label className="text-[10px] font-black text-gray-500 uppercase tracking-widest">Địa chỉ chi tiết</label><textarea className="w-full bg-gray-950 border border-gray-700 rounded-xl p-2.5 text-sm focus:border-blue-500 outline-none h-20 resize-none" value={formData.diachi||''} onChange={e=>setFormData({...formData, diachi: e.target.value})} /></div>
                                <div className="pt-4 flex gap-3">
                                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 bg-gray-800 hover:bg-gray-700 text-gray-400 py-3 rounded-xl font-black uppercase text-[10px] tracking-widest">HỦY</button>
                                    <button type="submit" disabled={loading} className="flex-[2] bg-blue-600 hover:bg-blue-500 text-white py-3 rounded-xl font-black uppercase text-[10px] tracking-widest flex justify-center items-center gap-2">{loading ? <RefreshCw className="animate-spin" size={16}/> : <Save size={16}/>} LƯU DỮ LIỆU</button>
                                </div>
                            </form>
                        </div>
                        <div className="hidden md:flex w-[350px] bg-gray-950 border-l border-gray-800 p-8 flex-col">
                            <h4 className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-6">Trực quan hóa thửa đất</h4>
                            <div className="flex-1 bg-gray-900 rounded-2xl border border-gray-800 relative flex items-center justify-center overflow-hidden">
                                {formData.geometry ? <canvas ref={editCanvasRef} width={300} height={300} className="w-full h-full" /> : <div className="text-center p-6 flex flex-col items-center gap-3"><MapPin className="text-gray-800" size={48} /><p className="text-[10px] text-gray-700 font-bold uppercase italic">Chưa có dữ liệu hình học</p></div>}
                            </div>
                            <div className="mt-6 p-4 bg-gray-900 rounded-2xl border border-gray-800">
                                <div onClick={() => fileInputRef.current?.click()} className="cursor-pointer group flex flex-col items-center gap-2">
                                    <FileUp className="text-gray-500 group-hover:text-blue-500 transition-colors" size={24} />
                                    <p className="text-[9px] text-gray-500 font-bold uppercase text-center">{formData.file ? formData.file.name : "Tải lên Shapefile / GeoJSON để cập nhật hình học"}</p>
                                    <input type="file" ref={fileInputRef} className="hidden" accept=".zip,.geojson,.json" onChange={e => setFormData({ ...formData, file: e.target.files?.[0] || null })} />
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ParcelManager;

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { User, UserRole, Branch } from '../../types';
import { Users, Plus, Edit2, Trash2, X, Save, Loader2, Key, Check, AlertTriangle, CheckCircle2, Info } from 'lucide-react';

const UserManager: React.FC = () => {
    const [users, setUsers] = useState<User[]>([]);
    const [branches, setBranches] = useState<Branch[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isResetModalOpen, setIsResetModalOpen] = useState(false);
    const [formData, setFormData] = useState<any>({});
    const [resetData, setResetData] = useState({ userId: '', userName: '', newPassword: '' });
    const [editingId, setEditingId] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try {
            const [usersData, branchesData] = await Promise.all([
                adminService.getUsers(),
                adminService.getBranches()
            ]);
            setUsers(usersData);
            setBranches(branchesData);
        } catch (e) { console.error("Load users error:", e); }
    };

    const handleSave = async () => {
        if (!formData.name || !formData.email) {
            showDialog('error', 'Thiếu dữ liệu', "Vui lòng nhập đầy đủ Họ tên và Email");
            return;
        }
        if (!editingId && !formData.password) {
            showDialog('error', 'Thiếu dữ liệu', "Vui lòng nhập mật khẩu cho người dùng mới");
            return;
        }

        setLoading(true);
        try {
            if (editingId) {
                await adminService.updateUser({...formData, id: editingId});
            } else {
                await adminService.addUser(formData);
            }
            setIsModalOpen(false);
            await loadData();
            showDialog('success', 'Thành công', editingId ? 'Đã cập nhật thông tin người dùng.' : 'Đã khởi tạo tài khoản mới.');
        } catch(e: any) { 
            showDialog('error', 'Lỗi hệ thống', e.message); 
        } finally {
            setLoading(false);
        }
    };

    const handleResetPassword = async () => {
        if (!resetData.newPassword) return showDialog('error', 'Thiếu mật khẩu', "Vui lòng nhập mật khẩu mới");
        setLoading(true);
        try {
            await adminService.resetPassword(resetData.userId, resetData.newPassword);
            showDialog('success', 'Đã đặt lại', `Đã đặt lại mật khẩu thành công cho ${resetData.userName}`);
            setIsResetModalOpen(false);
        } catch (e: any) {
            showDialog('error', 'Lỗi', e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        showDialog('confirm', 'Xác nhận xóa', "Bạn có chắc chắn muốn xóa vĩnh viễn người dùng này khỏi hệ thống?", async () => {
            try {
                await adminService.deleteUser(id);
                await loadData();
                showDialog('success', 'Đã xóa', 'Người dùng đã được gỡ bỏ.');
            } catch (e: any) { showDialog('error', 'Lỗi', e.message); }
        });
    };

    const openAddModal = () => {
        setEditingId(null);
        setFormData({
            role: UserRole.VIEWER,
            branchId: branches.length > 0 ? branches[0].id : 'HEAD_OFFICE',
            password: '123'
        });
        setIsModalOpen(true);
    };

    const openEditModal = (u: User) => {
        setEditingId(u.id);
        setFormData({ ...u });
        setIsModalOpen(true);
    };

    const openResetModal = (u: User) => {
        setResetData({ userId: u.id, userName: u.name, newPassword: '' });
        setIsResetModalOpen(true);
    };

    return (
        <div className="p-8">
            <div className="bg-gray-800 rounded-lg border border-gray-700 shadow-xl overflow-hidden">
                <div className="p-4 flex justify-between border-b border-gray-700 bg-gray-800/50">
                    <span className="font-semibold text-gray-300 flex items-center gap-2"><Users size={18} className="text-blue-400"/> Danh sách Người dùng</span>
                    <button onClick={openAddModal} className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-1.5 rounded text-sm font-bold shadow-lg transition-all flex items-center gap-2">
                        <Plus size={16}/> Thêm mới
                    </button>
                </div>
                <table className="w-full text-sm text-left text-gray-300">
                    <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-wider">
                        <tr>
                            <th className="p-4">Tên</th>
                            <th className="p-4">Email</th>
                            <th className="p-4">Quyền</th>
                            <th className="p-4">Chi nhánh</th>
                            <th className="p-4 text-right">Hành động</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-700">
                        {users.length === 0 ? (
                            <tr><td colSpan={5} className="p-8 text-center text-gray-500 italic">Đang tải danh sách người dùng...</td></tr>
                        ) : users.map(u => (
                            <tr key={u.id} className="hover:bg-gray-700/50 transition-colors group">
                                <td className="p-4 font-medium text-white">{u.name}</td>
                                <td className="p-4 text-gray-400">{u.email}</td>
                                <td className="p-4">
                                    <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${u.role === UserRole.ADMIN ? 'bg-red-900/40 text-red-300 border border-red-800' : 'bg-blue-900/40 text-blue-300 border border-blue-800'}`}>
                                        {u.role}
                                    </span>
                                </td>
                                <td className="p-4 text-gray-400 text-xs">
                                    {branches.find(b => b.id === u.branchId)?.name || u.branchId}
                                </td>
                                <td className="p-4 flex justify-end gap-2">
                                    <button onClick={() => openResetModal(u)} title="Đặt lại mật khẩu" className="p-1.5 text-orange-400 hover:bg-orange-400/10 rounded transition-colors"><Key size={16}/></button>
                                    <button onClick={() => openEditModal(u)} className="p-1.5 text-blue-400 hover:bg-blue-400/10 rounded transition-colors"><Edit2 size={16}/></button>
                                    <button onClick={() => handleDelete(u.id)} className="p-1.5 text-red-400 hover:bg-red-400/10 rounded transition-colors"><Trash2 size={16}/></button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'confirm' && <div className="w-14 h-14 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <div className="flex gap-2 w-full">
                                {dialog.type === 'confirm' ? (
                                    <>
                                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3 bg-gray-800 hover:bg-gray-700 text-gray-400 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">HỦY BỎ</button>
                                        <button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-red-900/20 transition-all">XÁC NHẬN</button>
                                    </>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all">OK</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* Modal Thêm/Sửa */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[500] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
                    <div className="bg-gray-800 rounded-xl w-full max-w-md p-6 border border-gray-700 shadow-2xl">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-2">
                            <h3 className="text-xl font-bold text-white flex items-center gap-2">
                                {editingId ? <Edit2 size={20} className="text-blue-400"/> : <Plus size={20} className="text-green-400"/>}
                                {editingId ? "Cập nhật Người dùng" : "Thêm Người dùng mới"}
                            </h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white"><X size={20}/></button>
                        </div>
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs text-gray-400 font-bold uppercase mb-1 block">Họ tên <span className="text-red-500">*</span></label>
                                <input className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} placeholder="VD: Nguyễn Văn A" />
                            </div>
                            <div>
                                <label className="text-xs text-gray-400 font-bold uppercase mb-1 block">Email <span className="text-red-500">*</span></label>
                                <input className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none" value={formData.email || ''} onChange={e => setFormData({...formData, email: e.target.value})} placeholder="email@example.com" />
                            </div>
                            {!editingId && (
                                <div>
                                    <label className="text-xs text-gray-400 font-bold uppercase mb-1 block">Mật khẩu ban đầu <span className="text-red-500">*</span></label>
                                    <input type="password" placeholder="Mặc định: 123" className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none" value={formData.password || ''} onChange={e => setFormData({...formData, password: e.target.value})} />
                                </div>
                            )}
                            <div>
                                <label className="text-xs text-gray-400 font-bold uppercase mb-1 block">Vai trò hệ thống</label>
                                <select className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none cursor-pointer" value={formData.role} onChange={e => setFormData({...formData, role: e.target.value})}>
                                    <option value={UserRole.ADMIN}>ADMIN (Toàn quyền)</option>
                                    <option value={UserRole.EDITOR}>EDITOR (Biên tập dữ liệu)</option>
                                    <option value={UserRole.VIEWER}>VIEWER (Chỉ xem)</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-xs text-gray-400 font-bold uppercase mb-1 block">Chi nhánh công tác</label>
                                <select className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none cursor-pointer" value={formData.branchId || ''} onChange={e => setFormData({...formData, branchId: e.target.value})}>
                                    <option value="">-- Chọn chi nhánh --</option>
                                    {branches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                        </div>
                        <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-gray-700">
                            <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-400 hover:text-white font-medium">Hủy bỏ</button>
                            <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2 rounded font-bold shadow-lg flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50">
                                {loading ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>}
                                {editingId ? "Lưu thay đổi" : "Tạo tài khoản"}
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Modal Đặt lại mật khẩu */}
            {isResetModalOpen && (
                <div className="fixed inset-0 z-[600] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-gray-800 rounded-2xl w-full max-w-sm p-6 border border-orange-500/30 shadow-[0_0_50px_rgba(249,115,22,0.1)]">
                        <div className="flex justify-between items-center mb-6 border-b border-gray-700 pb-3">
                            <div>
                                <h3 className="text-lg font-black text-white uppercase tracking-tighter flex items-center gap-2">
                                    <Key size={20} className="text-orange-500"/> Đặt lại mật khẩu
                                </h3>
                                <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mt-1">Người dùng: {resetData.userName}</p>
                            </div>
                            <button onClick={() => setIsResetModalOpen(false)} className="text-gray-500 hover:text-white"><X size={24}/></button>
                        </div>
                        <div className="space-y-4">
                            <div>
                                <label className="text-[10px] text-gray-400 font-black uppercase mb-1.5 block tracking-widest">Mật khẩu mới</label>
                                <input 
                                    type="text" 
                                    className="w-full bg-gray-900 border border-gray-700 rounded-xl p-3 text-white focus:border-orange-500 outline-none font-mono text-lg tracking-widest" 
                                    value={resetData.newPassword} 
                                    onChange={e => setResetData({...resetData, newPassword: e.target.value})} 
                                    placeholder="Nhập mật khẩu mới..." 
                                    autoFocus
                                />
                                <p className="text-[9px] text-gray-500 italic mt-2">* Mật khẩu sẽ được cập nhật trực tiếp vào cơ sở dữ liệu.</p>
                            </div>
                        </div>
                        <div className="flex gap-3 mt-8">
                            <button onClick={() => setIsResetModalOpen(false)} className="flex-1 py-3 text-gray-500 hover:text-white font-black text-[10px] uppercase tracking-widest transition-colors">HỦY BỎ</button>
                            <button 
                                onClick={handleResetPassword} 
                                disabled={loading} 
                                className="flex-[2] bg-orange-600 hover:bg-orange-500 text-white py-3 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-orange-900/20 flex items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50"
                            >
                                {loading ? <Loader2 className="animate-spin" size={14}/> : <Check size={14}/>} XÁC NHẬN ĐỔI
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default UserManager;

import React, { useState, useEffect, useRef } from 'react';
import { adminService } from '../../services/mockBackend';
import { SystemSetting } from '../../types';
import { Settings, Save, FileText, DatabaseBackup, Download, UploadCloud, RefreshCw, AlertTriangle, Image as ImageIcon, Trash2, Map as MapIcon, Shield, CheckCircle2, X, Info } from 'lucide-react';

const SystemSettingsManager: React.FC = () => {
    const [settings, setSettings] = useState<SystemSetting[]>([]);
    const [subTab, setSubTab] = useState<'GENERAL' | 'PDF' | 'MAP' | 'BACKUP'>('GENERAL');
    const [loading, setLoading] = useState(false);
    const [serverInfo, setServerInfo] = useState<any>(null);
    const backupInputRef = useRef<HTMLInputElement>(null);

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'success' | 'error';
        title: string;
        message: string;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string) => {
        setDialog({ isOpen: true, type, title, message });
    };

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [data, info] = await Promise.all([
                adminService.getSettings(),
                adminService.getServerInfo().catch(() => null)
            ]);
            setSettings(data);
            setServerInfo(info);
        } catch (e) { 
            console.error(e); 
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        setLoading(true);
        try {
            await adminService.saveSettings(settings);
            showDialog('success', 'Đã lưu', "Hệ thống đã ghi nhận các thay đổi cấu hình mới.");
        } catch (e: any) {
            showDialog('error', 'Lỗi lưu trữ', e.message);
        } finally { setLoading(false); }
    };

    const handleFileChange = (key: string, e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            showDialog('error', 'File quá lớn', "Vui lòng chọn ảnh dưới 2MB để đảm bảo hiệu năng tải trang.");
            return;
        }

        const reader = new FileReader();
        reader.onloadend = () => {
            const base64 = reader.result as string;
            setSettings(prev => prev.map(s => s.key === key ? { ...s, value: base64 } : s));
        };
        reader.readAsDataURL(file);
    };

    const renderSettingInput = (setting: SystemSetting) => {
        if (setting.type === 'image' || ['site_logo', 'site_favicon'].includes(setting.key)) {
            const isFavicon = setting.key === 'site_favicon';
            return (
                <div className="space-y-3">
                    {setting.value && (
                        <div className={`relative ${isFavicon ? 'w-16 h-16' : 'w-32 h-32'} bg-gray-900 rounded border border-gray-700 overflow-hidden group`}>
                            <img src={setting.value} alt={setting.key} className="w-full h-full object-contain p-1" />
                            <button 
                                onClick={() => setSettings(prev => prev.map(s => s.key === setting.key ? {...s, value: ''} : s))}
                                className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                            >
                                <Trash2 className="text-red-400" size={isFavicon ? 14 : 20} />
                            </button>
                        </div>
                    )}
                    <label className="flex items-center gap-2 px-4 py-2 bg-gray-700 hover:bg-gray-600 rounded cursor-pointer w-fit text-sm transition-colors border border-gray-600">
                        <ImageIcon size={16} />
                        <span>{setting.value ? "Thay đổi" : "Tải lên"}</span>
                        <input type="file" accept="image/*" className="hidden" onChange={e => handleFileChange(setting.key, e)} />
                    </label>
                </div>
            );
        }

        if (setting.type === 'boolean') {
            const isTrue = setting.value === 'true';
            return (
                <div className="flex items-center gap-3">
                    <button 
                        onClick={() => setSettings(prev => prev.map(s => s.key === setting.key ? {...s, value: isTrue ? 'false' : 'true'} : s))}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${isTrue ? 'bg-blue-600' : 'bg-gray-700'}`}
                    >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${isTrue ? 'translate-x-6' : 'translate-x-1'}`} />
                    </button>
                    <span className="text-sm text-gray-400 font-bold uppercase tracking-widest">{isTrue ? "ĐANG BẬT" : "ĐANG TẮT"}</span>
                </div>
            );
        }

        return (
            <input 
                className="w-full bg-gray-900 border border-gray-600 rounded p-2.5 text-white focus:border-blue-500 outline-none font-medium" 
                value={setting.value} 
                type={setting.type === 'number' ? 'number' : 'text'}
                step={setting.type === 'number' ? 'any' : undefined}
                onChange={e => setSettings(prev => prev.map(item => item.key === setting.key ? {...item, value: e.target.value} : item))}
            />
        );
    };

    return (
        <div className="p-8 max-w-5xl mx-auto space-y-6 text-white relative">
            <div className="flex gap-2 border-b border-gray-700 pb-2 overflow-x-auto no-scrollbar">
                <button onClick={() => setSubTab('GENERAL')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'GENERAL' ? 'text-blue-400 border-blue-400' : 'text-gray-500 border-transparent'}`}><Settings size={16}/> Web & Bảo mật</button>
                <button onClick={() => setSubTab('MAP')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'MAP' ? 'text-cyan-400 border-cyan-400' : 'text-gray-500 border-transparent'}`}><MapIcon size={16}/> Bản đồ</button>
                <button onClick={() => setSubTab('PDF')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'PDF' ? 'text-orange-400 border-orange-400' : 'text-gray-500 border-transparent'}`}><FileText size={16}/> Mẫu trích lục</button>
                <button onClick={() => setSubTab('BACKUP')} className={`px-4 py-2 text-sm font-bold whitespace-nowrap border-b-2 transition-all flex items-center gap-2 ${subTab === 'BACKUP' ? 'text-green-400 border-green-400' : 'text-gray-500 border-transparent'}`}><DatabaseBackup size={16}/> Hệ thống</button>
            </div>

            <div className="bg-gray-800 rounded-lg p-6 border border-gray-700 shadow-xl min-h-[400px]">
                {subTab === 'GENERAL' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        {settings.filter(s => ['system_name', 'site_logo', 'site_favicon', 'maintenance_mode', 'allow_registration'].includes(s.key)).map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label || s.key.replace(/_/g, ' ').toUpperCase()}</label>
                                    <span className="text-xs text-gray-500 italic">{s.description}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'MAP' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        <div className="p-4 bg-blue-900/10 border border-blue-800/30 rounded flex gap-3 items-center mb-4">
                            <MapIcon className="text-blue-400" size={24}/>
                            <p className="text-xs text-blue-300 italic">Thiết lập tọa độ trung tâm và mức zoom khi người dùng vừa truy cập bản đồ.</p>
                        </div>
                        {settings.filter(s => s.key.startsWith('map_') || s.key === 'default_zoom').map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label}</label>
                                    <span className="text-[10px] text-gray-500 font-mono">{s.key}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'PDF' && (
                    <div className="space-y-6 animate-in fade-in duration-300">
                        {settings.filter(s => s.key.startsWith('pdf_') || s.key === 'footer_text').map(s => (
                            <div key={s.key} className="grid grid-cols-1 md:grid-cols-3 gap-4 border-b border-gray-700/50 pb-6 last:border-0 last:pb-0">
                                <div className="col-span-1">
                                    <label className="text-sm font-bold text-gray-200 block mb-1">{s.label || s.description}</label>
                                    <span className="text-xs text-gray-500 italic">{s.description}</span>
                                </div>
                                <div className="col-span-2">
                                    {renderSettingInput(s)}
                                </div>
                            </div>
                        ))}
                    </div>
                )}

                {subTab === 'BACKUP' && (
                    <div className="space-y-8 animate-in fade-in duration-300">
                        <div className="bg-gray-900/50 p-4 rounded border border-gray-700">
                            <h4 className="text-xs font-bold text-gray-500 uppercase mb-4 tracking-wider flex items-center gap-2">
                                <Shield size={14}/> Sức khỏe Máy chủ
                            </h4>
                            {serverInfo ? (
                                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-xs">
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">Hệ điều hành</span>
                                        <span className="font-bold text-blue-400">{serverInfo.osType}</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">Thời gian chạy</span>
                                        <span className="font-bold text-green-400">{Math.floor(serverInfo.uptime / 3600)} giờ</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">RAM Trống</span>
                                        <span className="font-bold text-yellow-400">{(serverInfo.freeMem / 1024 / 1024 / 1024).toFixed(2)} GB</span>
                                    </div>
                                    <div className="p-3 bg-gray-800 rounded border border-gray-700">
                                        <span className="text-gray-500 block mb-1">CPU Load</span>
                                        <span className="font-bold text-purple-400">{serverInfo.cpuUsage}%</span>
                                    </div>
                                </div>
                            ) : <p className="text-gray-500 italic">Đang tải thông tin máy chủ...</p>}
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                            <div className="p-6 bg-blue-900/10 border border-blue-800/50 rounded-xl flex flex-col gap-4">
                                <div className="flex items-center gap-3 text-blue-400">
                                    <DatabaseBackup size={24}/>
                                    <h4 className="font-bold">Sao lưu Cơ sở dữ liệu</h4>
                                </div>
                                <button onClick={() => { setLoading(true); adminService.createBackup().finally(()=>setLoading(false)); }} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white py-2.5 rounded font-bold text-sm flex items-center justify-center gap-2">
                                    {loading ? <RefreshCw className="animate-spin" size={16}/> : <Download size={16}/>} Tải về bản Sao lưu (.sql)
                                </button>
                            </div>
                            <div className="p-6 bg-orange-900/10 border border-orange-800/50 rounded-xl flex flex-col gap-4">
                                <div className="flex items-center gap-3 text-orange-400">
                                    <UploadCloud size={24}/>
                                    <h4 className="font-bold">Phục hồi Dữ liệu</h4>
                                </div>
                                <input type="file" accept=".sql" className="hidden" ref={backupInputRef} onChange={e => { const file = e.target.files?.[0]; if(file) { setLoading(true); adminService.restoreDatabase(file).then(()=>showDialog('success', 'Phục hồi', 'Hệ thống đã nạp lại dữ liệu thành công.')).catch(err=>showDialog('error', 'Lỗi phục hồi', err.message)).finally(()=>setLoading(false)); }}} />
                                <button onClick={() => backupInputRef.current?.click()} disabled={loading} className="bg-orange-600 hover:bg-orange-500 text-white py-2.5 rounded font-bold text-sm flex items-center justify-center gap-2">
                                    {loading ? <RefreshCw className="animate-spin" size={16}/> : <ImageIcon size={16}/>} Chọn file phục hồi
                                </button>
                            </div>
                        </div>
                    </div>
                )}

                <div className="mt-8 flex justify-end gap-3 pt-6 border-t border-gray-700">
                    <button onClick={loadData} className="px-4 py-2 text-gray-400 hover:text-white font-medium">Làm mới</button>
                    <button onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-2 rounded font-bold shadow-lg flex items-center gap-2">
                        {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>} Lưu cấu hình
                    </button>
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default SystemSettingsManager;

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { MenuItem, UserRole } from '../../types';
import { LayoutList, Plus, Edit2, Trash2, X, Save, Info, Search, Link as LinkIcon, Globe, Monitor, Hash, Check, Loader2, AlertTriangle, CheckCircle2 } from 'lucide-react';
import * as Icons from 'lucide-react';

const MenuManager: React.FC = () => {
    const [menuItems, setMenuItems] = useState<MenuItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [formData, setFormData] = useState<any>({});
    const [isEditMode, setIsEditMode] = useState(false);
    const [iconSearch, setIconSearch] = useState('');

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => { loadMenu(); }, []);

    const loadMenu = async () => {
        setLoading(true);
        try {
            if (adminService && typeof adminService.getMenuItems === 'function') {
                const data = await adminService.getMenuItems();
                setMenuItems(data.sort((a, b) => a.order_index - b.order_index));
            }
        } catch (e) { console.error(e); } finally { setLoading(false); }
    };

    const handleLabelChange = (val: string) => {
        const updates: any = { label: val };
        if (!isEditMode && formData.type === 'EXTERNAL' && !formData.id) {
            updates.id = 'ext_' + val.toLowerCase().trim()
                .normalize("NFD").replace(/[\u0300-\u036f]/g, "") 
                .replace(/[^a-z0-9]/g, '_');
        }
        setFormData({ ...formData, ...updates });
    };

    const handleSave = async () => {
        if (!formData.id || !formData.label || !formData.icon) {
            return showDialog('error', 'Lỗi nhập liệu', "Vui lòng nhập đầy đủ thông tin bắt buộc (Nhãn, Mã trang, Icon).");
        }
        if (formData.type === 'EXTERNAL' && !formData.url) {
            return showDialog('error', 'Lỗi nhập liệu', "Vui lòng cung cấp địa chỉ URL hợp lệ cho liên kết ngoài.");
        }
        setLoading(true);
        try {
            if (isEditMode) await adminService.updateMenuItem(formData);
            else await adminService.addMenuItem({ ...formData, is_active: true });
            setIsModalOpen(false);
            await loadMenu();
            showDialog('success', 'Thành công', 'Đã lưu thay đổi vào cấu hình Sidebar.');
        } catch (e: any) { showDialog('error', 'Lỗi hệ thống', e.message); } finally { setLoading(false); }
    };

    const handleDelete = async (id: string) => {
        showDialog('confirm', 'Xác nhận xóa', "Thao tác này sẽ gỡ bỏ mục menu khỏi Sidebar của toàn bộ người dùng. Bạn vẫn muốn tiếp tục?", async () => {
            try {
                await adminService.deleteMenuItem(id);
                await loadMenu();
                showDialog('success', 'Đã xóa', 'Mục menu đã được loại bỏ.');
            } catch (e: any) { showDialog('error', 'Lỗi', e.message); }
        });
    };

    const openModal = (item?: MenuItem) => {
        setIsEditMode(!!item);
        setFormData(item ? { ...item } : { 
            id: '', 
            label: '', 
            icon: 'LayoutDashboard', 
            roles: ['GUEST', 'ADMIN', 'EDITOR', 'VIEWER'], 
            is_active: true,
            type: 'INTERNAL',
            url: '',
            order_index: menuItems.length
        });
        setIconSearch('');
        setIsModalOpen(true);
    };

    const toggleRole = (role: string) => {
        const currentRoles = formData.roles || [];
        if (currentRoles.includes(role)) {
            setFormData({ ...formData, roles: currentRoles.filter((r: string) => r !== role) });
        } else {
            setFormData({ ...formData, roles: [...currentRoles, role] });
        }
    };

    const availableIcons = Object.keys(Icons).filter(name => {
        const item = (Icons as any)[name];
        const matchesSearch = name.toLowerCase().includes(iconSearch.toLowerCase());
        const isNotInternal = !['createLucideIcon', 'LucideProps', 'default', 'icons'].includes(name);
        const isComponent = typeof item === 'function' || (typeof item === 'object' && item !== null);
        return matchesSearch && isNotInternal && isComponent;
    }).slice(0, 30);

    return (
        <div className="p-8 max-w-6xl mx-auto space-y-6">
            {/* Header & Button */}
            <div className="flex justify-between items-center">
                <div className="flex items-center gap-3">
                    <div className="bg-blue-600/20 p-3 rounded-2xl border border-blue-500/30">
                        <LayoutList size={24} className="text-blue-400"/>
                    </div>
                    <div>
                        <h2 className="text-2xl font-black uppercase tracking-tight text-white">Quản lý Sidebar</h2>
                        <p className="text-xs text-gray-500 font-bold uppercase tracking-widest">Tùy biến thanh điều hướng hệ thống</p>
                    </div>
                </div>
                <button onClick={() => openModal()} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-3 rounded-2xl text-xs font-black flex items-center gap-2 transition-all shadow-xl shadow-blue-900/40 active:scale-95">
                    <Plus size={18}/> THÊM MỤC MỚI
                </button>
            </div>

            {/* Main Table */}
            <div className="bg-gray-900/50 border border-gray-800 rounded-[2rem] shadow-2xl overflow-hidden backdrop-blur-xl">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-950/80 text-gray-500 uppercase text-[10px] tracking-[0.2em] font-black border-b border-gray-800">
                            <tr>
                                <th className="p-5 w-16 text-center">#</th>
                                <th className="p-5">Icon</th>
                                <th className="p-5">Nhãn hiển thị</th>
                                <th className="p-5">Loại</th>
                                <th className="p-5">Mã / URL</th>
                                <th className="p-5">Quyền xem</th>
                                <th className="p-5 text-right">Hành động</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-800 text-gray-300">
                            {menuItems.length === 0 && !loading ? (
                                <tr>
                                    <td colSpan={7} className="p-20 text-center text-gray-600 font-bold uppercase tracking-widest italic opacity-20">Chưa có mục menu nào</td>
                                </tr>
                            ) : menuItems.map((item) => {
                                const IconComponent = (Icons as any)[item.icon] || Icons.HelpCircle;
                                return (
                                    <tr key={item.id} className="hover:bg-blue-600/5 transition-colors group">
                                        <td className="p-5 text-center font-mono text-gray-600 group-hover:text-blue-400 transition-colors">{item.order_index}</td>
                                        <td className="p-5">
                                            <div className="w-10 h-10 bg-gray-800 rounded-xl flex items-center justify-center text-blue-400 group-hover:scale-110 transition-transform border border-gray-700">
                                                <IconComponent size={20}/>
                                            </div>
                                        </td>
                                        <td className="p-5">
                                            <div className="flex flex-col">
                                                <span className="font-black text-white text-base group-hover:text-blue-400 transition-colors">{item.label}</span>
                                                {!item.is_active && <span className="text-[9px] text-red-500 font-black uppercase">Đang ẩn</span>}
                                            </div>
                                        </td>
                                        <td className="p-5">
                                            {item.type === 'EXTERNAL' ? (
                                                <span className="px-2 py-1 bg-orange-950/30 text-orange-400 text-[9px] font-black rounded-lg border border-orange-800/40 uppercase tracking-tighter">Liên kết ngoài</span>
                                            ) : (
                                                <span className="px-2 py-1 bg-cyan-950/30 text-cyan-400 text-[9px] font-black rounded-lg border border-cyan-800/40 uppercase tracking-tighter">Trang nội bộ</span>
                                            )}
                                        </td>
                                        <td className="p-5 font-mono text-[10px] text-gray-500 truncate max-w-[180px]">
                                            {item.type === 'EXTERNAL' ? item.url : item.id}
                                        </td>
                                        <td className="p-5">
                                            <div className="flex flex-wrap gap-1">
                                                {item.roles.map(r => (
                                                    <span key={r} className="text-[8px] font-black px-1.5 py-0.5 rounded bg-gray-800 text-gray-400 border border-gray-700 uppercase">{r}</span>
                                                ))}
                                            </div>
                                        </td>
                                        <td className="p-5">
                                            <div className="flex justify-end gap-2">
                                                <button onClick={() => openModal(item)} className="p-2.5 bg-blue-600/10 text-blue-400 hover:bg-blue-600 hover:text-white rounded-xl transition-all shadow-lg"><Edit2 size={16}/></button>
                                                <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-red-600/10 text-red-400 hover:bg-red-600 hover:text-white rounded-xl transition-all shadow-lg"><Trash2 size={16}/></button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'confirm' && <div className="w-14 h-14 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            {dialog.type === 'alert' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <div className="flex gap-2 w-full">
                                {dialog.type === 'confirm' ? (
                                    <>
                                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3 bg-gray-800 hover:bg-gray-700 text-gray-400 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">HỦY BỎ</button>
                                        <button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-red-900/20 transition-all">XÁC NHẬN</button>
                                    </>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-900/20 transition-all">ĐÓNG</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* MODAL CẤU HÌNH */}
            {isModalOpen && (
                <div className="fixed inset-0 z-[1000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4">
                    <div className="bg-[#1a1f2e] rounded-[2.5rem] w-full max-w-md p-8 border border-gray-700 shadow-[0_20px_80px_rgba(0,0,0,0.6)] animate-in zoom-in-95 duration-300">
                        <div className="flex justify-between items-center mb-8 border-b border-gray-800 pb-4">
                            <h3 className="text-2xl font-black text-white uppercase tracking-tighter">Cấu hình Mục Menu</h3>
                            <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-white p-2 hover:bg-gray-800 rounded-full transition-all"><X size={28}/></button>
                        </div>

                        <div className="space-y-6 max-h-[70vh] overflow-y-auto pr-2 custom-scrollbar no-scrollbar">
                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-3 block tracking-[0.15em]">Loại Menu</label>
                                <div className="grid grid-cols-2 gap-2 bg-[#0d1117] p-1.5 rounded-2xl border border-gray-700/50">
                                    <button 
                                        type="button"
                                        onClick={() => setFormData({...formData, type: 'INTERNAL', id: ''})}
                                        className={`flex items-center justify-center gap-2 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${formData.type === 'INTERNAL' ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/30' : 'text-gray-500 hover:text-gray-300'}`}
                                    >
                                        <Monitor size={16}/> Trang Nội Bộ
                                    </button>
                                    <button 
                                        type="button"
                                        onClick={() => setFormData({...formData, type: 'EXTERNAL'})}
                                        className={`flex items-center justify-center gap-2 py-3 rounded-xl text-[11px] font-black uppercase transition-all ${formData.type === 'EXTERNAL' ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/30' : 'text-gray-500 hover:text-gray-300'}`}
                                    >
                                        <Globe size={16}/> Link Bên Ngoài
                                    </button>
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Nhãn hiển thị *</label>
                                <input 
                                    className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-4 text-white outline-none focus:border-blue-500 transition-all font-bold text-lg placeholder:text-gray-700" 
                                    value={formData.label || ''} 
                                    onChange={e => handleLabelChange(e.target.value)} 
                                    placeholder="Nhập tên trang..."
                                />
                            </div>

                            {formData.type === 'INTERNAL' ? (
                                <div className="grid grid-cols-4 gap-4">
                                    <div className="col-span-3">
                                        <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Mã trang (Router ID) *</label>
                                        <input className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-4 text-white font-mono text-sm outline-none focus:border-blue-500 transition-all" value={formData.id || ''} onChange={e => setFormData({...formData, id: e.target.value.toLowerCase().trim()})} placeholder="vd: map" disabled={isEditMode} />
                                    </div>
                                    <div className="col-span-1">
                                        <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Thứ tự</label>
                                        <input type="number" className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-4 text-white text-center font-black outline-none focus:border-blue-500 transition-all" value={formData.order_index || 0} onChange={e => setFormData({...formData, order_index: parseInt(e.target.value)})} />
                                    </div>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    <div>
                                        <label className="text-[10px] text-orange-400 font-black uppercase mb-2 block tracking-[0.15em]">Địa chỉ URL Link *</label>
                                        <div className="relative">
                                            <LinkIcon size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
                                            <input className="w-full bg-[#0d1117] border border-orange-900/30 rounded-2xl p-4 pl-12 text-white font-mono text-sm outline-none focus:border-orange-500 transition-all shadow-inner" value={formData.url || ''} onChange={e => setFormData({...formData, url: e.target.value})} placeholder="https://example.com" />
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Mã ID (Tự sinh)</label>
                                            <input className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-4 text-gray-500 font-mono text-xs outline-none" value={formData.id || ''} disabled />
                                        </div>
                                        <div>
                                            <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Thứ tự</label>
                                            <input type="number" className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-4 text-white text-center font-black outline-none" value={formData.order_index || 0} onChange={e => setFormData({...formData, order_index: parseInt(e.target.value)})} />
                                        </div>
                                    </div>
                                </div>
                            )}

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-2 block tracking-[0.15em]">Chọn Icon *</label>
                                <div className="space-y-3">
                                    <div className="relative">
                                        <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
                                        <input className="w-full bg-[#0d1117] border border-gray-700 rounded-2xl p-3 pl-12 text-xs text-white outline-none focus:border-blue-500 transition-all placeholder:text-gray-700" placeholder="Tìm kiếm icon (vd: map, home, chart)..." value={iconSearch} onChange={e => setIconSearch(e.target.value)} />
                                    </div>
                                    <div className="grid grid-cols-6 gap-3 p-3 bg-[#0d1117] rounded-3xl border border-gray-800 max-h-40 overflow-y-auto custom-scrollbar shadow-inner">
                                        {availableIcons.length === 0 ? (
                                            <div className="col-span-6 py-6 text-center text-gray-600 text-[10px] uppercase font-bold italic">Không thấy icon nào</div>
                                        ) : availableIcons.map(name => {
                                            const Icon = (Icons as any)[name];
                                            const isSelected = formData.icon === name;
                                            return (
                                                <button 
                                                    key={name} 
                                                    type="button"
                                                    onClick={() => setFormData({...formData, icon: name})} 
                                                    className={`p-3 rounded-2xl flex items-center justify-center transition-all ${isSelected ? 'bg-blue-600 text-white shadow-lg' : 'bg-gray-800/50 text-gray-500 hover:bg-gray-800 hover:text-gray-300'}`}
                                                    title={name}
                                                >
                                                    <Icon size={20} />
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                            </div>

                            <div>
                                <label className="text-[10px] text-gray-500 font-black uppercase mb-3 block tracking-[0.15em]">Quyền xem</label>
                                <div className="flex flex-wrap gap-2">
                                    {['GUEST', UserRole.ADMIN, UserRole.EDITOR, UserRole.VIEWER].map(role => {
                                        const isSelected = formData.roles?.includes(role);
                                        return (
                                            <button 
                                                key={role} 
                                                type="button"
                                                onClick={() => toggleRole(role)} 
                                                className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase border transition-all flex items-center gap-2 ${isSelected ? 'bg-blue-600 border-blue-600 text-white shadow-lg shadow-blue-900/20' : 'bg-[#0d1117] border-gray-700 text-gray-600 hover:border-gray-500'}`}
                                            >
                                                {isSelected && <Check size={12} />}
                                                {role}
                                            </button>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>

                        <div className="flex justify-end gap-4 mt-10 pt-6 border-t border-gray-800">
                            <button type="button" onClick={() => setIsModalOpen(false)} className="px-6 py-4 text-gray-500 hover:text-white font-black text-sm uppercase tracking-widest transition-colors">HỦY</button>
                            <button type="button" onClick={handleSave} disabled={loading} className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-4 rounded-2xl font-black text-sm shadow-[0_10px_30px_rgba(37,99,235,0.3)] flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest">
                                {loading ? <Loader2 className="animate-spin" size={18}/> : <Save size={18}/>} 
                                {isEditMode ? "Lưu thay đổi" : "Thêm mục mới"}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MenuManager;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2 } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// SỬ DỤNG THAM SỐ 3-PARAM CHO BÌNH DƯƠNG (VN2000 KTT 105.75 Múi 3) ĐỂ KHỚP VỚI WEB MERCATOR HƠN
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        if (feature.get('type') === 'accuracy') {
            return new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 })
            });
        }
        return new style.Style({
            image: new style.Circle({
                radius: 8,
                fill: new style.Fill({ color: '#3b82f6' }),
                stroke: new style.Stroke({ color: '#fff', width: 3 })
            })
        });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    // LOGIC XUẤT PDF ĐA TRANG ĐÃ ĐƯỢC SỬA LỖI CẮT BẢNG
    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }

            try {
                const canvas = await html2canvas(element, { 
                    scale: 2.5, // Tăng chất lượng ảnh
                    useCORS: true, 
                    logging: false, 
                    backgroundColor: '#ffffff' 
                });

                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = pdf.internal.pageSize.getHeight();

                const imgWidth = pdfWidth;
                const imgHeight = (canvas.height * pdfWidth) / canvas.width;

                let heightLeft = imgHeight;
                let position = 0;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);

                // Trang đầu tiên
                pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                heightLeft -= pdfHeight;

                // Xử lý các trang tiếp theo nếu nội dung quá dài (ví dụ bảng tọa độ nhiều điểm)
                while (heightLeft > 0) {
                    position -= pdfHeight; // Dịch chuyển "camera" xuống đúng 1 trang A4
                    pdf.addPage();
                    pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                    heightLeft -= pdfHeight;
                }

                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { 
                console.error("Print Error:", error);
                alert("Lỗi khi tạo PDF trích lục."); 
            } finally { 
                setIsPrinting(false); 
                setPrintingParcel(null); 
            }
        }, 1200);
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) {
            setVisibleLayerIds(prev => [...prev, id]);
        }

        const layer = availableLayers.find(l => l.id === id);
        if (layer) {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) {
                            sourceProj = 'EPSG:9210';
                        }
                        const extent = proj.transformExtent(
                            [bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax],
                            sourceProj,
                            'EPSG:3857'
                        );
                        if (mapInstance.current) {
                            mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                        }
                    }
                }
            } catch (e) {
                console.warn("Zoom Error: ", tableName);
            }
        }
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });

        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;

        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureMode) return; 
            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;
            const targetLayer = (layers.find(l => l.get('layerId') === activeLayerId) || layers[layers.length - 1]) as TileLayer<TileWMS>;
            const url = targetLayer.getSource()?.getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });

            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(`${API_URL}/api/proxy/forward?url=${encodeURIComponent(url)}`);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        handleSelectResult({ id: f.id, gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), geometry: f.geometry, properties: f.properties }, evt.coordinate);
                    }
                } catch (e) {
                    console.error("Query failed", e);
                } finally { 
                    setIsQuerying(false); 
                }
            }
        });

        map.on('pointermove', (evt) => {
            if (evt.dragging) return;
            const coords = proj.toLonLat(evt.coordinate);
            setMouseCoord(coords);
        });

        map.getView().on('change:rotation', () => {
            setMapRotation(map.getView().getRotation());
        });

        map.getView().on('change:resolution', () => {
            setMapZoom(map.getView().getZoom() || 0);
        });

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult, measureMode, activeLayerId]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) {
            if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current);
            return;
        }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) {
                    output = formatArea(geom);
                    tooltipCoord = geom.getInteriorPoint().getCoordinates();
                } else if (geom instanceof LineString) {
                    output = formatLength(geom);
                    tooltipCoord = geom.getLastCoordinate();
                }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => {
        measureSource.current.clear();
        mapInstance.current?.getOverlays().getArray()
            .filter(o => o !== overlayInstance.current)
            .forEach(o => mapInstance.current?.removeOverlay(o));
    };

    const handleZoomIn = () => {
        const view = mapInstance.current?.getView();
        if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 });
    };

    const handleZoomOut = () => {
        const view = mapInstance.current?.getView();
        if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 });
    };

    const handleResetRotation = () => {
        mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    };

    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Trình duyệt không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                const lonLat = [pos.coords.longitude, pos.coords.latitude];
                const coords = proj.fromLonLat(lonLat);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.clear();
                    const accuracyFeature = new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) });
                    accuracyFeature.set('type', 'accuracy');
                    source?.addFeature(accuracyFeature);
                    const posFeature = new Feature({ geometry: new Point(coords) });
                    posFeature.set('type', 'position');
                    source?.addFeature(posFeature);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            },
            () => setIsLocating(false),
            { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
        );
    };

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else source = new XYZ({ url: config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url, crossOrigin: 'anonymous' });
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            const layer = new TileLayer({
                source: new TileWMS({ url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png' }, crossOrigin: 'anonymous' }),
                opacity: Number(config.opacity ?? 1),
                zIndex: activeLayerId === config.id ? 50 : 10
            });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-bold tracking-widest text-sm uppercase animate-pulse">Đang nạp dữ liệu...</p>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>

            <div className="absolute bottom-28 left-1/2 -translate-x-1/2 z-[400] flex flex-col gap-2 pointer-events-none items-center w-full max-w-sm px-4">
                {isQuerying && (
                    <div className="w-full bg-slate-900/80 backdrop-blur-2xl border border-cyan-500/40 p-1.5 rounded-2xl shadow-2xl animate-in slide-in-from-bottom-8">
                        <div className="flex items-center gap-3 px-4 py-2">
                            <Fingerprint size={18} className="text-cyan-400 animate-pulse" />
                            <div className="flex-1"><p className="text-[10px] font-black text-cyan-400 uppercase tracking-[0.2em]">Spatial Query</p><p className="text-[9px] text-gray-400 font-bold uppercase">Đang nhận dạng thửa đất...</p></div>
                        </div>
                    </div>
                )}
            </div>

            {isPrinting && (
                <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4">
                    <Printer className="animate-bounce text-orange-500" size={64} />
                    <div className="text-center">
                        <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p>
                        <p className="text-xs text-gray-400 mt-2 italic">Hệ thống đang tự động căn chỉnh bảng tọa độ...</p>
                    </div>
                </div>
            )}

            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />

            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none">
                {selectedParcel && (
                    <div className="pointer-events-auto">
                        <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} />
                    </div>
                )}
            </div>

            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden">
                {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />}
            </div>

            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && (
                    <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button>
                )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden">
                    <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button>
                    <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button>
                </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>

            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState } from 'react';
import { LandParcel, User } from '../../types';

interface PrintTemplateProps {
    parcel: LandParcel;
    user?: User | null;
    systemSettings?: Record<string, string>;
}

interface GeometryPoint {
    id: number;
    x: number;
    y: number;
    distanceNext?: string;
}

const PrintTemplate: React.FC<PrintTemplateProps> = ({ parcel, user, systemSettings }) => {
    const formData = parcel.properties;
    const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
    const [geometryPoints, setGeometryPoints] = useState<GeometryPoint[]>([]);

    const getAttribute = (data: any, keys: string[]) => {
        for (const key of keys) {
            if (data[key] !== undefined && data[key] !== null && data[key] !== '') return data[key];
        }
        return "";
    };

    useEffect(() => {
        if (!parcel.geometry || !parcel.geometry.coordinates) return;

        let rawCoords: any[] = [];
        if (parcel.geometry.type === 'Polygon') {
            rawCoords = parcel.geometry.coordinates[0];
        } else if (parcel.geometry.type === 'MultiPolygon') {
            rawCoords = parcel.geometry.coordinates[0][0];
        }

        if (rawCoords.length > 0) {
            const isClosed = JSON.stringify(rawCoords[0]) === JSON.stringify(rawCoords[rawCoords.length - 1]);
            const filteredCoords = (isClosed && rawCoords.length > 1) ? rawCoords.slice(0, -1) : rawCoords;

            const points: GeometryPoint[] = filteredCoords.map((c: any, i: number) => ({
                id: i + 1,
                x: c[0],
                y: c[1]
            }));

            const isWGS84 = points[0].x > 100 && points[0].x < 110;

            for (let i = 0; i < points.length; i++) {
                const p1 = points[i];
                const p2 = points[i + 1] || points[0]; 

                let dist = 0;
                if (isWGS84) {
                    const avgLat = (p1.y + p2.y) / 2;
                    const cosLat = Math.cos(avgLat * Math.PI / 180);
                    const dx = (p2.x - p1.x) * 111319.9 * cosLat;
                    const dy = (p2.y - p1.y) * 111319.9;
                    dist = Math.sqrt(dx * dx + dy * dy);
                } else {
                    const dx = p2.x - p1.x;
                    const dy = p2.y - p1.y;
                    dist = Math.sqrt(dx * dx + dy * dy);
                }
                p1.distanceNext = dist.toFixed(2);
            }
            setGeometryPoints(points);

            const canvas = parcelCanvasRef.current;
            if (canvas) {
                const ctx = canvas.getContext('2d');
                if (ctx) {
                    ctx.clearRect(0, 0, canvas.width, canvas.height);

                    const xs = points.map(p => p.x);
                    const ys = points.map(p => p.y);
                    const minX = Math.min(...xs), maxX = Math.max(...xs);
                    const minY = Math.min(...ys), maxY = Math.max(...ys);
                    const rangeX = maxX - minX || 0.000001;
                    const rangeY = maxY - minY || 0.000001;

                    const padding = 50;
                    const availableW = canvas.width - padding * 2;
                    const availableH = canvas.height - padding * 2;
                    const scale = Math.min(availableW / rangeX, availableH / rangeY);

                    const offsetX = (canvas.width - rangeX * scale) / 2;
                    const offsetY = (canvas.height - rangeY * scale) / 2;

                    const tx = (x: number) => offsetX + (x - minX) * scale;
                    const ty = (y: number) => canvas.height - (offsetY + (y - minY) * scale);

                    ctx.beginPath();
                    ctx.lineWidth = 2.5;
                    ctx.strokeStyle = "#000000";
                    ctx.lineJoin = "round";
                    points.forEach((pt, idx) => {
                        const px = tx(pt.x);
                        const py = ty(pt.y);
                        if (idx === 0) ctx.moveTo(px, py);
                        else ctx.lineTo(px, py);
                    });
                    ctx.closePath();
                    ctx.stroke();

                    points.forEach((pt, idx) => {
                        const pNext = points[idx + 1] || points[0];
                        const x1 = tx(pt.x), y1 = ty(pt.y);
                        const x2 = tx(pNext.x), y2 = ty(pNext.y);

                        ctx.beginPath();
                        ctx.arc(x1, y1, 3, 0, Math.PI * 2);
                        ctx.fillStyle = "#000";
                        ctx.fill();

                        ctx.font = "bold 13px Arial";
                        const anglePoint = Math.atan2(y1 - (canvas.height/2), x1 - (canvas.width/2));
                        ctx.fillText(pt.id.toString(), x1 + Math.cos(anglePoint) * 18 - 4, y1 + Math.sin(anglePoint) * 18 + 4);

                        if (pt.distanceNext) {
                            const midX = (x1 + x2) / 2;
                            const midY = (y1 + y2) / 2;
                            ctx.save();
                            ctx.translate(midX, midY);
                            let angle = Math.atan2(y2 - y1, x2 - x1);
                            if (angle > Math.PI/2 || angle < -Math.PI/2) angle += Math.PI;
                            ctx.rotate(angle);
                            ctx.font = "italic bold 11px Arial";
                            ctx.textAlign = "center";
                            ctx.fillStyle = "#000000";
                            ctx.fillText(pt.distanceNext, 0, -6);
                            ctx.restore();
                        }
                    });
                }
            }
        }
    }, [parcel]);

