            uptime: os.uptime(), 
            hostname: os.hostname(), 
            cpuUsage: 0 
        });
    });

    // CHỨC NĂNG BACKUP THỰC TẾ
    router.get('/backup/create', async (req, res) => {
        try {
            let sqlContent = `-- GeoMaster GIS Enterprise Backup\n-- Date: ${new Date().toLocaleString()}\n-- Database: ${dbConfig.database}\n\n`;

            // 1. Xuất các bảng hệ thống
            const systemTables = ['system_settings', 'menu_items', 'branches', 'users', 'land_prices', 'role_permissions', 'wms_layers', 'basemaps', 'spatial_tables_registry'];
            for (const table of systemTables) {
                const tableRes = await pool.query(`SELECT * FROM "${table}"`);
                sqlContent += generateInserts(table, tableRes.rows);
            }

            // 2. Xuất các bảng dữ liệu không gian từ Registry
            const registryRes = await pool.query(`SELECT table_name FROM spatial_tables_registry`);
            for (const row of registryRes.rows) {
                const tableName = row.table_name;
                const checkTable = await pool.query(`SELECT EXISTS (SELECT FROM information_schema.tables WHERE table_name = $1)`, [tableName]);
                if (checkTable.rows[0].exists) {
                    // Đối với bảng không gian, cần chuyển geometry về dạng TEXT để dump
                    const dataRes = await pool.query(`SELECT *, ST_AsText(geometry) as geometry_wkt FROM "${tableName}"`);

                    if (dataRes.rows.length > 0) {
                        sqlContent += `-- Data for spatial table: ${tableName}\n`;
                        const cols = Object.keys(dataRes.rows[0]).filter(c => c !== 'geometry_wkt').map(c => `"${c}"`).join(', ');

                        dataRes.rows.forEach(r => {
                            const geomWkt = r.geometry_wkt;
                            const vals = Object.entries(r)
                                .filter(([k]) => k !== 'geometry_wkt')
                                .map(([_, val]) => {
                                    if (val === null) return 'NULL';
                                    if (typeof val === 'string') return `'${val.replace(/'/g, "''")}'`;
                                    return val;
                                }).join(', ');

                            if (geomWkt) {
                                sqlContent += `INSERT INTO "${tableName}" (${cols}, "geometry") VALUES (${vals}, ST_GeomFromText('${geomWkt}', 4326)) ON CONFLICT DO NOTHING;\n`;
                            } else {
                                sqlContent += `INSERT INTO "${tableName}" (${cols}) VALUES (${vals}) ON CONFLICT DO NOTHING;\n`;
                            }
                        });
                        sqlContent += '\n';
                    }
                }
            }

            res.setHeader('Content-Type', 'application/sql');
            res.setHeader('Content-Disposition', `attachment; filename=geomaster_backup_${new Date().getTime()}.sql`);
            res.status(200).send(sqlContent);

            await logSystemAction(req, 'BACKUP_DB', 'Xuất bản sao lưu Database SQL');
        } catch (e) {
            console.error("Backup Error:", e);
            res.status(500).send(`-- Lỗi trong quá trình xuất SQL: ${e.message}`);
        }
    });

    router.post('/backup/restore', (req, res) => {
        res.json({ status: 'ok', message: 'Phục hồi dữ liệu hoàn tất (Simulated)' });
    });

    return router;
}

