        await pool.query(`CREATE TABLE IF NOT EXISTS role_permissions (role TEXT PRIMARY KEY, permissions TEXT[])`);

        await seedDefaultData();
    } catch (e) { console.error("❌ CRITICAL DB INIT ERROR:", e.message); }
};

