import express from 'express';
const router = express.Router();

// Helper: Tự động retry khi fetch thất bại
const fetchWithRetry = async (url, options, retries = 2) => {
    for (let i = 0; i <= retries; i++) {
        try {
            const response = await fetch(url, options);
            // Nếu lỗi server 5xx thì throw để retry, lỗi 4xx thì trả về luôn
            if (!response.ok && response.status >= 500) {
                throw new Error(`Server returned ${response.status}`);
            }
            return response;
        } catch (err) {
            if (i === retries) throw err;
            await new Promise(r => setTimeout(r, 500 * (i + 1))); // Backoff tăng dần
        }
    }
};

router.get('/vietbando', async (req, res) => {
    const { z, x, y } = req.query;
    if (!z || !x || !y) return res.status(400).send("Missing tile coordinates");

    // URL chuẩn cho tiling của Vietbando API v2
    const targetUrl = `http://images.vietbando.com/ImageLoader/GetImage.ashx?Ver=2016&LayerIds=VBD&Y=${y}&X=${x}&Level=${z}`;

    try {
        const response = await fetchWithRetry(targetUrl, {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Referer': 'http://vietbando.com/',
                'Accept': 'image/webp,image/apng,image/*,*/*;q=0.8'
            },
            signal: AbortSignal.timeout(5000) // Timeout 5s cho mỗi lần thử
        }, 1); // Retry tối đa 1 lần

        if (!response.ok) {
            // Log warn thay vì error để tránh spam file log
            console.warn(`[Proxy-VBD] Tile ${z}/${x}/${y} status: ${response.status}`);
            return res.status(404).send('Tile not found'); 
        }

        const arrayBuffer = await response.arrayBuffer();

        res.set('Content-Type', response.headers.get('content-type') || 'image/png');
        res.set('Cache-Control', 'public, max-age=86400');
        res.set('Access-Control-Allow-Origin', '*');
        res.send(Buffer.from(arrayBuffer));
    } catch (error) {
        // Chỉ warn các lỗi kết nối thông thường
        console.warn(`[Proxy-VBD] Fail ${z}/${x}/${y}: ${error.message}`);
        res.status(404).send('Tile error');
    }
});

router.get('/forward', async (req, res) => {
    let targetBaseUrl = req.query.url;
    if (!targetBaseUrl) return res.status(400).send("Missing 'url' parameter");

    try {
        targetBaseUrl = decodeURIComponent(targetBaseUrl);
        const finalUrl = new URL(targetBaseUrl);

        // Copy các query params từ client sang URL đích
        Object.keys(req.query).forEach(key => {
            if (key !== 'url') {
                finalUrl.searchParams.set(key, req.query[key]);
            }
        });

        // Fix lỗi GeoServer đôi khi cần QUERY_LAYERS trùng với LAYERS
        const layers = finalUrl.searchParams.get('LAYERS');
        if (layers && !finalUrl.searchParams.get('QUERY_LAYERS')) {
            finalUrl.searchParams.set('QUERY_LAYERS', layers);
        }

        const response = await fetch(finalUrl.toString(), {
            signal: AbortSignal.timeout(15000), // Timeout 15s cho WMS
            headers: {
                'User-Agent': 'Mozilla/5.0 (GeoMaster Proxy)',
                'Accept': 'application/json, image/webp, image/png, image/*, */*',
                'Referer': finalUrl.origin
            }
        });

        const contentType = response.headers.get('content-type');
        if (contentType) res.set('Content-Type', contentType);

        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
        res.set('Cache-Control', 'public, max-age=300'); // Cache ngắn cho WMS

        if (!response.ok) {
            const errText = await response.text().catch(() => '');
            console.warn(`[Proxy-FWD] Upstream Error ${response.status}: ${finalUrl.host}`);
            return res.status(response.status).send(errText);
        }

        const arrayBuffer = await response.arrayBuffer();
        res.send(Buffer.from(arrayBuffer));
    } catch (e) {
        const isTimeout = e.name === 'TimeoutError' || e.name === 'AbortError';
        const logMsg = `[Proxy-FWD] Error: ${e.message} -> ${targetBaseUrl}`;

        // Phân loại log để dễ debug
        if (isTimeout) console.warn(logMsg);
        else console.error(logMsg);

        res.status(502).json({ 
            error: "Proxy Gateway Error", 
            message: "Không thể kết nối đến máy chủ bản đồ mục tiêu.",
            details: e.message
        });
    }
});

