            osType: os.type(), 
            freeMem: os.freemem(), 
            uptime: os.uptime(), 
            hostname: os.hostname(), 
            cpuUsage: 0 
        });
    });

    // CHỨC NĂNG BACKUP THỰC TẾ
    router.get('/backup/create', async (req, res) => {
        try {
            let sqlContent = `-- GeoMaster GIS Enterprise Backup\n-- Date: ${new Date().toLocaleString()}\n-- Database: ${dbConfig.database}\n\n`;

            // 1. Xuất các bảng hệ thống
            const systemTables = ['system_settings', 'menu_items', 'branches', 'users', 'land_prices', 'role_permissions', 'wms_layers', 'basemaps', 'spatial_tables_registry'];
            for (const table of systemTables) {
                const tableRes = await pool.query(`SELECT * FROM "${table}"`);
                sqlContent += generateInserts(table, tableRes.rows);
            }

            // 2. Xuất các bảng dữ liệu không gian từ Registry
            const registryRes = await pool.query(`SELECT table_name FROM spatial_tables_registry`);
            for (const row of registryRes.rows) {
                const tableName = row.table_name;
                const checkTable = await pool.query(`SELECT EXISTS (SELECT FROM information_schema.tables WHERE table_name = $1)`, [tableName]);
                if (checkTable.rows[0].exists) {
                    // Đối với bảng không gian, cần chuyển geometry về dạng TEXT để dump
                    const dataRes = await pool.query(`SELECT *, ST_AsText(geometry) as geometry_wkt FROM "${tableName}"`);

                    if (dataRes.rows.length > 0) {
                        sqlContent += `-- Data for spatial table: ${tableName}\n`;
                        const cols = Object.keys(dataRes.rows[0]).filter(c => c !== 'geometry_wkt').map(c => `"${c}"`).join(', ');

                        dataRes.rows.forEach(r => {
                            const geomWkt = r.geometry_wkt;
                            const vals = Object.entries(r)
                                .filter(([k]) => k !== 'geometry_wkt')
                                .map(([_, val]) => {
                                    if (val === null) return 'NULL';
                                    if (typeof val === 'string') return `'${val.replace(/'/g, "''")}'`;
                                    return val;
                                }).join(', ');

                            if (geomWkt) {
                                sqlContent += `INSERT INTO "${tableName}" (${cols}, "geometry") VALUES (${vals}, ST_GeomFromText('${geomWkt}', 4326)) ON CONFLICT DO NOTHING;\n`;
                            } else {
                                sqlContent += `INSERT INTO "${tableName}" (${cols}) VALUES (${vals}) ON CONFLICT DO NOTHING;\n`;
                            }
                        });
                        sqlContent += '\n';
                    }
                }
            }

            res.setHeader('Content-Type', 'application/sql');
            res.setHeader('Content-Disposition', `attachment; filename=geomaster_backup_${new Date().getTime()}.sql`);
            res.status(200).send(sqlContent);

            await logSystemAction(req, 'BACKUP_DB', 'Xuất bản sao lưu Database SQL');
        } catch (e) {
            console.error("Backup Error:", e);
            res.status(500).send(`-- Lỗi trong quá trình xuất SQL: ${e.message}`);
        }
    });

    router.post('/backup/restore', (req, res) => {
        res.json({ status: 'ok', message: 'Phục hồi dữ liệu hoàn tất (Simulated)' });
    });

    return router;
}

import React, { useState, useEffect } from 'react';
import { adminService } from '../../services/mockBackend';
import { User, UserRole, Branch } from '../../types';
import { Users, Plus, Edit2, Trash2, X, Save, Loader2, Key, Check, AlertTriangle, CheckCircle2, Info, Ban, UserCheck } from 'lucide-react';

const UserManager: React.FC = () => {
    const [users, setUsers] = useState<User[]>([]);
    const [branches, setBranches] = useState<Branch[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isResetModalOpen, setIsResetModalOpen] = useState(false);
    const [formData, setFormData] = useState<any>({});
    const [resetData, setResetData] = useState({ userId: '', userName: '', newPassword: '' });
    const [editingId, setEditingId] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try {
            const [usersData, branchesData] = await Promise.all([
                adminService.getUsers(),
                adminService.getBranches()
            ]);
            setUsers(usersData);
            setBranches(branchesData);
        } catch (e) { console.error("Load users error:", e); }
    };

    const handleSave = async () => {
        if (!formData.name || !formData.email) {
            showDialog('error', 'Thiếu dữ liệu', "Vui lòng nhập đầy đủ Họ tên và Email");
            return;
        }
        if (!editingId && !formData.password) {
            showDialog('error', 'Thiếu dữ liệu', "Vui lòng nhập mật khẩu cho người dùng mới");
            return;
        }

        setLoading(true);
        try {
            if (editingId) {
                await adminService.updateUser({...formData, id: editingId});
            } else {
                await adminService.addUser(formData);
            }
            setIsModalOpen(false);
            await loadData();
            showDialog('success', 'Thành công', editingId ? 'Đã cập nhật thông tin người dùng.' : 'Đã khởi tạo tài khoản mới.');
        } catch(e: any) { 
            showDialog('error', 'Lỗi hệ thống', e.message); 
        } finally {
            setLoading(false);
        }
    };

    const handleResetPassword = async () => {
        if (!resetData.newPassword) return showDialog('error', 'Thiếu mật khẩu', "Vui lòng nhập mật khẩu mới");
        setLoading(true);
        try {
            await adminService.resetPassword(resetData.userId, resetData.newPassword);
            showDialog('success', 'Đã đặt lại', `Đã đặt lại mật khẩu thành công cho ${resetData.userName}`);
            setIsResetModalOpen(false);
        } catch (e: any) {
            showDialog('error', 'Lỗi', e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        showDialog('confirm', 'Xác nhận xóa', "Bạn có chắc chắn muốn xóa vĩnh viễn người dùng này khỏi hệ thống?", async () => {
            try {
                await adminService.deleteUser(id);
                await loadData();
                showDialog('success', 'Đã xóa', 'Người dùng đã được gỡ bỏ.');
            } catch (e: any) { showDialog('error', 'Lỗi', e.message); }
        });
    };

    const handleToggleVerification = async (u: User) => {
        const action = u.is_verified ? 'HỦY KÍCH HOẠT' : 'KÍCH HOẠT';
        showDialog('confirm', `Xác nhận ${action}`, `Bạn có muốn thay đổi trạng thái tài khoản của ${u.name}?`, async () => {
            setLoading(true);
            try {
                await adminService.updateUser({ ...u, is_verified: !u.is_verified });
                await loadData();
                showDialog('success', 'Thành công', `Đã cập nhật trạng thái người dùng.`);
            } catch (e: any) { showDialog('error', 'Lỗi', e.message); } finally { setLoading(false); }
        });
    };

    const openAddModal = () => {
        setEditingId(null);
