const initDB = async () => {
    try {
        const client = await pool.connect();
        console.log("✅ Database Connected.");
        client.release();

        try { await pool.query(`CREATE EXTENSION IF NOT EXISTS postgis`); } catch (e) {}

        await pool.query(`CREATE TABLE IF NOT EXISTS system_logs (id SERIAL PRIMARY KEY, user_id TEXT, user_name TEXT, action TEXT, details TEXT, timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS system_settings (key TEXT PRIMARY KEY, value TEXT, type TEXT, label TEXT, description TEXT)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS branches (id TEXT PRIMARY KEY, code TEXT, name TEXT, address TEXT)`);

        // --- USERS TABLE ---
        await pool.query(`CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, email TEXT UNIQUE, password_hash TEXT, name TEXT, role TEXT, branch_id TEXT)`);

