        } catch (migErr) {}

        // BẢNG QUẢN LÝ TOKEN QUÊN MẬT KHẨU
        await pool.query(`
            CREATE TABLE IF NOT EXISTS password_reset_tokens (
                id SERIAL PRIMARY KEY,
                email TEXT NOT NULL,
                token TEXT NOT NULL,
                expires_at TIMESTAMP NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )
        `);

        await pool.query(`CREATE TABLE IF NOT EXISTS spatial_tables_registry (table_name TEXT PRIMARY KEY, display_name TEXT, description TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS wms_layers (id TEXT PRIMARY KEY, name TEXT, url TEXT, layers TEXT, visible BOOLEAN DEFAULT true, opacity NUMERIC DEFAULT 1)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS basemaps (id TEXT PRIMARY KEY, name TEXT, url TEXT, type TEXT, is_default BOOLEAN DEFAULT false, visible BOOLEAN DEFAULT true)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS land_prices (land_type TEXT PRIMARY KEY, base_price NUMERIC, description TEXT)`);
        await pool.query(`CREATE TABLE IF NOT EXISTS role_permissions (role TEXT PRIMARY KEY, permissions TEXT[])`);

        await seedDefaultData();
    } catch (e) { console.error("❌ CRITICAL DB INIT ERROR:", e.message); }
};

