            const res = await fetch(`${API_URL}/api/backup/create`, { headers: getAuthHeaders() });
            if (!res.ok) {
                const err = await res.json();
                throw new Error(err.error || "Tạo bản sao lưu thất bại");
            }

            const blob = await res.blob();
            // Kiểm tra xem blob có nội dung lỗi từ backend không (định dạng văn bản bắt đầu bằng -- Lỗi)
            if (blob.size < 500) {
                const text = await blob.text();
                if (text.startsWith('-- Lỗi')) throw new Error(text.replace('-- ', ''));
            }

            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `backup_${new Date().toISOString().replace(/[:.]/g, '-')}.sql`;
            document.body.appendChild(a);
            a.click();
            window.URL.revokeObjectURL(url);
            document.body.removeChild(a);
        } catch (e: any) {
            alert("Lỗi Backup: " + e.message);
            throw e;
        }
    },

    restoreDatabase: async (file: File) => {
