import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Login from './pages/Login';
import MapPage from './pages/MapPage';
import Dashboard from './pages/Dashboard';
import AdminPage from './pages/AdminPage'; 
import UserProfile from './pages/UserProfile';
import { User, UserRole, SystemSetting } from './types';
import { Menu, ShieldAlert, RefreshCw } from 'lucide-react';
import { adminService } from './services/mockBackend';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activePage, setActivePage] = useState('map');
  const [showLogin, setShowLogin] = useState(false);
  const [resetToken, setResetToken] = useState<string | null>(null);
  const [verificationToken, setVerificationToken] = useState<string | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
      // KIỂM TRA TOKEN TRÊN URL (CHO QUÊN MẬT KHẨU HOẶC XÁC THỰC EMAIL)
      const params = new URLSearchParams(window.location.search);
      const token = params.get('token');
      const verifyToken = params.get('verificationToken');

      if (token) {
          setResetToken(token);
          setShowLogin(true);
      }
      if (verifyToken) {
          setVerificationToken(verifyToken);
          setShowLogin(true);
      }

      const boot = async () => {
          setLoading(true);
          try {
              const settings: SystemSetting[] = await adminService.getSettings();
              const settingsMap: Record<string, string> = {};
              settings.forEach(s => settingsMap[s.key] = s.value);
              setSystemSettings(settingsMap);

              if (settingsMap['system_name']) {
                  document.title = settingsMap['system_name'];
              }

              const faviconUrl = settingsMap['site_favicon'] || settingsMap['site_logo'];
              if (faviconUrl) {
                  const favicon = document.getElementById('favicon') as HTMLLinkElement;
                  if (favicon) favicon.href = faviconUrl;
              }

              const savedUser = localStorage.getItem('geo_user');
              if (savedUser) {
                  const parsed = JSON.parse(savedUser);
                  setUser(parsed);
              }
          } catch (e) {
              console.error("Failed to boot app", e);
          } finally {
              setLoading(false);
          }
      };
      boot();
  }, []);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
    setResetToken(null);
    setVerificationToken(null);
    if (loggedInUser.role === UserRole.ADMIN) {
        setActivePage('admin');
    } else {
        setActivePage('dashboard');
    }
  };

  const handleUpdateUser = (updatedUser: User) => {
      setUser(updatedUser);
      localStorage.setItem('geo_user', JSON.stringify(updatedUser));
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    setActivePage('map');
  };

  const isMaintenance = systemSettings['maintenance_mode'] === 'true' && user?.role !== UserRole.ADMIN;

  if (loading) {
      return (
          <div className="h-screen w-full bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
              <RefreshCw className="animate-spin text-blue-500" size={48} />
              <p className="font-display uppercase tracking-widest text-sm">Khởi động GeoMaster...</p>
          </div>
      );
  }

  if (isMaintenance) {
      return (
          <div className="h-screen w-full bg-slate-950 flex flex-col items-center justify-center p-6 text-center">
              <div className="bg-orange-500/10 p-6 rounded-full mb-6 border border-orange-500/20">
                <ShieldAlert className="text-orange-500" size={64} />
              </div>
              <h1 className="text-3xl font-display font-bold text-white mb-2 uppercase tracking-tighter">Hệ thống đang bảo trì</h1>
              <p className="text-slate-400 max-w-md mb-8">Chúng tôi đang nâng cấp hệ thống để phục vụ tốt hơn. Vui lòng quay lại sau ít phút.</p>
              {user ? (
                  <button onClick={handleLogout} className="px-6 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all">Đăng xuất</button>
              ) : (
                  <button onClick={() => setShowLogin(true)} className="text-blue-500 hover:underline">Dành cho Quản trị viên</button>
              )}
          </div>
      );
  }

  if (showLogin) {
    return (
      <Login 
        onLogin={handleLogin} 
        onCancel={() => { setShowLogin(false); setResetToken(null); setVerificationToken(null); }}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
        footerText={systemSettings['footer_text']}
        allowRegistration={systemSettings['allow_registration'] === 'true'}
        initialToken={resetToken}
        verificationToken={verificationToken}
      />
    );
  }

  const renderContent = () => {
    switch (activePage) {
      case 'dashboard':
        return user ? <Dashboard user={user} /> : <div className="flex h-full items-center justify-center text-gray-400 bg-slate-900">Vui lòng đăng nhập để xem báo cáo.</div>;
      case 'map':
        return <MapPage user={user} systemSettings={systemSettings} />;
      case 'profile':
        return user ? <UserProfile user={user} onUpdateUser={handleUpdateUser} /> : <div className="p-8 text-red-400 bg-slate-900 h-full">Vui lòng đăng nhập.</div>;
      case 'admin':
        return user && user.role === UserRole.ADMIN ? (
            <AdminPage 
                systemName={systemSettings['system_name']}
                logoUrl={systemSettings['site_logo']}
            />
        ) : <div className="p-8 text-red-400 bg-slate-900 h-full">Bạn không có quyền truy cập trang này.</div>;
      default:
        return <MapPage user={user} systemSettings={systemSettings} />;
    }
  };

  return (
    <div className="flex h-screen w-full bg-gray-900 overflow-hidden font-sans relative">
      <Sidebar 
        user={user} 
        activePage={activePage} 
        onNavigate={setActivePage} 
        onLogout={handleLogout}
        onLoginClick={() => setShowLogin(true)}
        onCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        isCollapsed={isSidebarCollapsed}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
      />

      <main className="flex-1 h-full relative overflow-hidden bg-gray-100 flex flex-col transition-all duration-300">
        <div className="flex-1 min-h-0 w-full relative">
            {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { User, UserRole, MenuItem } from '../types';
import { LogOut, LogIn, ChevronLeft, ChevronRight, User as UserIcon, Database, HelpCircle, ExternalLink } from 'lucide-react';
import * as Icons from 'lucide-react';
import { adminService } from '../services/mockBackend';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    user, 
    activePage, 
    onNavigate, 
    onLogout, 
    onLoginClick, 
    onCollapse, 
    isCollapsed,
    systemName, 
    logoUrl 
}) => {
  const [dynamicMenu, setDynamicMenu] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
      const fetchMenu = async () => {
          try {
              // Kiểm tra xem hàm getMenuItems có tồn tại không trước khi gọi
              if (adminService && typeof adminService.getMenuItems === 'function') {
                  const items = await adminService.getMenuItems();
                  setDynamicMenu(items.filter(i => i.is_active).sort((a, b) => a.order_index - b.order_index));
              } else {
                  throw new Error("Service getMenuItems is not ready");
              }
          } catch (e) {
              console.error("Failed to load sidebar menu, using fallback", e);
              setDynamicMenu([
                  { id: 'dashboard', label: 'Bảng điều khiển', icon: 'LayoutDashboard', roles: ['ADMIN', 'EDITOR', 'VIEWER'], order_index: 0, is_active: true, type: 'INTERNAL' },
                  { id: 'map', label: 'Bản đồ WebGIS', icon: 'Map', roles: ['GUEST', 'ADMIN', 'EDITOR', 'VIEWER'], order_index: 1, is_active: true, type: 'INTERNAL' },
                  { id: 'admin', label: 'Quản trị hệ thống', icon: 'Shield', roles: ['ADMIN'], order_index: 2, is_active: true, type: 'INTERNAL' }
              ]);
          } finally {
              setLoading(false);
          }
      };
      fetchMenu();
  }, [user]);

  const visibleItems = dynamicMenu.filter(item => {
    if (!user) return item.roles.includes('GUEST');
    return item.roles.includes(user.role);
  });

  const handleMenuClick = (item: MenuItem) => {
      if (item.type === 'EXTERNAL' && item.url) {
          window.open(item.url, '_blank');
      } else {
          onNavigate(item.id);
      }
  };

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-64'} bg-[#0f172a] text-white h-screen flex flex-col transition-all duration-300 ease-in-out border-r border-slate-800 relative z-50`}>
      <button 
        onClick={onCollapse} 
        className="absolute -right-3 top-10 bg-blue-600 text-white rounded-full p-1 shadow-lg border border-white/20 hover:bg-blue-500 transition-all z-[60]"
      >
        {isCollapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
      </button>

      <div className={`p-5 border-b border-slate-800/50 flex flex-col items-center ${isCollapsed ? 'justify-center' : 'items-start'}`}>
        <div className="flex items-center gap-3">
            {logoUrl ? (
                <img src={logoUrl} alt="Logo" className="w-10 h-10 object-contain drop-shadow-[0_0_8px_rgba(59,130,246,0.5)]" />
            ) : (
                <Database className="w-8 h-8 text-blue-500" />
            )}
            {!isCollapsed && (
                <div className="animate-in fade-in slide-in-from-left-2 duration-300">
                    <h1 className="text-sm font-black text-white leading-tight uppercase tracking-tighter">
                        {systemName || 'GeoMaster'}
                    </h1>
                    <p className="text-[10px] text-blue-500 font-bold tracking-widest">GIS ENTERPRISE</p>
                </div>
            )}
        </div>
      </div>

      <div className="flex-1 py-6 space-y-2 overflow-y-auto custom-scrollbar no-scrollbar">
        {loading ? (
            <div className="px-6 py-2 animate-pulse flex flex-col gap-4">
                {[1,2,3].map(i => <div key={i} className="h-10 bg-slate-800 rounded-lg w-full"></div>)}
            </div>
        ) : visibleItems.map(item => {
          const isActive = activePage === item.id;
          const IconComponent = (Icons as any)[item.icon] || HelpCircle;

          return (
            <button
              key={item.id}
              onClick={() => handleMenuClick(item)}
              title={isCollapsed ? item.label : ''}
              className={`w-full flex items-center gap-4 px-6 py-3.5 transition-all relative group ${
                isActive 
                  ? 'text-blue-400 bg-blue-600/10' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800/50'
              }`}
            >
              {isActive && <div className="absolute left-0 top-0 w-1 h-full bg-blue-500 shadow-[0_0_10px_#3b82f6]"></div>}

              <div className={`${isCollapsed ? 'mx-auto' : ''} transition-transform group-hover:scale-110 flex items-center`}>
                <IconComponent size={22} className={isActive ? 'text-blue-400' : ''} />
              </div>

              {!isCollapsed && (
                <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-2 duration-300">
                    <span className="font-bold text-xs uppercase tracking-widest">
                        {item.label}
                    </span>
                    {item.type === 'EXTERNAL' && (
                        <ExternalLink size={10} className="text-slate-600 group-hover:text-orange-400 transition-colors" />
                    )}
                </div>
              )}
            </button>
          );
        })}
      </div>

      <div className="p-4 border-t border-slate-800/50 bg-slate-900/30">
        {user ? (
          <div className="flex flex-col gap-3">
            {!isCollapsed && (
              <div 
                onClick={() => onNavigate('profile')}
                className="flex items-center gap-3 animate-in fade-in duration-300 cursor-pointer hover:bg-slate-800/50 p-2 rounded-lg transition-colors group"
                title="Cập nhật hồ sơ cá nhân"
              >
                  <div className="w-9 h-9 rounded-full bg-blue-600/20 flex items-center justify-center border border-blue-500/30 overflow-hidden shrink-0 group-hover:border-blue-400 transition-colors">
                    {user.avatar ? (
                        <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                        <UserIcon size={18} className="text-blue-400" />
                    )}
                  </div>
                  <div className="overflow-hidden">
                      <p className="text-xs font-black text-white truncate uppercase tracking-tighter group-hover:text-blue-400 transition-colors">{user.name}</p>
                      <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">{user.role}</p>
                  </div>
              </div>
            )}

            {/* Show avatar only in collapsed mode if profile click is desired, but here logout is priority for collapsed */}
            {isCollapsed && (
                 <div 
                    onClick={() => onNavigate('profile')} 
                    className="w-9 h-9 mx-auto rounded-full bg-blue-600/20 flex items-center justify-center border border-blue-500/30 overflow-hidden cursor-pointer hover:border-blue-400 mb-2"
                    title={user.name}
                 >
                    {user.avatar ? (
                        <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                        <UserIcon size={18} className="text-blue-400" />
                    )}
                 </div>
            )}

            <button 
              onClick={onLogout}
              title={isCollapsed ? "Đăng xuất" : ""}
              className={`flex items-center gap-3 px-4 py-2.5 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all border border-red-500/20 ${isCollapsed ? 'justify-center' : ''}`}
            >
              <LogOut size={18} />
              {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng xuất</span>}
            </button>
          </div>
        ) : (
          <button 
            onClick={onLoginClick}
            className="w-full flex items-center gap-2 px-4 py-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-500 transition-all shadow-lg shadow-blue-900/20"
          >
            <LogIn size={18} />
            {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng nhập</span>}
          </button>
        )}
      </div>
    </div>
  );
};

export default Sidebar;

import express from 'express';
import cors from 'cors';
import pg from 'pg';
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs';
import dbConfig from './db_config.js';

// Routers
import proxyRouter from './routes_proxy.js';
import systemRouter from './routes_system.js';
import spatialRouter from './routes_spatial.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Đảm bảo thư mục uploads tồn tại
const uploadDir = path.join(__dirname, 'uploads');
if (!fs.existsSync(uploadDir)){
    fs.mkdirSync(uploadDir);
}

const { Pool } = pg;
const app = express();
const pool = new Pool({
    ...dbConfig,
    connectionTimeoutMillis: 10000,
});
const port = 3004;

app.use(cors({
    origin: '*',
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization', 'x-user-id', 'x-user-name', 'x-branch-id']
}));

app.use(express.json({ limit: '50mb' }));
app.enable('trust proxy');

// CẤU HÌNH STATIC FOLDER CHO UPLOADS (Để hiển thị avatar)
app.use('/uploads', express.static(path.join(__dirname, 'uploads')));

const logSystemAction = async (req, action, details, overrideUser = null) => {
