const UserProfile: React.FC<UserProfileProps> = ({ user, onUpdateUser }) => {
    const [name, setName] = useState(user.name);
    // avatarPreview dùng để hiển thị ngay lập tức khi user chọn ảnh
    const [avatarPreview, setAvatarPreview] = useState<string>(user.avatar ? (user.avatar.startsWith('http') ? user.avatar : `${API_URL}${user.avatar}`) : '');
    // selectedFile dùng để gửi lên server
    const [selectedFile, setSelectedFile] = useState<File | null>(null);

    // Password Change State
    const [oldPassword, setOldPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');

    const [loading, setLoading] = useState(false);
    const [passLoading, setPassLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.size > 5 * 1024 * 1024) {
                setMessage({ type: 'error', text: 'Ảnh đại diện không được vượt quá 5MB' });
                return;
            }
            // Lưu file để gửi đi
            setSelectedFile(file);

            // Tạo preview
            const reader = new FileReader();
            reader.onloadend = () => {
                setAvatarPreview(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleUpdateProfile = async () => {
        setLoading(true);
        setMessage(null);
        try {
            // Gửi file (nếu có) và tên lên server
            const result = await authService.updateProfile(user.id, name, selectedFile);

            // Cập nhật state local với thông tin mới từ server trả về
            const newAvatarUrl = result.avatar || user.avatar;
            onUpdateUser({ ...user, name, avatar: newAvatarUrl });

            // Nếu có avatar mới, cập nhật lại preview từ URL server (để đảm bảo đồng bộ)
            if (result.avatar) {
                setAvatarPreview(`${API_URL}${result.avatar}`);
                setSelectedFile(null); // Reset file select
            }

