                    </button>
                </div>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-900 text-gray-400 uppercase text-[10px] tracking-widest font-black">
                            <tr><th className="p-4">Tên hiển thị</th><th className="p-4">Workspace:Layer</th><th className="p-4">Trạng thái</th><th className="p-4 text-right">Thao tác</th></tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700 text-gray-300">
                            {wmsLayers.map(l => (
