                                        <input className="w-full bg-gray-900 border border-orange-900/30 rounded-lg p-2.5 text-white outline-none focus:border-orange-500 font-bold" placeholder="vd: Dữ liệu Thửa đất Phường 1" value={formData.displayName || ''} onChange={e => setFormData({...formData, displayName: e.target.value})} required />
                                    </div>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Mô tả / Ghi chú</label>
                                        <textarea className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white text-xs outline-none focus:border-green-500 h-20 resize-none" placeholder="Nhập ghi chú..." value={formData.description || ''} onChange={e => setFormData({...formData, description: e.target.value})}/>
                                    </div>
                                </>
                            )}

                            {/* Form cho LAYER WMS */}
                            {modalType === 'LAYER' && (
                                <>
                                    <div>
                                        <label className="text-[10px] text-gray-500 font-black uppercase block mb-1.5 ml-1">Tên hiển thị</label>
                                        <input className="w-full bg-gray-900 border border-gray-600 rounded-lg p-2.5 text-white outline-none focus:border-cyan-500" value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})}/>
