const getApiUrl = () => {
    const { hostname, protocol } = window.location;

    // Kiểm tra nếu đang chạy trên môi trường Local hoặc mạng LAN (IP)
    const isLocalOrLan = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocalOrLan) {
        // Tự động dùng Hostname hiện tại + Port 3004
        return `${protocol}//${hostname}:3004`;
    }

    return 'https://apigeo.gisvn.space'; 
};

