export const API_URL = getApiUrl();

const apiCall = async (endpoint: string, options: RequestInit = {}) => {
    const headers: any = {
        'Content-Type': 'application/json',
        ...options.headers,
    };

    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId;
        } catch (e) { }
    }

    // Nếu body là FormData thì xoá Content-Type để browser tự set boundary
    if (options.body instanceof FormData) {
        delete headers['Content-Type'];
    }

    const response = await fetch(`${API_URL}/api${endpoint}`, {
        ...options,
        headers,
    });

    if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(errorData.error || errorData.message || `API Error ${response.status}`);
    }

    // Return JSON if possible, else text
    const text = await response.text();
    try {
        return JSON.parse(text);
    } catch {
        return text;
    }
};

