import React, { useState, useEffect } from 'react';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import MapPage from './pages/MapPage';
import AdminPage from './pages/AdminPage';
import UserProfile from './pages/UserProfile';
import Sidebar from './components/Sidebar';
import { User, SystemSetting } from './types';
import { adminService, authService } from './services/mockBackend';
import { Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activePage, setActivePage] = useState('dashboard');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [systemSettings, setSystemSettings] = useState<Record<string, string>>({});
  const [loading, setLoading] = useState(true);

  // Parse URL for verification token
  const urlParams = new URLSearchParams(window.location.search);
  const verificationToken = urlParams.get('verify_token');
  const resetToken = urlParams.get('reset_token');

  useEffect(() => {
      const boot = async () => {
          setLoading(true);
          try {
              let settingsMap: Record<string, string> = {};
              try {
                const settings: SystemSetting[] = await adminService.getSettings();
                settings.forEach(s => settingsMap[s.key] = s.value);
                setSystemSettings(settingsMap);
              } catch (e) {
                console.warn("Could not load settings", e);
              }

              if (settingsMap['system_name']) {
                  document.title = settingsMap['system_name'];
              }

              const faviconUrl = settingsMap['site_favicon'] || settingsMap['site_logo'];
              if (faviconUrl) {
                  const favicon = document.getElementById('favicon') as HTMLLinkElement;
                  if (favicon) favicon.href = faviconUrl;
              }

              const savedUser = localStorage.getItem('geo_user');
              if (savedUser) {
                  const parsed = JSON.parse(savedUser);
                  setUser(parsed); // Hiển thị ngay dữ liệu cũ để không bị giật lag

                  // SYNC: Gọi lên server lấy thông tin mới nhất (Avatar, Tên, Quyền)
                  // Giúp đồng bộ giữa các máy khác nhau
                  try {
                      const freshUser = await authService.getProfile(parsed.id);
                      if (freshUser) {
                          // Giữ lại token hoặc các trường local nếu server không trả về (tùy backend)
                          // Ở đây backend trả về đủ user info, ta cập nhật lại state và localStorage
                          const mergedUser = { ...parsed, ...freshUser };
                          setUser(mergedUser);
                          localStorage.setItem('geo_user', JSON.stringify(mergedUser));
                      }
                  } catch (syncErr) {
                      console.warn("Không thể đồng bộ thông tin user mới nhất (Offline hoặc Lỗi Server)", syncErr);
                  }
              }

              if (verificationToken || resetToken) {
                setShowLogin(true);
              }

          } catch (e) {
              console.error("Failed to boot app", e);
          } finally {
              setLoading(false);
          }
      };
      boot();
  }, [verificationToken, resetToken]);

  const handleLogin = (loggedInUser: User) => {
    setUser(loggedInUser);
    localStorage.setItem('geo_user', JSON.stringify(loggedInUser));
    setShowLogin(false);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('geo_user');
    setActivePage('dashboard');
  };

  const renderContent = () => {
    if (activePage === 'profile' && user) return <UserProfile user={user} onUpdateUser={(u) => { setUser(u); localStorage.setItem('geo_user', JSON.stringify(u)); }} />;
    if (activePage === 'admin' && user?.role === 'ADMIN') return <AdminPage systemName={systemSettings['system_name']} logoUrl={systemSettings['site_logo']} />;
    if (activePage === 'map') return <MapPage user={user} systemSettings={systemSettings} />;
    return <Dashboard user={user || { id: 'guest', name: 'Khách', email: '', role: 'VIEWER' } as any} />;
  };

  if (loading) {
    return (
      <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center text-white gap-4">
        <Loader2 className="animate-spin text-blue-500" size={48} />
        <p className="text-sm font-bold uppercase tracking-widest animate-pulse">Khởi động hệ thống...</p>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-100 overflow-hidden">
      <Sidebar 
        user={user} 
        activePage={activePage} 
        onNavigate={setActivePage} 
        onLogout={handleLogout}
        onLoginClick={() => setShowLogin(true)}
        onCollapse={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        isCollapsed={isSidebarCollapsed}
        systemName={systemSettings['system_name']}
        logoUrl={systemSettings['site_logo']}
      />

      <main className="flex-1 relative overflow-hidden h-full">
        {renderContent()}
      </main>

      {showLogin && (
        <Login 
          onLogin={handleLogin} 
          onCancel={() => { setShowLogin(false); window.history.replaceState({}, document.title, window.location.pathname); }}
          systemName={systemSettings['system_name']}
          logoUrl={systemSettings['site_logo']}
          footerText={systemSettings['footer_text']}
          allowRegistration={systemSettings['allow_registration'] === 'true'}
          initialToken={resetToken}
          verificationToken={verificationToken}
        />
      )}
    </div>
  );
};

export default App;

import express from 'express';
import multer from 'multer';
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';
import nodemailer from 'nodemailer';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const upload = multer({ 
    dest: 'uploads/',
    limits: { fileSize: 5 * 1024 * 1024 } // Limit 5MB
});

// Cấu hình Email (Thay bằng thông tin thật của bạn nếu muốn gửi mail thật)
const transporter = nodemailer.createTransport({
    service: 'gmail',
    auth: {
        user: 'your-email@gmail.com', 
        pass: 'your-app-password'
    }
});

export default function(pool, logSystemAction, dbConfig, seedDefaultData) {
    const router = express.Router();

    // --- 1. AUTHENTICATION & PROFILE ---

    router.post('/auth/login', async (req, res) => {
        const { email, password } = req.body;
        try {
            const result = await pool.query(`SELECT * FROM users WHERE email = $1`, [email]);
            const user = result.rows[0];

            if (!user || user.password_hash !== password) { // Lưu ý: Nên dùng bcrypt trong thực tế
                return res.status(401).json({ error: "Email hoặc mật khẩu không đúng." });
            }

            if (user.is_verified === false) {
                return res.status(403).json({ error: "Tài khoản chưa được kích hoạt. Vui lòng kiểm tra email." });
            }

            // Xóa password trước khi trả về
            delete user.password_hash;
            delete user.verification_token;

            await logSystemAction(req, 'LOGIN', `Đăng nhập thành công`, user);
            res.json(user);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/register', async (req, res) => {
        const { name, email, branchId } = req.body;
        const password = '123'; // Mật khẩu mặc định
        const token = crypto.randomBytes(20).toString('hex');

        try {
            // Kiểm tra email tồn tại
            const check = await pool.query(`SELECT id FROM users WHERE email = $1`, [email]);
            if (check.rows.length > 0) return res.status(400).json({ error: "Email đã tồn tại trong hệ thống." });

            const id = 'user_' + Date.now();
            await pool.query(
                `INSERT INTO users (id, email, password_hash, name, role, branch_id, is_verified, verification_token) 
                 VALUES ($1, $2, $3, $4, 'VIEWER', $5, false, $6)`,
                [id, email, password, name, branchId, token]
            );

            // Gửi email giả lập (Log ra console thay vì gửi thật để test local)
            console.log(`[SIMULATED EMAIL] To: ${email} | Link: http://localhost:3003?verify_token=${token}`);

            res.json({ status: 'ok', message: 'Đăng ký thành công. Vui lòng kiểm tra email.' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/verify-email', async (req, res) => {
        const { token } = req.body;
        try {
            const result = await pool.query(`UPDATE users SET is_verified = true, verification_token = NULL WHERE verification_token = $1 RETURNING *`, [token]);
            if (result.rows.length === 0) return res.status(400).json({ error: "Token không hợp lệ hoặc đã hết hạn." });
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/forgot-password', async (req, res) => {
        const { email } = req.body;
        try {
            const userRes = await pool.query(`SELECT id FROM users WHERE email = $1`, [email]);
            if (userRes.rows.length === 0) return res.status(404).json({ error: "Email không tồn tại." });

            const token = crypto.randomBytes(20).toString('hex');
            // Lưu token vào bảng riêng hoặc bảng users (ở đây dùng bảng riêng cho sạch)
            await pool.query(`INSERT INTO password_reset_tokens (email, token, expires_at) VALUES ($1, $2, NOW() + INTERVAL '15 minutes')`, [email, token]);

            console.log(`[SIMULATED RESET EMAIL] To: ${email} | Link: http://localhost:3003?reset_token=${token}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/reset-password', async (req, res) => {
        const { token, newPassword } = req.body;
        try {
            // Kiểm tra token
            const tokenRes = await pool.query(`SELECT email FROM password_reset_tokens WHERE token = $1 AND expires_at > NOW()`, [token]);
            if (tokenRes.rows.length === 0) return res.status(400).json({ error: "Token không hợp lệ hoặc đã hết hạn." });

            const email = tokenRes.rows[0].email;
            await pool.query(`UPDATE users SET password_hash = $1 WHERE email = $2`, [newPassword, email]);
            await pool.query(`DELETE FROM password_reset_tokens WHERE email = $1`, [email]);

            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // Cập nhật Profile (Avatar & Tên)
    router.put('/users/:id/profile', upload.single('avatar'), async (req, res) => {
        const { id } = req.params;
        const { name } = req.body;
        const file = req.file;

        try {
            let avatarUrl = null;
            if (file) {
                // Di chuyển file vào thư mục uploads/avatars (tạo nếu chưa có)
                const avatarDir = path.join(__dirname, 'uploads', 'avatars');
                if (!fs.existsSync(avatarDir)) fs.mkdirSync(avatarDir, { recursive: true });

                const ext = path.extname(file.originalname);
                const filename = `avatar_${id}_${Date.now()}${ext}`;
                const newPath = path.join(avatarDir, filename);

                fs.renameSync(file.path, newPath);
                avatarUrl = `/uploads/avatars/${filename}`; // Đường dẫn tương đối
            }

            let query = `UPDATE users SET name = $1`;
            const params = [name];

            if (avatarUrl) {
                query += `, avatar = $2 WHERE id = $3`;
                params.push(avatarUrl, id);
            } else {
                query += ` WHERE id = $2`;
                params.push(id);
            }

            query += ` RETURNING id, name, avatar, email, role, branch_id as "branchId"`;

            const result = await pool.query(query, params);
            res.json(result.rows[0]);
        } catch (e) { 
            if (file && fs.existsSync(file.path)) fs.unlinkSync(file.path);
            res.status(500).json({ error: e.message }); 
        }
    });

    router.put('/users/:id/change-password', async (req, res) => {
        const { oldPassword, newPassword } = req.body;
        try {
            const check = await pool.query(`SELECT password_hash FROM users WHERE id = $1`, [req.params.id]);
            if (check.rows.length === 0) return res.status(404).json({ error: "User not found" });
            if (check.rows[0].password_hash !== oldPassword) return res.status(400).json({ error: "Mật khẩu cũ không đúng" });

            await pool.query(`UPDATE users SET password_hash = $1 WHERE id = $2`, [newPassword, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- 2. USER MANAGEMENT (ADMIN) ---

    router.get('/users', async (req, res) => { 
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified as "is_verified", avatar FROM users ORDER BY name ASC`); 
            res.json(r.rows); 
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // API QUAN TRỌNG: Lấy thông tin chi tiết 1 user để đồng bộ client
    router.get('/users/:id', async (req, res) => {
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified as "is_verified", avatar FROM users WHERE id = $1`, [req.params.id]);
            if (r.rows.length === 0) return res.status(404).json({ error: "User not found" });
            res.json(r.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/users', async (req, res) => {
        const { name, email, role, branchId, password, is_verified } = req.body;
        try {
            const id = 'user_' + Date.now();
            await pool.query(
                `INSERT INTO users (id, email, password_hash, name, role, branch_id, is_verified) VALUES ($1, $2, $3, $4, $5, $6, $7)`, 
                [id, email, password || '123', name, role, branchId, is_verified]
            );
            await logSystemAction(req, 'ADD_USER', `Thêm người dùng: ${email}`);
            res.json({ status: 'ok', id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/users/:id', async (req, res) => {
        const { name, email, role, branchId, is_verified } = req.body;
        try {
            await pool.query(
                `UPDATE users SET name=$1, email=$2, role=$3, branch_id=$4, is_verified=$5 WHERE id=$6`, 
                [name, email, role, branchId, is_verified, req.params.id]
            );
            await logSystemAction(req, 'UPDATE_USER', `Cập nhật người dùng: ${email}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/users/:id', async (req, res) => {
        try {
            await pool.query(`DELETE FROM users WHERE id=$1`, [req.params.id]);
            await logSystemAction(req, 'DELETE_USER', `Xóa người dùng ID: ${req.params.id}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/users/:id/reset-password', async (req, res) => {
        try {
            await pool.query(`UPDATE users SET password_hash=$1 WHERE id=$2`, [req.body.password, req.params.id]);
            await logSystemAction(req, 'RESET_PASS', `Đặt lại mật khẩu cho user ID: ${req.params.id}`);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- 3. SYSTEM CONFIGURATION ---

    // Branches
