export const API_URL = (() => {
    const { hostname, protocol } = window.location;
    const isLocalOrLan = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');
    if (isLocalOrLan) {
        return `${protocol}//${hostname}:3004`;
    }
    return 'https://apigeo.gisvn.space'; 
})();

const getAuthHeaders = () => {
    const headers: any = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

async function apiCall(endpoint: string, options: RequestInit = {}) {
    const url = `${API_URL}/api${endpoint}`;
    const headers = { ...getAuthHeaders(), ...options.headers };

    // Nếu body là FormData, xoá Content-Type để browser tự set multipart/form-data
    if (options.body instanceof FormData) {
        delete headers['Content-Type'];
    }

    const config = {
        ...options,
        headers
    };

    const res = await fetch(url, config);
    if (!res.ok) {
        const text = await res.text();
        try {
            const json = JSON.parse(text);
            throw new Error(json.error || json.message || `API Error: ${res.status}`);
        } catch (e: any) {
            throw new Error(text || `API Error: ${res.status}`);
        }
    }
    return res.json();
}

