import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { 
    LayoutDashboard, Map, Settings, LogOut, ChevronLeft, ChevronRight, 
    User as UserIcon, Shield, Menu 
} from 'lucide-react';
import { API_URL } from '../services/mockBackend';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  user, activePage, onNavigate, onLogout, onLoginClick, onCollapse, isCollapsed, systemName, logoUrl 
}) => {
  const [imgError, setImgError] = useState(false);

  const getAvatarUrl = (path?: string) => {
      if (!path) return null;
      if (path.startsWith('http') || path.startsWith('data:')) return path;
      const cleanPath = path.startsWith('/') ? path : `/${path}`;
      return `${API_URL}${cleanPath}`;
  };

  const renderAvatar = () => {
      if (!user) return <UserIcon size={18} className="text-blue-400" />;

      const avatarSrc = getAvatarUrl(user.avatar);

      if (avatarSrc && !imgError) {
          return (
              <img 
                  key={user.avatar}
                  src={avatarSrc} 
                  alt={user.name} 
                  className="w-full h-full object-cover" 
                  onError={() => setImgError(true)}
              />
          );
      }

      return (
          <div className="w-full h-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
              {user.name ? user.name.charAt(0) : <UserIcon size={16} />}
          </div>
      );
  };

  const menuItems = [
    { id: 'map', icon: Map, label: 'Bản đồ', public: true },
    { id: 'dashboard', icon: LayoutDashboard, label: 'Bảng điều khiển', public: false },
    { id: 'admin', icon: Shield, label: 'Quản trị hệ thống', public: false, adminOnly: true },
  ];

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-72'} bg-[#0f172a] text-white h-screen flex flex-col transition-all duration-300 ease-in-out border-r border-slate-800 relative z-50 shadow-2xl`}>
      {/* HEADER */}
      <div className={`h-16 flex items-center ${isCollapsed ? 'justify-center' : 'px-6 gap-3'} border-b border-slate-800 bg-[#0f172a]`}>
         {logoUrl ? (
            <img src={logoUrl} alt="Logo" className="w-8 h-8 object-contain" />
         ) : (
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center shrink-0">
               <Map size={18} className="text-white" />
            </div>
         )}

         {!isCollapsed && (
            <span className="font-bold text-lg tracking-tight whitespace-nowrap overflow-hidden text-ellipsis">
               {systemName || 'GeoMaster'}
            </span>
         )}
      </div>

      {/* USER PROFILE SECTION */}
      <div className="p-4 border-b border-slate-800">
         {user ? (
            <div className={`flex items-center gap-3 ${isCollapsed ? 'justify-center' : ''}`}>
               <div className="w-10 h-10 rounded-full overflow-hidden border-2 border-slate-700 shrink-0 cursor-pointer" onClick={() => onNavigate('profile')}>
                  {renderAvatar()}
               </div>
               {!isCollapsed && (
                  <div className="flex flex-col overflow-hidden">
                     <span className="font-bold text-sm truncate">{user.name}</span>
                     <span className="text-[10px] text-slate-400 truncate uppercase">{user.role}</span>
                  </div>
               )}
            </div>
         ) : (
             <button 
                onClick={onLoginClick}
                className={`w-full py-2 bg-blue-600 hover:bg-blue-500 rounded-lg text-xs font-bold uppercase transition-all flex items-center justify-center gap-2 ${isCollapsed ? 'px-0' : ''}`}
             >
                <UserIcon size={16} /> {!isCollapsed && "Đăng nhập"}
             </button>
         )}
      </div>

      {/* NAVIGATION */}
      <nav className="flex-1 py-4 px-3 space-y-1 overflow-y-auto custom-scrollbar">
         {menuItems.map(item => {
            if (!item.public && !user) return null;
            if (item.adminOnly && user?.role !== UserRole.ADMIN) return null;

            const isActive = activePage === item.id;
            return (
               <button
                  key={item.id}
                  onClick={() => onNavigate(item.id)}
                  className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all duration-200 group relative ${
                     isActive 
                     ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
                     : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                  } ${isCollapsed ? 'justify-center' : ''}`}
                  title={isCollapsed ? item.label : ''}
               >
                  <item.icon size={20} className={isActive ? 'animate-pulse' : 'group-hover:scale-110 transition-transform'} />
                  {!isCollapsed && <span className="text-sm font-medium">{item.label}</span>}
                  {isCollapsed && isActive && <div className="absolute right-1 w-1.5 h-1.5 bg-white rounded-full"></div>}
               </button>
            );
         })}
      </nav>

      {/* FOOTER */}
      <div className="p-4 border-t border-slate-800">
         {user && (
             <button 
                onClick={onLogout}
                className={`w-full flex items-center gap-3 p-3 rounded-xl text-slate-400 hover:bg-red-900/20 hover:text-red-400 transition-all ${isCollapsed ? 'justify-center' : ''}`}
                title="Đăng xuất"
             >
                <LogOut size={20} />
                {!isCollapsed && <span className="text-sm font-bold">Đăng xuất</span>}
             </button>
         )}
         <button 
            onClick={onCollapse}
            className="absolute -right-3 top-1/2 -translate-y-1/2 bg-blue-600 text-white p-1 rounded-full shadow-lg hover:bg-blue-500 transition-colors z-[100] hidden md:flex"
         >
            {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
         </button>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { authService, API_URL } from '../services/mockBackend';
import { User as UserIcon, Save, Key, Upload, Loader2, CheckCircle2, AlertTriangle, RefreshCw } from 'lucide-react';

interface UserProfileProps {
    user: User;
    onUpdateUser: (updatedUser: User) => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ user, onUpdateUser }) => {
    const [name, setName] = useState(user.name);
    const [selectedFile, setSelectedFile] = useState<File | null>(null);
    const [avatarPreview, setAvatarPreview] = useState<string | null>(null);

    // Password change state
    const [oldPassword, setOldPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');

    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

    useEffect(() => {
        if (user.avatar) {
            if (user.avatar.startsWith('http') || user.avatar.startsWith('data:')) {
                setAvatarPreview(user.avatar);
            } else {
                setAvatarPreview(`${API_URL}${user.avatar}`);
            }
        }
    }, [user.avatar]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const file = e.target.files[0];
            setSelectedFile(file);
            const reader = new FileReader();
            reader.onloadend = () => {
                setAvatarPreview(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleUpdateProfile = async () => {
        setLoading(true);
        setMessage(null);
        try {
            const result = await authService.updateProfile(user.id, name, selectedFile);
            const newAvatarUrl = result.avatar || user.avatar;
            onUpdateUser({ ...user, name, avatar: newAvatarUrl });

            if (result.avatar) {
                setAvatarPreview(`${API_URL}${result.avatar}?t=${Date.now()}`);
                setSelectedFile(null);
            }

            setMessage({ type: 'success', text: 'Cập nhật hồ sơ thành công!' });
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message || 'Lỗi cập nhật hồ sơ' });
        } finally {
            setLoading(false);
        }
    };

    const handleChangePassword = async (e: React.FormEvent) => {
        e.preventDefault();
        setMessage(null);

        if (newPassword !== confirmPassword) {
            setMessage({ type: 'error', text: 'Mật khẩu xác nhận không khớp.' });
            return;
        }

        if (newPassword.length < 6) {
            setMessage({ type: 'error', text: 'Mật khẩu phải từ 6 ký tự.' });
            return;
        }

        setLoading(true);
        try {
            await authService.changePassword(user.id, oldPassword, newPassword);
            setMessage({ type: 'success', text: 'Đổi mật khẩu thành công.' });
            setOldPassword('');
            setNewPassword('');
            setConfirmPassword('');
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message || 'Lỗi đổi mật khẩu.' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="p-8 h-full overflow-y-auto bg-gray-50">
            <div className="max-w-3xl mx-auto space-y-8">
                <div>
                    <h1 className="text-2xl font-black text-gray-900 uppercase tracking-tight mb-2">Hồ sơ cá nhân</h1>
                    <p className="text-gray-500 text-sm">Quản lý thông tin tài khoản và bảo mật</p>
                </div>

                {message && (
                    <div className={`p-4 rounded-xl flex items-center gap-3 ${message.type === 'success' ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
                        {message.type === 'success' ? <CheckCircle2 size={20} /> : <AlertTriangle size={20} />}
                        <span className="font-bold text-sm">{message.text}</span>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    {/* Left Col: Avatar & Basic Info */}
                    <div className="md:col-span-1 space-y-6">
                        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200 flex flex-col items-center">
                            <div className="relative w-32 h-32 rounded-full overflow-hidden border-4 border-gray-100 shadow-inner mb-4 group">
                                {avatarPreview ? (
                                    <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover" />
                                ) : (
                                    <div className="w-full h-full bg-blue-100 flex items-center justify-center text-blue-500">
                                        <UserIcon size={48} />
                                    </div>
                                )}
                                <label className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white flex-col gap-1">
                                    <Upload size={24} />
                                    <span className="text-[10px] font-bold uppercase">Đổi ảnh</span>
                                    <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
                                </label>
                            </div>
                            <h3 className="font-bold text-lg text-gray-900">{user.name}</h3>
                            <p className="text-xs text-gray-500 uppercase font-bold tracking-wider">{user.role} • {user.branchId}</p>
                        </div>
                    </div>

                    {/* Right Col: Forms */}
                    <div className="md:col-span-2 space-y-6">
                        {/* Edit Profile */}
                        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                            <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                                <UserIcon size={18} className="text-blue-500" /> Thông tin chung
                            </h3>
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Email (Tên đăng nhập)</label>
                                    <input type="email" value={user.email} disabled className="w-full bg-gray-100 border border-gray-200 rounded-xl p-3 text-gray-500 font-medium cursor-not-allowed" />
                                </div>
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Họ và tên</label>
                                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full bg-white border border-gray-300 rounded-xl p-3 text-gray-900 font-medium focus:border-blue-500 outline-none transition-colors" />
                                </div>
                                <div className="pt-2">
                                    <button 
                                        onClick={handleUpdateProfile} 
                                        disabled={loading}
                                        className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-lg shadow-blue-200 flex items-center gap-2 transition-all disabled:opacity-50"
                                    >
                                        {loading ? <Loader2 className="animate-spin" size={18} /> : <Save size={18} />}
                                        Lưu thay đổi
                                    </button>
                                </div>
                            </div>
                        </div>

                        {/* Change Password */}
                        <form onSubmit={handleChangePassword} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                            <h3 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                                <Key size={18} className="text-orange-500" /> Đổi mật khẩu
                            </h3>
                            <div className="space-y-4">
                                <div>
                                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Mật khẩu hiện tại</label>
                                    <input type="password" value={oldPassword} onChange={(e) => setOldPassword(e.target.value)} className="w-full bg-white border border-gray-300 rounded-xl p-3 text-gray-900 outline-none focus:border-orange-500 transition-colors" required />
                                </div>
                                <div className="grid grid-cols-2 gap-4">
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Mật khẩu mới</label>
                                        <input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} className="w-full bg-white border border-gray-300 rounded-xl p-3 text-gray-900 outline-none focus:border-orange-500 transition-colors" required minLength={6} />
                                    </div>
                                    <div>
                                        <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Xác nhận mật khẩu mới</label>
                                        <input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full bg-white border border-gray-300 rounded-xl p-3 text-gray-900 outline-none focus:border-orange-500 transition-colors" required minLength={6} />
                                    </div>
                                </div>
                                <div className="pt-2">
                                    <button 
                                        type="submit" 
                                        disabled={loading}
                                        className="bg-white border border-gray-300 text-gray-700 hover:bg-gray-50 hover:text-orange-600 px-6 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2 transition-all disabled:opacity-50"
                                    >
                                        {loading ? <Loader2 className="animate-spin" size={18} /> : <RefreshCw size={18} />}
                                        Cập nhật mật khẩu
                                    </button>
                                </div>
                            </div>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default UserProfile;

import express from 'express';
import multer from 'multer';
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';
import nodemailer from 'nodemailer';
import os from 'os';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// CẤU HÌNH MULTER CHO UPLOAD AVATAR
const storage = multer.diskStorage({
    destination: function (req, file, cb) {
        const uploadPath = path.join(__dirname, 'uploads');
        if (!fs.existsSync(uploadPath)) {
            fs.mkdirSync(uploadPath, { recursive: true });
        }
        cb(null, uploadPath);
    },
    filename: function (req, file, cb) {
        const userId = req.params.id || 'unknown';
        const uniqueSuffix = Date.now();
        const ext = path.extname(file.originalname);
        cb(null, `avatar-${userId}-${uniqueSuffix}${ext}`);
    }
});

const upload = multer({ 
    storage: storage,
    limits: { fileSize: 5 * 1024 * 1024 } // Giới hạn 5MB
});

// CẤU HÌNH EMAIL (Sử dụng cho tính năng Quên mật khẩu & Kích hoạt)
