export default function(pool, logSystemAction, dbConfig, seedDefaultData) {
    const router = express.Router();

    // --- 1. AUTHENTICATION (Đăng nhập, Đăng ký, Xác thực) ---

    router.post('/auth/login', async (req, res) => {
        const { email, password } = req.body;
        try {
            const result = await pool.query(`SELECT * FROM users WHERE email = $1`, [email]);
            const user = result.rows[0];

            if (!user || user.password_hash !== password) {
                return res.status(401).json({ error: "Email hoặc mật khẩu không đúng." });
            }

            if (user.is_verified === false) {
                return res.status(403).json({ error: "Tài khoản chưa kích hoạt. Vui lòng kiểm tra email." });
            }

            const userData = {
                id: user.id,
                email: user.email,
                name: user.name,
                role: user.role,
                branchId: user.branch_id,
                avatar: user.avatar
            };

            await logSystemAction(req, 'LOGIN', `Đăng nhập thành công`, userData);
            res.json(userData);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/register', async (req, res) => {
        const { name, email, branchId } = req.body;
        const password = '123';
        const token = crypto.randomBytes(20).toString('hex');

        try {
            const check = await pool.query(`SELECT id FROM users WHERE email = $1`, [email]);
            if (check.rows.length > 0) return res.status(400).json({ error: "Email đã tồn tại." });

            const id = 'u-' + Date.now();
            await pool.query(
                `INSERT INTO users (id, email, password_hash, name, role, branch_id, is_verified, verification_token) 
                 VALUES ($1, $2, $3, $4, 'VIEWER', $5, false, $6)`,
                [id, email, password, name, branchId, token]
            );

            // Gửi mail thực tế
            const origin = req.headers.origin || 'https://geo.gisvn.space';
            const verifyLink = `${origin}/?verificationToken=${token}`;

            try {
                await transporter.sendMail({
                    from: '"GISVN System" <thaith.bd@gmail.com>',
                    to: email,
                    subject: '[GISVN] Xác thực tài khoản',
                    html: `<p>Chào ${name},</p><p>Click vào link sau để kích hoạt: <a href="${verifyLink}">${verifyLink}</a></p>`
                });
            } catch (mErr) { console.warn("Mail error:", mErr.message); }

            res.json({ status: 'ok', message: 'Vui lòng kiểm tra email để kích hoạt.' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/verify-email', async (req, res) => {
        const { token } = req.body;
        try {
            const result = await pool.query(`UPDATE users SET is_verified = true, verification_token = NULL WHERE verification_token = $1 RETURNING id`, [token]);
            if (result.rows.length === 0) return res.status(400).json({ error: "Token không hợp lệ." });
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/forgot-password', async (req, res) => {
        const { email } = req.body;
        try {
            const userCheck = await pool.query(`SELECT id FROM users WHERE email = $1`, [email]);
            if (userCheck.rows.length === 0) return res.status(404).json({ error: "Email không tồn tại." });

            const token = crypto.randomBytes(32).toString('hex');
            const expires = new Date(Date.now() + 15 * 60 * 1000); 
            await pool.query(`INSERT INTO password_reset_tokens (email, token, expires_at) VALUES ($1, $2, $3)`, [email, token, expires]);

            const origin = req.headers.origin || 'https://geo.gisvn.space';
            const resetLink = `${origin}/?token=${token}`;

            try {
                await transporter.sendMail({
                    from: '"GISVN Support" <thaith.bd@gmail.com>',
                    to: email,
                    subject: '[GISVN] Khôi phục mật khẩu',
                    html: `<p>Nhấp vào đây để đổi mật khẩu: <a href="${resetLink}">${resetLink}</a></p>`
                });
            } catch (mErr) { console.warn("Mail error:", mErr.message); }
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/auth/reset-password', async (req, res) => {
        const { token, newPassword } = req.body;
        try {
            const tokenRes = await pool.query(`SELECT * FROM password_reset_tokens WHERE token = $1 AND expires_at > NOW()`, [token]);
            if (tokenRes.rows.length === 0) return res.status(400).json({ error: "Token hết hạn hoặc sai." });

            const email = tokenRes.rows[0].email;
            await pool.query(`UPDATE users SET password_hash = $1 WHERE email = $2`, [newPassword, email]);
            await pool.query(`DELETE FROM password_reset_tokens WHERE email = $1`, [email]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- 2. USER & PROFILE MANAGEMENT ---

    // Cập nhật Profile (Dùng cho máy khách)
    router.put('/users/:id/profile', upload.single('avatar'), async (req, res) => {
        const { id } = req.params;
        const { name } = req.body;
        try {
            let avatarUrl = null;
            if (req.file) {
                avatarUrl = `/uploads/${req.file.filename}`;
            }

            let query = `UPDATE users SET name = $1`;
            const params = [name];

            if (avatarUrl) {
                query += `, avatar = $2 WHERE id = $3`;
                params.push(avatarUrl, id);
            } else {
                query += ` WHERE id = $2`;
                params.push(id);
            }

            query += ` RETURNING id, name, avatar, email, role, branch_id as "branchId"`;

            const result = await pool.query(query, params);
            await logSystemAction(req, 'UPDATE_PROFILE', `Cập nhật hồ sơ user: ${id}`);
            res.json(result.rows[0]);
        } catch (e) { 
            res.status(500).json({ error: e.message }); 
        }
    });

    router.get('/users', async (req, res) => { 
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified as "is_verified", avatar FROM users ORDER BY name ASC`); 
            res.json(r.rows); 
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // API QUAN TRỌNG: Đồng bộ dữ liệu giữa các máy
    router.get('/users/:id', async (req, res) => {
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified as "is_verified", avatar FROM users WHERE id = $1`, [req.params.id]);
            if (r.rows.length === 0) return res.status(404).json({ error: "User not found" });
            res.set('Cache-Control', 'no-store'); // Chống cache máy khách
            res.json(r.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.post('/users', async (req, res) => {
        const { name, email, role, branchId, password, is_verified } = req.body;
        const id = 'u-' + Date.now();
        try {
            await pool.query(
                `INSERT INTO users (id, email, password_hash, name, role, branch_id, is_verified) VALUES ($1, $2, $3, $4, $5, $6, $7)`, 
                [id, email, password || '123', name, role, branchId, is_verified ?? true]
            );
            await logSystemAction(req, 'ADD_USER', `Thêm user bởi admin: ${email}`);
            res.json({ status: 'ok', id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/users/:id', async (req, res) => {
        const { name, email, role, branchId, is_verified } = req.body;
        try {
            await pool.query(
                `UPDATE users SET name=$1, email=$2, role=$3, branch_id=$4, is_verified=$5 WHERE id=$6`, 
                [name, email, role, branchId, is_verified, req.params.id]
            );
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.delete('/users/:id', async (req, res) => {
        try {
            await pool.query(`DELETE FROM users WHERE id=$1`, [req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/users/:id/change-password', async (req, res) => {
        const { oldPassword, newPassword } = req.body;
        try {
            const check = await pool.query(`SELECT password_hash FROM users WHERE id = $1`, [req.params.id]);
            if (check.rows[0].password_hash !== oldPassword) return res.status(400).json({ error: "Mật khẩu cũ không đúng" });
            await pool.query(`UPDATE users SET password_hash = $1 WHERE id = $2`, [newPassword, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.put('/users/:id/reset-password', async (req, res) => {
        try {
            await pool.query(`UPDATE users SET password_hash=$1 WHERE id=$2`, [req.body.password, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- 3. CẤU HÌNH CHI NHÁNH & GIÁ ĐẤT ---

    router.get('/branches', async (req, res) => {
        try { res.json((await pool.query(`SELECT * FROM branches ORDER BY name`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/branches', async (req, res) => {
        try {
            const id = 'br-' + Date.now();
            await pool.query(`INSERT INTO branches (id, code, name, address) VALUES ($1, $2, $3, $4)`, [id, req.body.code, req.body.name, req.body.address]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.put('/branches/:id', async (req, res) => {
        try {
            await pool.query(`UPDATE branches SET code=$1, name=$2, address=$3 WHERE id=$4`, [req.body.code, req.body.name, req.body.address, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.delete('/branches/:id', async (req, res) => {
        try { await pool.query(`DELETE FROM branches WHERE id=$1`, [req.params.id]); res.json({ status: 'ok' }); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    router.get('/land-prices', async (req, res) => {
        try { res.json((await pool.query(`SELECT land_type as "landType", base_price as "basePrice", description FROM land_prices`)).rows); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.post('/land-prices', async (req, res) => {
        try { await pool.query(`INSERT INTO land_prices VALUES ($1, $2, $3)`, [req.body.landType, req.body.basePrice, req.body.description]); res.json({ status: 'ok' }); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.put('/land-prices/:id', async (req, res) => {
        try { await pool.query(`UPDATE land_prices SET base_price=$1, description=$2 WHERE land_type=$3`, [req.body.basePrice, req.body.description, req.params.id]); res.json({ status: 'ok' }); } catch (e) { res.status(500).json({ error: e.message }); }
    });
    router.delete('/land-prices/:id', async (req, res) => {
        try { await pool.query(`DELETE FROM land_prices WHERE land_type=$1`, [req.params.id]); res.json({ status: 'ok' }); } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- 4. CẤU HÌNH BẢN ĐỒ & LAYER (WMS, Basemaps, Permissions) ---

    router.get('/wms-layers', async (req, res) => {
