import { User, UserRole, Branch, LandParcel, DashboardStats, SystemLog, LandPriceConfig, WMSLayerConfig, BasemapConfig, SystemSetting, RoleConfig } from '../types';

/**
 * Determine the API Base URL based on the current environment.
 */
const getApiUrl = () => {
    const { hostname, protocol } = window.location;
    const isLocalOrLan = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');
    return isLocalOrLan ? `${protocol}//${hostname}:3004` : 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

/**
 * Helper to get authentication headers from localStorage.
 */
const getAuthHeaders = () => {
    const headers: any = { 'Content-Type': 'application/json' };
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

/**
 * Core API caller with unified error handling.
 */
const apiCall = async (endpoint: string, options: any = {}) => {
    const headers = { ...getAuthHeaders(), ...options.headers };
    if (options.body instanceof FormData) {
        delete headers['Content-Type'];
    }
    const res = await fetch(`${API_URL}/api${endpoint}`, { ...options, headers });
    if (!res.ok) {
        const err = await res.json().catch(() => ({ error: 'Unknown server error' }));
        throw new Error(err.error || err.message || `API Error ${res.status}`);
    }
    return res.json();
};

