import React, { useState, useEffect } from 'react';
import { User } from './types';
import { authService } from './services/mockBackend';
import Dashboard from './pages/Dashboard';
import MapPage from './pages/MapPage';
import AdminPage from './pages/AdminPage';
import UserProfile from './pages/UserProfile';
import Login from './pages/Login';
import Sidebar from './components/Sidebar';

/**
 * Main Application Component
 */
const App: React.FC = () => {
    const [user, setUser] = useState<User | null>(null);
    const [activePage, setActivePage] = useState('dashboard');
    const [loading, setLoading] = useState(true);

    // Sync user data with server on mount
    useEffect(() => {
        const init = async () => {
            const savedUser = localStorage.getItem('geo_user');
            if (savedUser) {
                const parsed = JSON.parse(savedUser);
                setUser(parsed);
                try {
                    const freshUser = await authService.getProfile(parsed.id);
                    if (freshUser) {
                        const mergedUser = { ...parsed, ...freshUser };
                        setUser(mergedUser);
                        localStorage.setItem('geo_user', JSON.stringify(mergedUser));
                    }
                } catch (syncErr) {
                    console.warn("Không thể đồng bộ thông tin mới (Offline/Server Error)");
                }
            }
            setLoading(false);
        };
        init();
    }, []);

    const handleLogin = (u: User) => {
        setUser(u);
        localStorage.setItem('geo_user', JSON.stringify(u));
    };

    const handleLogout = () => {
        setUser(null);
        localStorage.removeItem('geo_user');
    };

    if (loading) return (
        <div className="h-screen w-full flex items-center justify-center bg-gray-950 text-white font-bold">
            Đang khởi tạo hệ thống...
        </div>
    );

    if (!user) return (
        <Login 
            onLogin={handleLogin} 
            onCancel={() => {}} 
            systemName="GeoMaster GIS"
            allowRegistration={true}
        />
    );

    const renderPage = () => {
        switch (activePage) {
            case 'dashboard': return <Dashboard user={user} />;
            case 'map': return <MapPage user={user} />;
            case 'admin': return <AdminPage />;
            case 'profile': return <UserProfile user={user} onUpdateUser={setUser} />;
            default: return <Dashboard user={user} />;
        }
    };

    return (
        <div className="flex h-screen w-full bg-gray-950 overflow-hidden">
            <Sidebar 
                user={user} 
                activePage={activePage} 
                onPageChange={setActivePage} 
                onLogout={handleLogout} 
            />
            <div className="flex-1 overflow-hidden">
                {renderPage()}
            </div>
        </div>
    );
};

export default App;

