export default function(pool, logSystemAction, transporter) {
    const router = express.Router();

    // --- LOGIN ---
    router.post('/login', async (req, res) => {
        const { email, password } = req.body;
        try {
            const result = await pool.query(`SELECT * FROM users WHERE email = $1`, [email]);
            const user = result.rows[0];

            if (!user || user.password_hash !== password) {
                return res.status(401).json({ error: "Email hoặc mật khẩu không đúng." });
            }

            if (user.is_verified === false) {
                return res.status(403).json({ error: "Tài khoản chưa kích hoạt. Vui lòng kiểm tra email." });
            }

            const userData = {
                id: user.id, email: user.email, name: user.name,
                role: user.role, branchId: user.branch_id, avatar: user.avatar
            };

            await logSystemAction(req, 'LOGIN', `Đăng nhập thành công`, userData);
            res.json(userData);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- REGISTER ---
    router.post('/register', async (req, res) => {
        const { name, email, branchId } = req.body;
        const password = '123';
