            await pool.query(
                `INSERT INTO users (id, email, password_hash, name, role, branch_id, is_verified) VALUES ($1, $2, $3, $4, $5, $6, $7)`, 
                [id, email, password || '123', name, role, branchId, is_verified ?? true]
            );
            res.json({ status: 'ok', id });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- ADMIN: UPDATE USER ---
    router.put('/:id', async (req, res) => {
        const { name, email, role, branchId, is_verified } = req.body;
        try {
            await pool.query(
                `UPDATE users SET name=$1, email=$2, role=$3, branch_id=$4, is_verified=$5 WHERE id=$6`, 
                [name, email, role, branchId, is_verified, req.params.id]
            );
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

