import { User, UserRole, Branch, LandParcel, DashboardStats, SystemLog, LandPriceConfig, WMSLayerConfig, SystemSetting, RoleConfig, PermissionDefinition, BasemapConfig, MenuItem } from '../types';

/**
 * Tự động xác định URL của API dựa trên địa chỉ trình duyệt.
 * Đảm bảo khi truy cập từ IP LAN (192.168.x.x) thì API cũng trỏ về đó thay vì localhost.
 */
const getApiUrl = () => {
    const { hostname, protocol } = window.location;

    // Nếu truy cập qua tên miền chính thức
    if (hostname === 'geo.gisvn.space' || hostname === 'www.geo.gisvn.space') {
        return 'https://apigeo.gisvn.space';
    }

    // Nếu truy cập qua IP hoặc localhost, tự động trỏ về port 3004 của máy đó
    return `${protocol}//${hostname}:3004`;
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    const cleanEndpoint = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;
    const finalUrl = `${API_URL}${cleanEndpoint}`;

    try {
        const headers: any = { 'Content-Type': 'application/json', ...getAuthHeaders(), ...options?.headers };
        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        if (!res.ok) {
            const errorData = await res.json().catch(() => ({}));
            throw new Error(errorData.error || errorData.message || `Lỗi ${res.status}`);
        }
        return res.json();
    } catch (error: any) {
        throw error;
    }
};

export const gisService = {
    getLayers: async (): Promise<WMSLayerConfig[]> => apiCall('/wms-layers').catch(() => []),
    getBasemaps: async (): Promise<BasemapConfig[]> => apiCall('/basemaps').catch(() => []),
    getSpatialTables: async (): Promise<any[]> => apiCall('/spatial-tables').catch(() => []),
    searchParcels: async (tableName: string, filters: any): Promise<LandParcel[]> => {
        let queryString = `?t=${Date.now()}`;
        if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
        if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
        if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
        if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
        const data = await apiCall(`/data/${tableName}${queryString}`);
        return (data || []).map((item: any) => ({
            id: item.gid?.toString(),
            gid: item.gid,
            geometry: item.geometry,
            properties: { ...item, so_to: item.sodoto, so_thua: item.sothua, ownerName: item.tenchu, area: item.dientich, landType: item.loaidat }
        }));
    }
};

