  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    user, 
    activePage, 
    onNavigate, 
    onLogout, 
    onLoginClick, 
    onCollapse, 
    isCollapsed,
    systemName, 
    logoUrl 
}) => {
  const [dynamicMenu, setDynamicMenu] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [imgError, setImgError] = useState(false);

  // Quan trọng: Reset lỗi ảnh khi avatar user thay đổi
  useEffect(() => {
      setImgError(false);
  }, [user?.avatar]);

  useEffect(() => {
      const fetchMenu = async () => {
          try {
              if (adminService && typeof adminService.getMenuItems === 'function') {
                  const items = await adminService.getMenuItems();
                  setDynamicMenu(items.filter(i => i.is_active).sort((a, b) => a.order_index - b.order_index));
              }
          } catch (e) {
              console.error("Failed to load sidebar menu", e);
          } finally {
              setLoading(false);
          }
      };
      fetchMenu();
  }, [user]);

  const visibleItems = dynamicMenu.filter(item => {
    if (!user) return item.roles.includes('GUEST');
    return item.roles.includes(user.role);
  });

  const handleMenuClick = (item: MenuItem) => {
      if (item.type === 'EXTERNAL' && item.url) {
          window.open(item.url, '_blank');
      } else {
          onNavigate(item.id);
      }
  };

  /**
   * Tạo URL ảnh tuyệt đối. 
   * Nếu user.avatar là "/uploads/abc.png", API_URL là "http://1.2.3.4:3004"
   * Kết quả: "http://1.2.3.4:3004/uploads/abc.png?v=timestamp"
   */
  const getAvatarUrl = (path?: string) => {
      if (!path) return null;
      if (path.startsWith('http') || path.startsWith('data:')) return path;
      const cleanPath = path.startsWith('/') ? path : `/${path}`;
      // Thêm version để trình duyệt không dùng ảnh cũ từ cache
      return `${API_URL}${cleanPath}?v=${new Date().getTime()}`;
  };

  const renderAvatar = () => {
      if (!user) return <UserIcon size={18} className="text-blue-400" />;

      const avatarSrc = getAvatarUrl(user.avatar);

      if (avatarSrc && !imgError) {
          return (
              <img 
                  src={avatarSrc} 
                  alt={user.name} 
                  className="w-full h-full object-cover" 
                  onError={() => {
                      console.warn("Avatar load failed:", avatarSrc);
                      setImgError(true);
                  }}
              />
          );
      }

      return (
          <div className="w-full h-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
              {user.name ? user.name.charAt(0) : <UserIcon size={16} />}
          </div>
      );
  };

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-72'} bg-[#0f172a] text-white h-screen flex flex-col transition-all duration-300 ease-in-out border-r border-slate-800 relative z-50 shadow-2xl`}>
      <button 
        onClick={onCollapse} 
        className="absolute -right-3 top-10 bg-blue-600 text-white rounded-full p-1.5 shadow-lg border-2 border-[#0f172a] hover:bg-blue-500 transition-all z-[60]"
      >
        {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
      </button>

      <div className={`p-6 border-b border-slate-800/80 flex flex-col items-center ${isCollapsed ? 'justify-center' : 'items-start'}`}>
        <div className="flex items-center gap-3.5">
            {logoUrl ? (
                <img src={logoUrl} alt="Logo" className="w-9 h-9 object-contain drop-shadow-[0_0_15px_rgba(59,130,246,0.6)]" />
            ) : (
                <div className="w-9 h-9 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/50">
                    <Database className="w-5 h-5 text-white" />
                </div>
            )}
            {!isCollapsed && (
                <div className="animate-in fade-in slide-in-from-left-2 duration-300">
                    <h1 className="text-base font-black text-white leading-none uppercase tracking-tighter mb-1">
                        {systemName || 'GeoMaster'}
                    </h1>
                    <div className="flex items-center gap-1.5">
                        <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                        <p className="text-[9px] text-slate-400 font-bold tracking-[0.2em] uppercase">Enterprise</p>
                    </div>
                </div>
            )}
        </div>
      </div>

      <div className="flex-1 py-6 space-y-1.5 overflow-y-auto custom-scrollbar no-scrollbar px-3">
        {loading ? (
            <div className="animate-pulse flex flex-col gap-3 px-2">
                {[1,2,3].map(i => <div key={i} className="h-11 bg-slate-800/50 rounded-xl w-full"></div>)}
            </div>
        ) : visibleItems.map(item => {
          const isActive = activePage === item.id;
          const IconComponent = (Icons as any)[item.icon] || HelpCircle;

          return (
            <button
              key={item.id}
              onClick={() => handleMenuClick(item)}
              title={isCollapsed ? item.label : ''}
              className={`w-full flex items-center gap-3.5 px-4 py-3 rounded-xl transition-all relative group overflow-hidden ${
                isActive 
                  ? 'text-white bg-blue-600 shadow-lg shadow-blue-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800/80'
              }`}
            >
              <div className={`${isCollapsed ? 'mx-auto' : ''} transition-transform group-hover:scale-110 flex items-center z-10`}>
                <IconComponent size={20} className={isActive ? 'text-white' : 'text-slate-400 group-hover:text-blue-400'} />
              </div>

              {!isCollapsed && (
                <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-2 duration-300 z-10">
                    <span className={`font-bold text-xs uppercase tracking-wide ${isActive ? 'text-white' : ''}`}>
                        {item.label}
                    </span>
                    {item.type === 'EXTERNAL' && (
                        <ExternalLink size={12} className="text-slate-500 group-hover:text-white transition-colors" />
                    )}
                </div>
              )}
            </button>
          );
        })}
      </div>

      <div className="p-4 border-t border-slate-800/80 bg-slate-900/50 backdrop-blur-sm">
        {user ? (
          <div className="flex flex-col gap-3">
            {!isCollapsed ? (
              <div 
                onClick={() => onNavigate('profile')}
                className="flex items-center gap-3.5 p-2.5 rounded-xl cursor-pointer hover:bg-slate-800 transition-all group border border-transparent hover:border-slate-700/50"
                title="Cập nhật hồ sơ"
              >
                  <div className="w-10 h-10 rounded-full border-2 border-slate-700 group-hover:border-blue-500 overflow-hidden shrink-0 shadow-lg transition-all">
                    {renderAvatar()}
                  </div>
                  <div className="overflow-hidden flex-1">
                      <p className="text-xs font-black text-white truncate group-hover:text-blue-400 transition-colors">
                          {user.name}
                      </p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mt-0.5 flex items-center gap-1">
                          <span className={`w-1.5 h-1.5 rounded-full ${user.role === 'ADMIN' ? 'bg-orange-500' : 'bg-blue-500'}`}></span>
                          {user.role}
                      </p>
                  </div>
              </div>
            ) : (
                 <div 
                    onClick={() => onNavigate('profile')} 
                    className="w-10 h-10 mx-auto rounded-full border-2 border-slate-700 hover:border-blue-500 overflow-hidden cursor-pointer mb-3 shadow-lg transition-all"
                    title={user.name}
                 >
                    {renderAvatar()}
                 </div>
            )}

            <button 
              onClick={onLogout}
              title={isCollapsed ? "Đăng xuất" : ""}
              className={`flex items-center gap-3 px-4 py-2.5 bg-red-500/10 text-red-400 rounded-xl hover:bg-red-500 hover:text-white transition-all border border-red-500/10 hover:border-red-500 ${isCollapsed ? 'justify-center' : ''}`}
            >
              <LogOut size={18} />
              {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng xuất</span>}
            </button>
          </div>
        ) : (
          <button 
            onClick={onLoginClick}
            className="w-full flex items-center gap-2 px-4 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all shadow-lg shadow-blue-900/30 group"
          >
            <LogIn size={18} className="group-hover:-translate-x-0.5 transition-transform" />
            {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng nhập</span>}
          </button>
        )}
      </div>
    </div>
  );
};

export default Sidebar;

import express from 'express';
import multer from 'multer';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Thư mục upload tuyệt đối trên VPS
const uploadPath = path.join(__dirname, 'uploads');
if (!fs.existsSync(uploadPath)) fs.mkdirSync(uploadPath, { recursive: true });

// Cấu hình lưu trữ Avatar
const storage = multer.diskStorage({
    destination: function (req, file, cb) {
        cb(null, uploadPath);
    },
    filename: function (req, file, cb) {
        const userId = req.params.id || 'unknown';
        const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
        cb(null, `avatar-${userId}-${uniqueSuffix}${path.extname(file.originalname)}`);
    }
});
const upload = multer({ storage: storage, limits: { fileSize: 5 * 1024 * 1024 } });

export default function(pool, logSystemAction) {
    const router = express.Router();

    // --- LẤY DANH SÁCH USER ---
    router.get('/', async (req, res) => { 
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified, avatar FROM users ORDER BY name ASC`); 
            res.json(r.rows); 
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- LẤY CHI TIẾT USER (DÙNG ĐỂ ĐỒNG BỘ) ---
    router.get('/:id', async (req, res) => {
        try {
            const r = await pool.query(`SELECT id, email, name, role, branch_id as "branchId", is_verified, avatar FROM users WHERE id = $1`, [req.params.id]);
            if (r.rows.length === 0) return res.status(404).json({ error: "User not found" });
            // Quan trọng: Gửi header chống cache cho API profile
            res.set('Cache-Control', 'no-store, no-cache, must-revalidate, private'); 
            res.json(r.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- CẬP NHẬT HỒ SƠ & AVATAR (XÓA FILE CŨ ĐỂ TIẾT KIỆM) ---
    router.put('/:id/profile', upload.single('avatar'), async (req, res) => {
        const { id } = req.params;
        const { name } = req.body;
        try {
            // 1. Tìm đường dẫn file cũ trong DB
            const userRes = await pool.query(`SELECT avatar FROM users WHERE id = $1`, [id]);
            const oldAvatarUrl = userRes.rows[0]?.avatar;

            let avatarUrl = null;
            if (req.file) {
                avatarUrl = `/uploads/${req.file.filename}`;

                // 2. Nếu có ảnh cũ, tiến hành xóa file vật lý trên ổ đĩa VPS
                if (oldAvatarUrl && oldAvatarUrl.startsWith('/uploads/')) {
                    const fileName = path.basename(oldAvatarUrl);
                    const oldFilePath = path.join(uploadPath, fileName);

                    if (fs.existsSync(oldFilePath)) {
                        try {
                            fs.unlinkSync(oldFilePath);
                            console.log(`[VPS] Deleted old avatar file: ${oldFilePath}`);
                        } catch (err) {
                            console.error(`[VPS Error] Could not unlink file: ${err.message}`);
                        }
                    }
                }
            }

            // 3. Cập nhật DB
            let query = `UPDATE users SET name = $1`;
            const params = [name];
            if (avatarUrl) {
                query += `, avatar = $2 WHERE id = $3`;
                params.push(avatarUrl, id);
            } else {
                query += ` WHERE id = $2`;
                params.push(id);
            }

            const result = await pool.query(query + ` RETURNING id, name, avatar, email, role, branch_id as "branchId"`, params);
            await logSystemAction(req, 'UPDATE_PROFILE', `User ${id} cập nhật hồ sơ`);
            res.json(result.rows[0]);
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- ĐỔI MẬT KHẨU ---
    router.put('/:id/change-password', async (req, res) => {
        const { oldPassword, newPassword } = req.body;
        try {
            const check = await pool.query(`SELECT password_hash FROM users WHERE id = $1`, [req.params.id]);
            if (check.rows[0].password_hash !== oldPassword) return res.status(400).json({ error: "Mật khẩu cũ không đúng" });
            await pool.query(`UPDATE users SET password_hash = $1 WHERE id = $2`, [newPassword, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    // --- RESET PASSWORD (ADMIN) ---
    router.post('/:id/reset-password', async (req, res) => {
        const { newPassword } = req.body;
        try {
            await pool.query(`UPDATE users SET password_hash = $1 WHERE id = $2`, [newPassword, req.params.id]);
            res.json({ status: 'ok' });
        } catch (e) { res.status(500).json({ error: e.message }); }
    });

    return router;
}

import React, { useState, useRef, useEffect } from 'react';
import { User } from '../types';
import { authService, API_URL } from '../services/mockBackend';
import { User as UserIcon, Camera, Save, Lock, Mail, Building, Shield, RefreshCw, CheckCircle2, AlertTriangle, Key } from 'lucide-react';

interface UserProfileProps {
    user: User;
    onUpdateUser: (updatedUser: User) => void;
}

const UserProfile: React.FC<UserProfileProps> = ({ user, onUpdateUser }) => {
    const [name, setName] = useState(user.name);
    // Khởi tạo preview từ avatar hiện tại
    const [avatarPreview, setAvatarPreview] = useState<string>('');
    const [selectedFile, setSelectedFile] = useState<File | null>(null);

    const [oldPassword, setOldPassword] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');

    const [loading, setLoading] = useState(false);
    const [passLoading, setPassLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Cập nhật preview mỗi khi user prop thay đổi
    useEffect(() => {
        if (user.avatar) {
            const url = user.avatar.startsWith('http') 
                ? user.avatar 
                : `${API_URL}${user.avatar.startsWith('/') ? '' : '/'}${user.avatar}?v=${Date.now()}`;
            setAvatarPreview(url);
        } else {
            setAvatarPreview('');
        }
    }, [user.avatar]);

    const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            if (file.size > 5 * 1024 * 1024) {
                setMessage({ type: 'error', text: 'Ảnh đại diện không được vượt quá 5MB' });
                return;
            }
            setSelectedFile(file);
            const reader = new FileReader();
            reader.onloadend = () => {
                setAvatarPreview(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleUpdateProfile = async () => {
        setLoading(true);
        setMessage(null);
        try {
            const result = await authService.updateProfile(user.id, name, selectedFile);

            // Cập nhật State toàn cục để Sidebar nhận dữ liệu mới ngay
            // Quan trọng: result.avatar trả về từ server là path tương đối "/uploads/..."
            const updatedUser = { ...user, name, avatar: result.avatar || user.avatar };
            onUpdateUser(updatedUser);

            setSelectedFile(null);
            setMessage({ type: 'success', text: 'Cập nhật hồ sơ thành công!' });
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message || 'Lỗi cập nhật hồ sơ' });
        } finally {
            setLoading(false);
        }
    };

    const handleChangePassword = async () => {
        if (!oldPassword || !newPassword || !confirmPassword) {
            setMessage({ type: 'error', text: 'Vui lòng điền đầy đủ thông tin mật khẩu' });
            return;
        }
        if (newPassword !== confirmPassword) {
            setMessage({ type: 'error', text: 'Mật khẩu xác nhận không khớp' });
            return;
        }
        if (newPassword.length < 6) {
            setMessage({ type: 'error', text: 'Mật khẩu mới phải từ 6 ký tự trở lên' });
            return;
        }

        setPassLoading(true);
        setMessage(null);
        try {
            await authService.changePassword(user.id, oldPassword, newPassword);
            setMessage({ type: 'success', text: 'Đổi mật khẩu thành công!' });
            setOldPassword('');
            setNewPassword('');
            setConfirmPassword('');
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message || 'Đổi mật khẩu thất bại' });
        } finally {
            setPassLoading(false);
        }
    };

    return (
        <div className="p-8 bg-slate-950 min-h-full flex justify-center animate-in fade-in duration-300">
            <div className="w-full max-w-4xl space-y-8">
                <div className="flex items-center gap-4 border-b border-gray-800 pb-6">
                    <div className="bg-blue-600/20 p-4 rounded-full border border-blue-500/30 shadow-[0_0_15px_rgba(37,99,235,0.3)]">
                        <UserIcon className="text-blue-400 w-8 h-8" />
                    </div>
                    <div>
                        <h1 className="text-3xl font-black text-white uppercase tracking-tight">Hồ sơ cá nhân</h1>
                        <p className="text-gray-400 text-sm font-medium">Quản lý thông tin tài khoản trên VPS</p>
                    </div>
                </div>

                {message && (
                    <div className={`p-4 rounded-xl border flex items-center gap-3 ${message.type === 'success' ? 'bg-green-900/20 border-green-800 text-green-400' : 'bg-red-900/20 border-red-800 text-red-400'}`}>
                        {message.type === 'success' ? <CheckCircle2 size={20} /> : <AlertTriangle size={20} />}
                        <span className="font-bold text-sm">{message.text}</span>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-gray-900 rounded-2xl border border-gray-800 p-6 shadow-xl relative overflow-hidden">
                            <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                                <span className="w-1 h-6 bg-blue-500 rounded-full"></span>
                                Thông tin chung
                            </h3>

                            <div className="flex flex-col sm:flex-row gap-8 items-start">
                                <div className="relative group mx-auto sm:mx-0">
                                    <div className="w-32 h-32 rounded-full border-4 border-gray-800 overflow-hidden bg-gray-800 shadow-2xl">
                                        {avatarPreview ? (
                                            <img src={avatarPreview} alt="Profile" className="w-full h-full object-cover" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center bg-gray-700 text-gray-500">
                                                <UserIcon size={48} />
                                            </div>
                                        )}
                                    </div>
                                    <button 
                                        onClick={() => fileInputRef.current?.click()}
                                        className="absolute bottom-0 right-0 p-2 bg-blue-600 rounded-full text-white shadow-lg hover:bg-blue-500 transition-all border-4 border-gray-900"
                                    >
                                        <Camera size={16} />
                                    </button>
                                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleAvatarChange} />
                                </div>

                                <div className="flex-1 w-full space-y-4">
                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase mb-1.5 block tracking-wider">Họ và Tên</label>
                                        <input 
                                            type="text" 
                                            value={name} 
                                            onChange={(e) => setName(e.target.value)} 
                                            className="w-full bg-gray-950 border border-gray-700 rounded-xl p-3 text-white font-medium focus:border-blue-500 outline-none transition-all"
                                        />
                                    </div>

                                    <div>
                                        <label className="text-xs font-bold text-gray-500 uppercase mb-1.5 block tracking-wider flex items-center gap-1"><Mail size={12}/> Email</label>
                                        <div className="w-full bg-gray-800/50 border border-gray-800 rounded-xl p-3 text-gray-400 font-mono text-sm truncate">
                                            {user.email}
                                        </div>
                                    </div>

                                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                        <div>
                                            <label className="text-xs font-bold text-gray-500 uppercase mb-1.5 block tracking-wider flex items-center gap-1"><Building size={12}/> Chi nhánh</label>
                                            <div className="w-full bg-gray-800/50 border border-gray-800 rounded-xl p-3 text-gray-400 font-bold text-sm">
                                                {user.branchId}
                                            </div>
                                        </div>

                                        <div>
                                            <label className="text-xs font-bold text-gray-500 uppercase mb-1.5 block tracking-wider flex items-center gap-1"><Shield size={12}/> Vai trò</label>
                                            <div className="w-full bg-gray-800/50 border border-gray-800 rounded-xl p-3 flex items-center">
                                                <div className="inline-flex items-center px-3 py-0.5 rounded-lg bg-blue-900/20 border border-blue-800 text-blue-400 text-xs font-black uppercase tracking-widest">
                                                    {user.role}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="mt-8 flex justify-end">
                                <button 
                                    onClick={handleUpdateProfile} 
                                    disabled={loading}
                                    className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2.5 rounded-xl font-bold text-sm shadow-lg shadow-blue-900/20 flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                                >
                                    {loading ? <RefreshCw className="animate-spin" size={18}/> : <Save size={18}/>}
                                    Lưu thay đổi
                                </button>
                            </div>
                        </div>
                    </div>

                    <div className="md:col-span-1">
                        <div className="bg-gray-900 rounded-2xl border border-gray-800 p-6 shadow-xl h-full flex flex-col">
                            <h3 className="text-lg font-bold text-white mb-6 flex items-center gap-2">
                                <Lock size={18} className="text-orange-500"/>
                                Đổi mật khẩu
                            </h3>

                            <div className="space-y-4 flex-1">
                                <div>
                                    <label className="text-xs font-bold text-gray-500 uppercase mb-1.5 block tracking-wider">Mật khẩu hiện tại</label>
                                    <input 
                                        type="password" 
                                        value={oldPassword} 
                                        onChange={(e) => setOldPassword(e.target.value)} 
                                        className="w-full bg-gray-950 border border-gray-700 rounded-xl p-3 text-white focus:border-orange-500 outline-none transition-all"
                                        placeholder="••••••"
