/**
 * Tự động xác định URL của API dựa trên địa chỉ trình duyệt.
 * Hỗ trợ: Localhost, LAN IP, VPS IP, Domain.
 */
export const getApiUrl = () => {
    const { hostname, protocol, port } = window.location;

    // 1. Tên miền chính thức
    if (hostname === 'geo.gisvn.space' || hostname === 'www.geo.gisvn.space') {
        return 'https://apigeo.gisvn.space';
    }

    // 2. Truy cập qua VPS IP hoặc Localhost
    // Nếu đang ở port 3003 (Vite), 5173 (Vite default) hoặc không có port (80/443)
    // nhưng không phải domain chính, thì ép về port 3004 của hostname đó.
    if (port !== '3004') {
        return `${protocol}//${hostname}:3004`;
    }

    // 3. Fallback về origin hiện tại
    return window.location.origin;
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    // Chuẩn hóa endpoint: đảm bảo luôn có /api ở đầu và không bị lặp
    const cleanPath = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
    const apiPath = cleanPath.startsWith('/api') ? cleanPath : `/api${cleanPath}`;

    const finalUrl = `${API_URL}${apiPath}`;

    try {
        const headers: any = { 
            'Content-Type': 'application/json', 
            ...getAuthHeaders(), 
            ...options?.headers 
        };
        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        if (!res.ok) {
            let errorMessage = `Lỗi ${res.status}`;
            try {
                const errorData = await res.json();
                errorMessage = errorData.error || errorData.message || errorMessage;
            } catch (e) {
                if (res.status === 404) errorMessage = `Không tìm thấy API: ${apiPath} trên máy chủ ${API_URL}`;
            }
            throw new Error(errorMessage);
        }
        return res.json();
    } catch (error: any) {
        console.error(`[API Error] ${finalUrl}:`, error.message);
        throw error;
    }
};

