/**
 * Tự động xác định URL của API dựa trên địa chỉ trình duyệt.
 * Hỗ trợ: Localhost, LAN IP, VPS IP, Domain và các môi trường Sandbox.
 */
export const getApiUrl = () => {
    try {
        const { hostname, protocol, port, origin } = window.location;

        // 1. Xử lý trường hợp protocol đặc biệt (như blob: hoặc file:)
        // Nếu không phải http/https, mặc định trỏ về localhost để tránh lỗi parse URL
        if (!protocol.startsWith('http')) {
            return 'http://localhost:3004';
        }

        // 2. Tên miền chính thức
        if (hostname === 'geo.gisvn.space' || hostname === 'www.geo.gisvn.space') {
            return 'https://apigeo.gisvn.space';
        }

        // 3. Truy cập qua VPS IP hoặc Localhost (Phát triển)
        // Nếu đang ở port 3003 (Vite), 5173 (Vite default), hoặc hostname hợp lệ mà không có port
        // thì chúng ta cần trỏ về port 3004 của chính IP đó.
        if (hostname && (port === '3003' || port === '5173' || port === '3000')) {
            return `${protocol}//${hostname}:3004`;
        }

        // 4. Trường hợp chạy qua Reverse Proxy (Nginx) trên VPS 
        // (truy cập IP không kèm port hoặc domain phụ)
        if (hostname && !port) {
            // Nếu là địa chỉ IP (thường thấy ở VPS), vẫn ưu tiên thử port 3004
            const isIp = /^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$/.test(hostname);
            if (isIp) return `${protocol}//${hostname}:3004`;
        }

        // 5. Fallback cuối cùng: dùng origin hiện tại
        return origin.replace(/:3003$/, ':3004').replace(/:5173$/, ':3004');
    } catch (e) {
        return 'http://localhost:3004';
    }
};

