/**
 * Tự động xác định URL của API dựa trên địa chỉ trình duyệt.
 * Đảm bảo hoạt động trên: Localhost, VPS IP, Domain và Sandbox (Giả lập).
 */
export const getApiUrl = () => {
    try {
        const { hostname, protocol, port, origin } = window.location;

        // 1. Trường hợp chạy trong Sandbox/Giả lập (thường có protocol là blob: hoặc hostname trống)
        if (!hostname || hostname === '' || protocol.startsWith('blob')) {
            // Trong giả lập, ta thường dùng proxy của Vite (/api) hoặc localhost
            return ''; // Trả về rỗng để fetch dùng đường dẫn tương đối /api/...
        }

        // 2. Tên miền chính thức đã cấu hình SSL
        if (hostname === 'geo.gisvn.space' || hostname === 'www.geo.gisvn.space') {
            return 'https://apigeo.gisvn.space';
        }

        // 3. Truy cập trực tiếp qua VPS IP hoặc Localhost
        // Nếu port hiện tại là của Frontend (3003, 5173, 3000), trỏ về port API (3004)
        if (port === '3003' || port === '5173' || port === '3000') {
            return `${protocol}//${hostname}:3004`;
        }

        // 4. Nếu truy cập qua IP mà không có port (đã qua Nginx Reverse Proxy)
        const isIp = /^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$/.test(hostname);
        if (isIp && !port) {
            // Thử trỏ về port 3004 nếu Nginx chưa cấu hình map /api
            // Nếu đã cấu hình Nginx map /api -> 3004 thì dùng origin
            return origin; 
        }

        // 5. Mặc định dùng origin hiện tại
        return origin;
    } catch (e) {
        return '';
    }
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    // Chuẩn hóa endpoint: đảm bảo luôn có /api ở đầu
    const cleanPath = endpoint.startsWith('/') ? endpoint : `/${endpoint}`;
    const apiPath = cleanPath.startsWith('/api') ? cleanPath : `/api${cleanPath}`;

    // Đảm bảo không có dấu gạch chéo dư thừa giữa API_URL và apiPath
    const base = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;
    const finalUrl = `${base}${apiPath}`;

    try {
        const headers: any = { 
            'Content-Type': 'application/json', 
            ...getAuthHeaders(), 
            ...options?.headers 
        };
        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });

        if (!res.ok) {
            let errorMessage = `Lỗi ${res.status}`;
            try {
                const errorData = await res.json();
                errorMessage = errorData.error || errorData.message || errorMessage;
            } catch (e) {
                if (res.status === 404) {
                    errorMessage = `Không tìm thấy API tại: ${finalUrl}. Kiểm tra Backend port 3004.`;
                }
            }
            throw new Error(errorMessage);
        }
        return res.json();
    } catch (error: any) {
        console.error(`[API Error] Request: ${finalUrl}`, error.message);
        throw error;
    }
};

