/**
 * Tự động xác định URL của API dựa trên địa chỉ trình duyệt.
 * Hỗ trợ: Localhost, VPS IP, Domain chính và Trình giả lập (Sandbox).
 */
export const getApiUrl = () => {
    try {
        const { hostname, protocol, port, origin } = window.location;

        // 1. Trường hợp chạy trong Sandbox/Giả lập (hostname rỗng hoặc protocol đặc biệt)
        if (!hostname || hostname === '' || protocol.startsWith('blob')) {
            return ''; // Trả về rỗng để fetch dùng đường dẫn tương đối thông qua Vite Proxy
        }

        // 2. Tên miền chính thức
        if (hostname === 'geo.gisvn.space' || hostname === 'www.geo.gisvn.space') {
            return 'https://apigeo.gisvn.space';
        }

        // 3. Truy cập trực tiếp qua VPS IP hoặc Localhost (Phát triển)
        // Nếu port hiện tại là 3003 (Vite), ép về port 3004 (API) của cùng Hostname đó
        if (port === '3003' || port === '5173' || port === '3000') {
            return `${protocol}//${hostname}:3004`;
        }

        // 4. Nếu truy cập qua IP mà không có port (đã qua Nginx Reverse Proxy)
        const isIp = /^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$/.test(hostname);
        if (isIp && !port) {
            // Nếu là IP VPS, ưu tiên dùng origin hiện tại (vì Nginx thường đã map /api)
            return origin;
        }

        // 5. Mặc định dùng origin hiện tại
        return origin.replace(/:3003$/, ':3004');
    } catch (e) {
        return '';
    }
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    const cleanEndpoint = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;

    // Đảm bảo không bị lặp gạch chéo
    const base = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;
    const finalUrl = `${base}${cleanEndpoint}`;

    try {
        const headers: any = { 'Content-Type': 'application/json', ...getAuthHeaders(), ...options?.headers };
        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        const responseText = await res.text();

        let responseData: any = null;
        if (responseText) {
            try { responseData = JSON.parse(responseText); } catch (e) {}
        }

        if (!res.ok) {
            let errorMessage = `Lỗi hệ thống (${res.status})`;
            if (responseData && (responseData.error || responseData.message)) {
                errorMessage = responseData.error || responseData.message;
            }
            if (res.status === 404) {
                errorMessage = `Không tìm thấy API: ${finalUrl}. Hãy kiểm tra Backend port 3004.`;
            }
            throw new Error(errorMessage);
        }

        return responseData || { status: 'ok' };
    } catch (error: any) {
        console.error(`[API Connection Error] ${finalUrl}:`, error.message);
        throw error;
    }
};

